window.trendingPapers = {
    "today": [{"paper": {"id": "2511.22699", "authors": [{"_id": "692d06234397b1ec214f6788", "name": "Z-Image Team", "hidden": false}, {"_id": "692d06234397b1ec214f6789", "name": "Huanqia Cai", "hidden": false}, {"_id": "692d06234397b1ec214f678a", "name": "Sihan Cao", "hidden": false}, {"_id": "692d06234397b1ec214f678b", "name": "Ruoyi Du", "hidden": false}, {"_id": "692d06234397b1ec214f678c", "name": "Peng Gao", "hidden": false}, {"_id": "692d06234397b1ec214f678d", "name": "Steven Hoi", "hidden": false}, {"_id": "692d06234397b1ec214f678e", "name": "Shijie Huang", "hidden": false}, {"_id": "692d06234397b1ec214f678f", "name": "Zhaohui Hou", "hidden": false}, {"_id": "692d06234397b1ec214f6790", "name": "Dengyang Jiang", "hidden": false}, {"_id": "692d06234397b1ec214f6791", "name": "Xin Jin", "hidden": false}, {"_id": "692d06234397b1ec214f6792", "name": "Liangchen Li", "hidden": false}, {"_id": "692d06234397b1ec214f6793", "name": "Zhen Li", "hidden": false}, {"_id": "692d06234397b1ec214f6794", "name": "Zhong-Yu Li", "hidden": false}, {"_id": "692d06234397b1ec214f6795", "name": "David Liu", "hidden": false}, {"_id": "692d06234397b1ec214f6796", "name": "Dongyang Liu", "hidden": false}, {"_id": "692d06234397b1ec214f6797", "name": "Junhan Shi", "hidden": false}, {"_id": "692d06234397b1ec214f6798", "name": "Qilong Wu", "hidden": false}, {"_id": "692d06234397b1ec214f6799", "name": "Feng Yu", "hidden": false}, {"_id": "692d06234397b1ec214f679a", "name": "Chi Zhang", "hidden": false}, {"_id": "692d06234397b1ec214f679b", "name": "Shifeng Zhang", "hidden": false}, {"_id": "692d06234397b1ec214f679c", "name": "Shilin Zhou", "hidden": false}], "publishedAt": "2025-11-27T18:52:07.000Z", "submittedOnDailyAt": "2025-12-01T00:38:17.269Z", "title": "Z-Image: An Efficient Image Generation Foundation Model with Single-Stream Diffusion Transformer", "submittedOnDailyBy": {"_id": "6285a9133ab6642179158944", "avatarUrl": "/avatars/6e10fa07c94141fcdbe0cab02bb731ca.svg", "isPro": false, "fullname": "Zhen Li", "user": "Paper99", "type": "user"}, "summary": "The landscape of high-performance image generation models is currently dominated by proprietary systems, such as Nano Banana Pro and Seedream 4.0. Leading open-source alternatives, including Qwen-Image, Hunyuan-Image-3.0 and FLUX.2, are characterized by massive parameter counts (20B to 80B), making them impractical for inference, and fine-tuning on consumer-grade hardware. To address this gap, we propose Z-Image, an efficient 6B-parameter foundation generative model built upon a Scalable Single-Stream Diffusion Transformer (S3-DiT) architecture that challenges the \"scale-at-all-costs\" paradigm. By systematically optimizing the entire model lifecycle -- from a curated data infrastructure to a streamlined training curriculum -- we complete the full training workflow in just 314K H800 GPU hours (approx. $630K). Our few-step distillation scheme with reward post-training further yields Z-Image-Turbo, offering both sub-second inference latency on an enterprise-grade H800 GPU and compatibility with consumer-grade hardware (<16GB VRAM). Additionally, our omni-pre-training paradigm also enables efficient training of Z-Image-Edit, an editing model with impressive instruction-following capabilities. Both qualitative and quantitative experiments demonstrate that our model achieves performance comparable to or surpassing that of leading competitors across various dimensions. Most notably, Z-Image exhibits exceptional capabilities in photorealistic image generation and bilingual text rendering, delivering results that rival top-tier commercial models, thereby demonstrating that state-of-the-art results are achievable with significantly reduced computational overhead. We publicly release our code, weights, and online demo to foster the development of accessible, budget-friendly, yet state-of-the-art generative models.", "upvotes": 23, "discussionId": "692d06234397b1ec214f679d", "projectPage": "https://tongyi-mai.github.io/Z-Image-blog/", "githubRepo": "https://github.com/Tongyi-MAI/Z-Image", "ai_summary": "Z-Image, a 6B-parameter Scalable Single-Stream Diffusion Transformer (S3-DiT) model, achieves high-performance image generation with reduced computational cost, offering sub-second inference and compatibility with consumer hardware.", "ai_keywords": ["Scalable Single-Stream Diffusion Transformer", "S3-DiT", "diffusion transformer", "omni-pre-training", "instruction-following capabilities", "photorealistic image generation", "bilingual text rendering", "distillation scheme", "reward post-training", "H800 GPU", "VRAM"], "githubStars": 2931, "organization": {"_id": "6925b20fed452d1567c012d3", "name": "Tongyi-MAI", "fullname": "Tongyi-MAI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64379d79fac5ea753f1c10f3/fxHO6QoYjdv9_LTyiUD3g.jpeg"}, "summary_zh": "<ul>\n    <li>\u76ee\u524d\u9ad8\u6027\u80fd\u56fe\u50cf\u751f\u6210\u6a21\u578b\u4e3b\u8981\u7531\u4e13\u6709\u7cfb\u7edf\u4e3b\u5bfc\uff0c\u5982Nano Banana Pro\u548cSeedream 4.0\u3002</li>\n    <li>\u5f00\u653e\u6e90\u7801\u66ff\u4ee3\u54c1\uff08\u5982Qwen-Image\u548cHunyuan-Image-3.0\uff09\u53c2\u6570\u6570\u91cf\u5e9e\u5927\uff0820B\u523080B\uff09\uff0c\u4e0d\u9002\u5408\u666e\u901a\u786c\u4ef6\u7684\u63a8\u7406\u548c\u5fae\u8c03\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86Z-Image\uff0c\u4e00\u4e2a\u9ad8\u6548\u76846B\u53c2\u6570\u751f\u6210\u6a21\u578b\uff0c\u57fa\u4e8e\u53ef\u6269\u5c55\u5355\u6d41\u6269\u6563\u53d8\u538b\u5668\u67b6\u6784\uff08S3-DiT\uff09\uff0c\u6311\u6218\u201c\u89c4\u6a21\u4f18\u5148\u201d\u7684\u7406\u5ff5\u3002</li>\n    <li>\u901a\u8fc7\u4f18\u5316\u6574\u4e2a\u6a21\u578b\u751f\u547d\u5468\u671f\uff0c\u6211\u4eec\u7684\u8bad\u7ec3\u5de5\u4f5c\u6d41\u7a0b\u4ec5\u9700314K H800 GPU\u5c0f\u65f6\uff0c\u6210\u672c\u7ea6\u4e3a630K\u7f8e\u5143\u3002</li>\n    <li>Z-Image\u5728\u751f\u6210\u771f\u5b9e\u611f\u56fe\u50cf\u548c\u53cc\u8bed\u6587\u672c\u6e32\u67d3\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u7ed3\u679c\u53ef\u4e0e\u9876\u7ea7\u5546\u4e1a\u6a21\u578b\u5ab2\u7f8e\uff0c\u5e76\u4e14\u6211\u4eec\u516c\u5f00\u53d1\u5e03\u4e86\u4ee3\u7801\u548c\u5728\u7ebf\u6f14\u793a\uff0c\u4fc3\u8fdb\u66f4\u5177\u53ef\u53ca\u6027\u548c\u7ecf\u6d4e\u6027\u7684\u751f\u6210\u6a21\u578b\u53d1\u5c55\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>High-performance image generation is mainly led by proprietary systems like Nano Banana Pro and Seedream 4.0, while open-source models often have very large sizes (20B to 80B parameters).</li>\n    <li>Z-Image is a new generative model with only 6 billion parameters, designed to be efficient and built on the S3-DiT architecture.</li>\n    <li>It completes the full training process in 314,000 GPU hours, costing about $630,000, and has a special distillation method that produces Z-Image-Turbo for fast inference.</li>\n    <li>Z-Image can run on consumer-grade hardware and excels in photorealistic image generation and bilingual text rendering, matching or exceeding the performance of leading models.</li>\n    <li>The creators are making Z-Image's code, weights, and demo available to support the development of accessible generative models.</li>\n</ul>"}, "publishedAt": "2025-11-27T13:52:07.000Z", "title": "Z-Image: An Efficient Image Generation Foundation Model with Single-Stream Diffusion Transformer", "summary": "The landscape of high-performance image generation models is currently dominated by proprietary systems, such as Nano Banana Pro and Seedream 4.0. Leading open-source alternatives, including Qwen-Image, Hunyuan-Image-3.0 and FLUX.2, are characterized by massive parameter counts (20B to 80B), making them impractical for inference, and fine-tuning on consumer-grade hardware. To address this gap, we propose Z-Image, an efficient 6B-parameter foundation generative model built upon a Scalable Single-Stream Diffusion Transformer (S3-DiT) architecture that challenges the \"scale-at-all-costs\" paradigm. By systematically optimizing the entire model lifecycle -- from a curated data infrastructure to a streamlined training curriculum -- we complete the full training workflow in just 314K H800 GPU hours (approx. $630K). Our few-step distillation scheme with reward post-training further yields Z-Image-Turbo, offering both sub-second inference latency on an enterprise-grade H800 GPU and compatibility with consumer-grade hardware (<16GB VRAM). Additionally, our omni-pre-training paradigm also enables efficient training of Z-Image-Edit, an editing model with impressive instruction-following capabilities. Both qualitative and quantitative experiments demonstrate that our model achieves performance comparable to or surpassing that of leading competitors across various dimensions. Most notably, Z-Image exhibits exceptional capabilities in photorealistic image generation and bilingual text rendering, delivering results that rival top-tier commercial models, thereby demonstrating that state-of-the-art results are achievable with significantly reduced computational overhead. We publicly release our code, weights, and online demo to foster the development of accessible, budget-friendly, yet state-of-the-art generative models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.22699.png", "numComments": 1, "submittedBy": {"_id": "6285a9133ab6642179158944", "avatarUrl": "/avatars/6e10fa07c94141fcdbe0cab02bb731ca.svg", "fullname": "Zhen Li", "name": "Paper99", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 23}, "organization": {"_id": "6925b20fed452d1567c012d3", "name": "Tongyi-MAI", "fullname": "Tongyi-MAI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64379d79fac5ea753f1c10f3/fxHO6QoYjdv9_LTyiUD3g.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2511.23475", "authors": [{"_id": "692d0d8f4397b1ec214f67e7", "name": "Zhizhou Zhong", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67e8", "name": "Yicheng Ji", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67e9", "name": "Zhe Kong", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67ea", "name": "Yiying Liu", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67eb", "name": "Jiarui Wang", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67ec", "name": "Jiasun Feng", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67ed", "name": "Lupeng Liu", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67ee", "name": "Xiangyi Wang", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67ef", "name": "Yanjia Li", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67f0", "name": "Yuqing She", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67f1", "name": "Ying Qin", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67f2", "name": "Huan Li", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67f3", "name": "Shuiyang Mao", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67f4", "name": "Wei Liu", "hidden": false}, {"_id": "692d0d8f4397b1ec214f67f5", "name": "Wenhan Luo", "hidden": false}], "publishedAt": "2025-11-28T18:59:01.000Z", "submittedOnDailyAt": "2025-12-01T01:08:00.505Z", "title": "AnyTalker: Scaling Multi-Person Talking Video Generation with Interactivity Refinement", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "Recently, multi-person video generation has started to gain prominence. While a few preliminary works have explored audio-driven multi-person talking video generation, they often face challenges due to the high costs of diverse multi-person data collection and the difficulty of driving multiple identities with coherent interactivity. To address these challenges, we propose AnyTalker, a multi-person generation framework that features an extensible multi-stream processing architecture. Specifically, we extend Diffusion Transformer's attention block with a novel identity-aware attention mechanism that iteratively processes identity-audio pairs, allowing arbitrary scaling of drivable identities. Besides, training multi-person generative models demands massive multi-person data. Our proposed training pipeline depends solely on single-person videos to learn multi-person speaking patterns and refines interactivity with only a few real multi-person clips. Furthermore, we contribute a targeted metric and dataset designed to evaluate the naturalness and interactivity of the generated multi-person videos. Extensive experiments demonstrate that AnyTalker achieves remarkable lip synchronization, visual quality, and natural interactivity, striking a favorable balance between data costs and identity scalability.", "upvotes": 12, "discussionId": "692d0d904397b1ec214f67f6", "projectPage": "https://hkust-c4g.github.io/AnyTalker-homepage/", "githubRepo": "https://github.com/HKUST-C4G/AnyTalker", "ai_summary": "The proposed AnyTalker framework generates high-quality multi-person talking videos by extending Diffusion Transformer with identity-aware attention, leveraging single-person videos for training, and using a specialized dataset for evaluation.", "ai_keywords": ["Diffusion Transformer", "identity-aware attention", "multi-person video generation", "audio-driven generation", "multi-stream processing", "lip synchronization", "visual quality", "interactivity", "dataset"], "githubStars": 63, "summary_zh": "<ul>\n    <li>\u591a\u4eba\u7269\u89c6\u9891\u751f\u6210\u6700\u8fd1\u8d8a\u6765\u8d8a\u53d7\u5230\u5173\u6ce8\uff0c\u4f46\u9762\u4e34\u6570\u636e\u6536\u96c6\u6210\u672c\u9ad8\u548c\u591a\u8eab\u4efd\u4e92\u52a8\u96be\u5ea6\u5927\u7684\u6311\u6218\u3002</li>\n    <li>\u63d0\u51fa\u4e86AnyTalker\u6846\u67b6\uff0c\u4f7f\u7528\u53ef\u6269\u5c55\u7684\u591a\u6d41\u5904\u7406\u67b6\u6784\u6765\u89e3\u51b3\u8fd9\u4e9b\u95ee\u9898\u3002</li>\n    <li>AnyTalker\u91c7\u7528\u4e86\u4e00\u79cd\u65b0\u7684\u8eab\u4efd\u611f\u77e5\u6ce8\u610f\u529b\u673a\u5236\uff0c\u53ef\u4ee5\u7075\u6d3b\u5904\u7406\u8eab\u4efd\u4e0e\u97f3\u9891\u7684\u914d\u5bf9\uff0c\u5e76\u6269\u5c55\u53ef\u9a71\u52a8\u7684\u8eab\u4efd\u6570\u91cf\u3002</li>\n    <li>\u8bad\u7ec3\u8fc7\u7a0b\u4e2d\u53ea\u9700\u8981\u5355\u4eba\u89c6\u9891\u6765\u5b66\u4e60\u591a\u4eba\u7684\u8bf4\u8bdd\u6a21\u5f0f\uff0c\u5c11\u91cf\u771f\u5b9e\u7684\u591a\u4eba\u7269\u7247\u6bb5\u7528\u4e8e\u63d0\u5347\u4e92\u52a8\u6027\u3002</li>\n    <li>\u901a\u8fc7\u4e00\u7cfb\u5217\u5b9e\u9a8c\uff0cAnyTalker\u5728\u5507\u540c\u6b65\u3001\u89c6\u89c9\u8d28\u91cf\u548c\u81ea\u7136\u4e92\u52a8\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u540c\u65f6\u5728\u6570\u636e\u6210\u672c\u548c\u8eab\u4efd\u6269\u5c55\u6027\u4e4b\u95f4\u53d6\u5f97\u4e86\u826f\u597d\u5e73\u8861\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multi-person video generation is becoming more important, especially for talking videos driven by audio.</li>\n    <li>Challenges include high costs for gathering diverse multi-person data and ensuring smooth interaction among different identities.</li>\n    <li>AnyTalker is a new framework that uses a special attention mechanism to process audio and identities, allowing for more flexible scaling of characters.</li>\n    <li>It trains on single-person videos to learn how people speak and needs only a few multi-person clips to improve interaction.</li>\n    <li>AnyTalker has been tested and shows excellent lip syncing, video quality, and natural interaction, while keeping data collection costs low.</li>\n</ul>"}, "publishedAt": "2025-11-28T13:59:01.000Z", "title": "AnyTalker: Scaling Multi-Person Talking Video Generation with Interactivity Refinement", "summary": "Recently, multi-person video generation has started to gain prominence. While a few preliminary works have explored audio-driven multi-person talking video generation, they often face challenges due to the high costs of diverse multi-person data collection and the difficulty of driving multiple identities with coherent interactivity. To address these challenges, we propose AnyTalker, a multi-person generation framework that features an extensible multi-stream processing architecture. Specifically, we extend Diffusion Transformer's attention block with a novel identity-aware attention mechanism that iteratively processes identity-audio pairs, allowing arbitrary scaling of drivable identities. Besides, training multi-person generative models demands massive multi-person data. Our proposed training pipeline depends solely on single-person videos to learn multi-person speaking patterns and refines interactivity with only a few real multi-person clips. Furthermore, we contribute a targeted metric and dataset designed to evaluate the naturalness and interactivity of the generated multi-person videos. Extensive experiments demonstrate that AnyTalker achieves remarkable lip synchronization, visual quality, and natural interactivity, striking a favorable balance between data costs and identity scalability.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.23475.png", "numComments": 1, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 172}, "isAuthorParticipating": false}, {"paper": {"id": "2511.18822", "authors": [{"_id": "692d00ed4397b1ec214f677d", "name": "Zhennan Chen", "hidden": false}, {"_id": "692d00ed4397b1ec214f677e", "name": "Junwei Zhu", "hidden": false}, {"_id": "692d00ed4397b1ec214f677f", "name": "Xu Chen", "hidden": false}, {"_id": "692d00ed4397b1ec214f6780", "name": "Jiangning Zhang", "hidden": false}, {"_id": "692d00ed4397b1ec214f6781", "name": "Xiaobin Hu", "hidden": false}, {"_id": "692d00ed4397b1ec214f6782", "name": "Hanzhen Zhao", "hidden": false}, {"_id": "692d00ed4397b1ec214f6783", "name": "Chengjie Wang", "hidden": false}, {"_id": "692d00ed4397b1ec214f6784", "name": "Jian Yang", "hidden": false}, {"_id": "692d00ed4397b1ec214f6785", "name": "Ying Tai", "hidden": false}], "publishedAt": "2025-11-24T06:55:49.000Z", "submittedOnDailyAt": "2025-12-01T00:32:27.778Z", "title": "DiP: Taming Diffusion Models in Pixel Space", "submittedOnDailyBy": {"_id": "66449e619ff401732687f013", "avatarUrl": "/avatars/251897d1324a70a9bf761513871c5841.svg", "isPro": false, "fullname": "chen", "user": "zhen-nan", "type": "user"}, "summary": "Diffusion models face a fundamental trade-off between generation quality and computational efficiency. Latent Diffusion Models (LDMs) offer an efficient solution but suffer from potential information loss and non-end-to-end training. In contrast, existing pixel space models bypass VAEs but are computationally prohibitive for high-resolution synthesis. To resolve this dilemma, we propose DiP, an efficient pixel space diffusion framework. DiP decouples generation into a global and a local stage: a Diffusion Transformer (DiT) backbone operates on large patches for efficient global structure construction, while a co-trained lightweight Patch Detailer Head leverages contextual features to restore fine-grained local details. This synergistic design achieves computational efficiency comparable to LDMs without relying on a VAE. DiP is accomplished with up to 10times faster inference speeds than previous method while increasing the total number of parameters by only 0.3%, and achieves an 1.79 FID score on ImageNet 256times256.", "upvotes": 10, "discussionId": "692d00ed4397b1ec214f6786", "ai_summary": "DiP, a pixel space diffusion framework, combines a Diffusion Transformer and a Patch Detailer Head to achieve computational efficiency and high-quality image generation without using VAEs.", "ai_keywords": ["diffusion models", "latent diffusion models (LDMs)", "pixel space models", "variational autoencoders (VAEs)", "diffusion transformer (DiT)", "patch detailer head", "FID score"], "summary_zh": "<ul>\n    <li>\u6269\u6563\u6a21\u578b\u5728\u751f\u6210\u8d28\u91cf\u548c\u8ba1\u7b97\u6548\u7387\u4e4b\u95f4\u5b58\u5728\u6743\u8861\u3002</li>\n    <li>\u6f5c\u5728\u6269\u6563\u6a21\u578b\uff08LDMs\uff09\u63d0\u4f9b\u4e86\u9ad8\u6548\u7684\u89e3\u51b3\u65b9\u6848\uff0c\u4f46\u53ef\u80fd\u4f1a\u5bfc\u81f4\u4fe1\u606f\u635f\u5931\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u9ad8\u6548\u50cf\u7d20\u7a7a\u95f4\u6269\u6563\u6846\u67b6\uff0c\u79f0\u4e3aDiP\u3002</li>\n    <li>DiP\u5c06\u751f\u6210\u8fc7\u7a0b\u5206\u4e3a\u5168\u5c40\u548c\u5c40\u90e8\u4e24\u4e2a\u9636\u6bb5\uff0c\u4f7f\u7528Diffusion Transformer\uff08DiT\uff09\u8fdb\u884c\u5168\u5c40\u7ed3\u6784\u6784\u5efa\u3002</li>\n    <li>DiP\u6bd4\u4ee5\u524d\u7684\u65b9\u6cd5\u5feb10\u500d\uff0c\u53c2\u6570\u589e\u52a0\u4ec50.3%\uff0c\u5728ImageNet\u4e0a\u83b7\u5f971.79\u7684FID\u5f97\u5206\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Diffusion models balance quality and speed but have limitations in efficiency and information retention.</li>\n    <li>Latent Diffusion Models (LDMs) are efficient but can lose information and don't train end-to-end.</li>\n    <li>Current pixel space models are too slow for high-resolution images.</li>\n    <li>DiP is a new pixel space diffusion method that separates the generation process into global and local stages.</li>\n    <li>DiP is much faster, being up to 10 times quicker than previous methods, and has a minimal increase in parameters while achieving a good quality score on ImageNet.</li>\n</ul>"}, "publishedAt": "2025-11-24T01:55:49.000Z", "title": "DiP: Taming Diffusion Models in Pixel Space", "summary": "Diffusion models face a fundamental trade-off between generation quality and computational efficiency. Latent Diffusion Models (LDMs) offer an efficient solution but suffer from potential information loss and non-end-to-end training. In contrast, existing pixel space models bypass VAEs but are computationally prohibitive for high-resolution synthesis. To resolve this dilemma, we propose DiP, an efficient pixel space diffusion framework. DiP decouples generation into a global and a local stage: a Diffusion Transformer (DiT) backbone operates on large patches for efficient global structure construction, while a co-trained lightweight Patch Detailer Head leverages contextual features to restore fine-grained local details. This synergistic design achieves computational efficiency comparable to LDMs without relying on a VAE. DiP is accomplished with up to 10times faster inference speeds than previous method while increasing the total number of parameters by only 0.3%, and achieves an 1.79 FID score on ImageNet 256times256.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.18822.png", "numComments": 1, "submittedBy": {"_id": "66449e619ff401732687f013", "avatarUrl": "/avatars/251897d1324a70a9bf761513871c5841.svg", "fullname": "chen", "name": "zhen-nan", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4}, "isAuthorParticipating": false}, {"paper": {"id": "2511.22663", "authors": [{"_id": "692cff484397b1ec214f676e", "name": "Dian Zheng", "hidden": false}, {"_id": "692cff484397b1ec214f676f", "name": "Manyuan Zhang", "hidden": false}, {"_id": "692cff484397b1ec214f6770", "name": "Hongyu Li", "hidden": false}, {"_id": "692cff484397b1ec214f6771", "name": "Kai Zou", "hidden": false}, {"_id": "692cff484397b1ec214f6772", "name": "Hongbo Liu", "hidden": false}, {"_id": "692cff484397b1ec214f6773", "name": "Ziyu Guo", "hidden": false}, {"_id": "692cff484397b1ec214f6774", "name": "Kaituo Feng", "hidden": false}, {"_id": "692cff484397b1ec214f6775", "name": "Yexin Liu", "hidden": false}, {"_id": "692cff484397b1ec214f6776", "name": "Ying Luo", "hidden": false}, {"_id": "692cff484397b1ec214f6777", "name": "Yan Feng", "hidden": false}, {"_id": "692cff484397b1ec214f6778", "name": "Peng Pei", "hidden": false}, {"_id": "692cff484397b1ec214f6779", "name": "Xunliang Cai", "hidden": false}, {"_id": "692cff484397b1ec214f677a", "name": "Hongsheng Li", "hidden": false}], "publishedAt": "2025-11-27T17:55:25.000Z", "submittedOnDailyAt": "2025-12-01T00:57:45.124Z", "title": "Architecture Decoupling Is Not All You Need For Unified Multimodal Model", "submittedOnDailyBy": {"_id": "67079840a9bcb7459b8d2a46", "avatarUrl": "/avatars/32466863c5554f20cb2775b138832ac3.svg", "isPro": false, "fullname": "Kaituo Feng", "user": "KaituoFeng", "type": "user"}, "summary": "Unified multimodal models for image generation and understanding represent a significant step toward AGI and have attracted widespread attention from researchers. The main challenge of this task lies in the difficulty in establishing an optimal training paradigm due to inherent conflicting targets in understanding and generation tasks. To alleviate these conflicts and pursue higher performance, many researchers adopt varying degrees of model decoupling (e.g., Double image encoders, MOE/MOT architecture, or frozen MLLM). However, excessive model decoupling can lead to the loss of interleave generation ability, undermining the original intent of unified models. In this work, we aim to explore how to mitigate task conflicts without resorting to model decoupling. Firstly, we analyze why decoupling alleviates conflicts by studying the cross-modal attention behavior of models. We observe that model decoupling essentially drives models toward task-specific multimodal interaction patterns, as seen in Qwen-VL and HunyuanImage, and that the more thorough the decoupling, the more consistent the behavior becomes. Motivated by this observation, we propose Attention Interaction Alignment (AIA) loss, which explicitly learns Task-Specific multimodal interaction patterns during training. To demonstrate the generalizability of our AIA loss, we apply it to Emu3 and Janus-Pro during SFT and post-training stage respectively. Without bells and whistles, AIA not only refines cross-modal attention patterns, but also boosts both generation and understanding performance.", "upvotes": 8, "discussionId": "692cff484397b1ec214f677b", "projectPage": "https://zhengdian1.github.io/AIA-project/", "githubRepo": "https://github.com/zhengdian1/AIA", "ai_summary": "The proposed Attention Interaction Alignment (AIA) loss improves cross-modal attention and performance in unified multimodal models for image generation and understanding without decoupling.", "ai_keywords": ["multimodal models", "image generation", "understanding", "task-specific multimodal interaction", "cross-modal attention", "Attention Interaction Alignment (AIA) loss", "SFT", "post-training stage", "Qwen-VL", "HunyuanImage", "Emu3", "Janus-Pro"], "githubStars": 5, "summary_zh": "<ul>\n    <li>\u7edf\u4e00\u7684\u591a\u6a21\u6001\u6a21\u578b\u5728\u56fe\u50cf\u751f\u6210\u548c\u7406\u89e3\u65b9\u9762\u662f\u671d\u5411\u901a\u7528\u4eba\u5de5\u667a\u80fd\u7684\u91cd\u8981\u8fdb\u5c55\uff0c\u53d7\u5230\u7814\u7a76\u8005\u7684\u5e7f\u6cdb\u5173\u6ce8\u3002</li>\n    <li>\u5efa\u7acb\u6700\u4f73\u8bad\u7ec3\u6a21\u5f0f\u7684\u4e3b\u8981\u6311\u6218\u5728\u4e8e\u7406\u89e3\u548c\u751f\u6210\u4efb\u52a1\u4e4b\u95f4\u5b58\u5728\u56fa\u6709\u7684\u51b2\u7a81\u3002</li>\n    <li>\u8bb8\u591a\u7814\u7a76\u8005\u901a\u8fc7\u4e0d\u540c\u7a0b\u5ea6\u7684\u6a21\u578b\u89e3\u8026\u6765\u7f13\u89e3\u8fd9\u4e9b\u51b2\u7a81\uff0c\u4f46\u8fc7\u5ea6\u89e3\u8026\u53ef\u80fd\u4f1a\u635f\u5931\u6a21\u578b\u7684\u751f\u6210\u80fd\u529b\u3002</li>\n    <li>\u672c\u6587\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u635f\u5931\u51fd\u6570\uff0c\u79f0\u4e3a\u6ce8\u610f\u529b\u4ea4\u4e92\u5bf9\u9f50\uff08AIA\uff09\uff0c\u65e8\u5728\u5728\u4e0d\u89e3\u8026\u6a21\u578b\u7684\u60c5\u51b5\u4e0b\u51cf\u8f7b\u4efb\u52a1\u51b2\u7a81\u3002</li>\n    <li>AIA\u635f\u5931\u53ef\u4ee5\u63d0\u9ad8\u8de8\u6a21\u6001\u6ce8\u610f\u529b\u6a21\u5f0f\uff0c\u5e76\u589e\u5f3a\u751f\u6210\u548c\u7406\u89e3\u7684\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Unified multimodal models for generating and understanding images are important for advancing artificial general intelligence (AGI).</li>\n    <li>Training these models is challenging due to conflicting goals in understanding and generating tasks.</li>\n    <li>Some researchers use model decoupling to improve performance, but too much decoupling can weaken the model's ability to integrate tasks.</li>\n    <li>This work investigates how to reduce conflicts without decoupling models by studying how they interact with different types of data.</li>\n    <li>The authors introduce a new method called Attention Interaction Alignment (AIA) loss to improve how models learn to interact during training, resulting in better performance in both image generation and understanding.</li>\n</ul>"}, "publishedAt": "2025-11-27T12:55:25.000Z", "title": "Architecture Decoupling Is Not All You Need For Unified Multimodal Model", "summary": "Unified multimodal models for image generation and understanding represent a significant step toward AGI and have attracted widespread attention from researchers. The main challenge of this task lies in the difficulty in establishing an optimal training paradigm due to inherent conflicting targets in understanding and generation tasks. To alleviate these conflicts and pursue higher performance, many researchers adopt varying degrees of model decoupling (e.g., Double image encoders, MOE/MOT architecture, or frozen MLLM). However, excessive model decoupling can lead to the loss of interleave generation ability, undermining the original intent of unified models. In this work, we aim to explore how to mitigate task conflicts without resorting to model decoupling. Firstly, we analyze why decoupling alleviates conflicts by studying the cross-modal attention behavior of models. We observe that model decoupling essentially drives models toward task-specific multimodal interaction patterns, as seen in Qwen-VL and HunyuanImage, and that the more thorough the decoupling, the more consistent the behavior becomes. Motivated by this observation, we propose Attention Interaction Alignment (AIA) loss, which explicitly learns Task-Specific multimodal interaction patterns during training. To demonstrate the generalizability of our AIA loss, we apply it to Emu3 and Janus-Pro during SFT and post-training stage respectively. Without bells and whistles, AIA not only refines cross-modal attention patterns, but also boosts both generation and understanding performance.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.22663.png", "numComments": 1, "submittedBy": {"_id": "67079840a9bcb7459b8d2a46", "avatarUrl": "/avatars/32466863c5554f20cb2775b138832ac3.svg", "fullname": "Kaituo Feng", "name": "KaituoFeng", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "isAuthorParticipating": false}, {"paper": {"id": "2511.23199", "authors": [{"_id": "692d09fb4397b1ec214f67b2", "name": "Zhenxiong Tan", "hidden": false}, {"_id": "692d09fb4397b1ec214f67b3", "name": "Zeqing Wang", "hidden": false}, {"_id": "692d09fb4397b1ec214f67b4", "name": "Xingyi Yang", "hidden": false}, {"_id": "692d09fb4397b1ec214f67b5", "name": "Songhua Liu", "hidden": false}, {"_id": "692d09fb4397b1ec214f67b6", "name": "Xinchao Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/634cfebc350bcee9bed20a4d/TtAxSiJXuWb3AASpinIdd.mp4"], "publishedAt": "2025-11-28T14:03:39.000Z", "submittedOnDailyAt": "2025-12-01T02:09:07.640Z", "title": "Vision Bridge Transformer at Scale", "submittedOnDailyBy": {"_id": "634cfebc350bcee9bed20a4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/634cfebc350bcee9bed20a4d/fN47nN5rhw-HJaFLBZWQy.png", "isPro": false, "fullname": "Xingyi Yang", "user": "adamdad", "type": "user"}, "summary": "We introduce Vision Bridge Transformer (ViBT), a large-scale instantiation of Brownian Bridge Models designed for conditional generation. Unlike traditional diffusion models that transform noise into data, Bridge Models directly model the trajectory between inputs and outputs, creating an efficient data-to-data translation paradigm. By scaling these models to 20B and 1.3B parameters, we demonstrate their effectiveness for image and video translation tasks. To support this scale, we adopt a Transformer architecture and propose a variance-stabilized velocity-matching objective for robust training. Together, these advances highlight the power of scaling Bridge Models for instruction-based image editing and complex video translation.", "upvotes": 7, "discussionId": "692d09fb4397b1ec214f67b7", "projectPage": "https://yuanshi9815.github.io/ViBT_homepage/", "githubRepo": "https://github.com/Yuanshi9815/ViBT", "ai_summary": "Bridge Models, instantiated as Vision Bridge Transformer (ViBT), efficiently translate data through direct modeling of input-to-output trajectories, achieving robust performance in image and video editing tasks at large scales.", "ai_keywords": ["Vision Bridge Transformer (ViBT)", "Brownian Bridge Models", "diffusion models", "data-to-data translation", "variance-stabilized velocity-matching objective"], "summary_zh": "<ul>\n    <li>\u4ecb\u7ecd\u4e86\u89c6\u89c9\u6865\u63a5\u53d8\u6362\u5668\uff08ViBT\uff09\uff0c\u7528\u4e8e\u6761\u4ef6\u751f\u6210\u7684\u5e03\u6717\u6865\u6a21\u578b\u3002</li>\n    <li>\u4e0e\u4f20\u7edf\u6269\u6563\u6a21\u578b\u4e0d\u540c\uff0c\u6865\u63a5\u6a21\u578b\u76f4\u63a5\u5efa\u6a21\u8f93\u5165\u548c\u8f93\u51fa\u4e4b\u95f4\u7684\u8f68\u8ff9\u3002</li>\n    <li>\u901a\u8fc7\u6269\u5c55\u5230200\u4ebf\u548c13\u4ebf\u53c2\u6570\uff0c\u8bc1\u660e\u4e86\u5176\u5728\u56fe\u50cf\u548c\u89c6\u9891\u7ffb\u8bd1\u4efb\u52a1\u4e2d\u7684\u6709\u6548\u6027\u3002</li>\n    <li>\u91c7\u7528\u53d8\u6362\u5668\u67b6\u6784\uff0c\u5e76\u63d0\u51fa\u4e86\u65b9\u5dee\u7a33\u5b9a\u7684\u901f\u5ea6\u5339\u914d\u76ee\u6807\u4ee5\u589e\u5f3a\u8bad\u7ec3\u7a33\u5065\u6027\u3002</li>\n    <li>\u8fd9\u4e9b\u8fdb\u5c55\u5c55\u793a\u4e86\u6269\u5c55\u6865\u63a5\u6a21\u578b\u5728\u57fa\u4e8e\u6307\u4ee4\u7684\u56fe\u50cf\u7f16\u8f91\u548c\u590d\u6742\u89c6\u9891\u7ffb\u8bd1\u4e2d\u7684\u6f5c\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Vision Bridge Transformer (ViBT) is a new model for generating data based on existing data.</li>\n    <li>It works differently from traditional models by directly modeling the process between input and output data.</li>\n    <li>ViBT has been scaled up to have 20 billion and 1.3 billion parameters, making it effective for translating images and videos.</li>\n    <li>The model uses a Transformer architecture and a special training method to improve stability.</li>\n    <li>This approach shows promise for advanced image editing and complex video translation tasks.</li>\n</ul>"}, "publishedAt": "2025-11-28T09:03:39.000Z", "title": "Vision Bridge Transformer at Scale", "summary": "We introduce Vision Bridge Transformer (ViBT), a large-scale instantiation of Brownian Bridge Models designed for conditional generation. Unlike traditional diffusion models that transform noise into data, Bridge Models directly model the trajectory between inputs and outputs, creating an efficient data-to-data translation paradigm. By scaling these models to 20B and 1.3B parameters, we demonstrate their effectiveness for image and video translation tasks. To support this scale, we adopt a Transformer architecture and propose a variance-stabilized velocity-matching objective for robust training. Together, these advances highlight the power of scaling Bridge Models for instruction-based image editing and complex video translation.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/634cfebc350bcee9bed20a4d/TtAxSiJXuWb3AASpinIdd.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.23199.png", "numComments": 1, "submittedBy": {"_id": "634cfebc350bcee9bed20a4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/634cfebc350bcee9bed20a4d/fN47nN5rhw-HJaFLBZWQy.png", "fullname": "Xingyi Yang", "name": "adamdad", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 17}, "isAuthorParticipating": false}, {"paper": {"id": "2511.22677", "authors": [{"_id": "692d12574397b1ec214f6850", "name": "Dongyang Liu", "hidden": false}, {"_id": "692d12574397b1ec214f6851", "name": "Peng Gao", "hidden": false}, {"_id": "692d12574397b1ec214f6852", "name": "David Liu", "hidden": false}, {"_id": "692d12574397b1ec214f6853", "name": "Ruoyi Du", "hidden": false}, {"_id": "692d12574397b1ec214f6854", "name": "Zhen Li", "hidden": false}, {"_id": "692d12574397b1ec214f6855", "name": "Qilong Wu", "hidden": false}, {"_id": "692d12574397b1ec214f6856", "name": "Xin Jin", "hidden": false}, {"_id": "692d12574397b1ec214f6857", "name": "Sihan Cao", "hidden": false}, {"_id": "692d12574397b1ec214f6858", "name": "Shifeng Zhang", "hidden": false}, {"_id": "692d12574397b1ec214f6859", "name": "Hongsheng Li", "hidden": false}, {"_id": "692d12574397b1ec214f685a", "name": "Steven Hoi", "hidden": false}], "publishedAt": "2025-11-27T18:24:28.000Z", "submittedOnDailyAt": "2025-12-01T01:29:35.579Z", "title": "Decoupled DMD: CFG Augmentation as the Spear, Distribution Matching as the Shield", "submittedOnDailyBy": {"_id": "646f1bef075e11ca78da3bb7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/646f1bef075e11ca78da3bb7/gNS-ikyZXYeMrf4a7HTQE.jpeg", "isPro": false, "fullname": "Dongyang Liu (Chris Liu)", "user": "Cxxs", "type": "user"}, "summary": "Diffusion model distillation has emerged as a powerful technique for creating efficient few-step and single-step generators. Among these, Distribution Matching Distillation (DMD) and its variants stand out for their impressive performance, which is widely attributed to their core mechanism of matching the student's output distribution to that of a pre-trained teacher model. In this work, we challenge this conventional understanding. Through a rigorous decomposition of the DMD training objective, we reveal that in complex tasks like text-to-image generation, where CFG is typically required for desirable few-step performance, the primary driver of few-step distillation is not distribution matching, but a previously overlooked component we identify as CFG Augmentation (CA). We demonstrate that this term acts as the core ``engine'' of distillation, while the Distribution Matching (DM) term functions as a ``regularizer'' that ensures training stability and mitigates artifacts. We further validate this decoupling by demonstrating that while the DM term is a highly effective regularizer, it is not unique; simpler non-parametric constraints or GAN-based objectives can serve the same stabilizing function, albeit with different trade-offs. This decoupling of labor motivates a more principled analysis of the properties of both terms, leading to a more systematic and in-depth understanding. This new understanding further enables us to propose principled modifications to the distillation process, such as decoupling the noise schedules for the engine and the regularizer, leading to further performance gains. Notably, our method has been adopted by the Z-Image ( https://github.com/Tongyi-MAI/Z-Image ) project to develop a top-tier 8-step image generation model, empirically validating the generalization and robustness of our findings.", "upvotes": 7, "discussionId": "692d12574397b1ec214f685b", "projectPage": "https://tongyi-mai.github.io/Z-Image-blog/", "githubRepo": "https://github.com/Tongyi-MAI/Z-Image/tree/main", "ai_summary": "The study reveals that in text-to-image generation, CFG Augmentation is the primary driver of few-step distillation in Distribution Matching Distillation (DMD), while the distribution matching term acts as a regularizer.", "ai_keywords": ["diffusion model distillation", "Distribution Matching Distillation (DMD)", "CFG Augmentation (CA)", "text-to-image generation", "configuration (CFG)", "distribution matching", "noise schedules", "Z-Image"], "githubStars": 2971, "organization": {"_id": "6925b20fed452d1567c012d3", "name": "Tongyi-MAI", "fullname": "Tongyi-MAI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64379d79fac5ea753f1c10f3/fxHO6QoYjdv9_LTyiUD3g.jpeg"}, "summary_zh": "<ul>\n    <li>\u6269\u6563\u6a21\u578b\u84b8\u998f\u662f\u4e00\u79cd\u9ad8\u6548\u7684\u751f\u6210\u5668\u6280\u672f\uff0c\u5c24\u5176\u662f\u5728\u5c11\u91cf\u6b65\u9aa4\u548c\u5355\u6b65\u751f\u6210\u4e2d\u3002</li>\n    <li>\u7814\u7a76\u6311\u6218\u4e86\u4f20\u7edf\u89c2\u5ff5\uff0c\u53d1\u73b0\u590d\u6742\u4efb\u52a1\uff08\u5982\u6587\u672c\u5230\u56fe\u50cf\u751f\u6210\uff09\u4e2d\u7684\u5173\u952e\u56e0\u7d20\u662f\u201cCFG\u589e\u5f3a\u201d\uff0c\u800c\u975e\u4ec5\u4ec5\u662f\u5206\u5e03\u5339\u914d\u3002</li>\n    <li>\u5206\u5e03\u5339\u914d\u5728\u84b8\u998f\u4e2d\u8d77\u5230\u201c\u6b63\u5219\u5316\u5668\u201d\u7684\u4f5c\u7528\uff0c\u786e\u4fdd\u8bad\u7ec3\u7a33\u5b9a\u6027\uff0c\u4f46\u5e76\u4e0d\u662f\u552f\u4e00\u7684\u9009\u62e9\u3002</li>\n    <li>\u901a\u8fc7\u89e3\u8026\u566a\u58f0\u8c03\u5ea6\uff0c\u6211\u4eec\u63d0\u51fa\u4e86\u6539\u8fdb\u84b8\u998f\u8fc7\u7a0b\u7684\u65b9\u6cd5\uff0c\u8fdb\u4e00\u6b65\u63d0\u9ad8\u4e86\u6027\u80fd\u3002</li>\n    <li>\u6211\u4eec\u7684\u7814\u7a76\u6210\u679c\u5df2\u88abZ-Image\u9879\u76ee\u91c7\u7528\uff0c\u6210\u529f\u5f00\u53d1\u51fa\u9876\u7ea7\u76848\u6b65\u56fe\u50cf\u751f\u6210\u6a21\u578b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Diffusion model distillation is a method for creating efficient image generators that can work in few steps.</li>\n    <li>Distribution Matching Distillation (DMD) is popular for its effective performance but this study questions why it works.</li>\n    <li>The authors found that in complex tasks like text-to-image generation, the key factor is not just matching distributions but a component called CFG Augmentation (CA).</li>\n    <li>They show that the Distribution Matching (DM) term helps stabilize training but is not the only way to do so; other methods can achieve similar results.</li>\n    <li>The research led to improvements in the distillation process, which were successfully applied in a new image generation model called Z-Image.</li>\n</ul>"}, "publishedAt": "2025-11-27T13:24:28.000Z", "title": "Decoupled DMD: CFG Augmentation as the Spear, Distribution Matching as the Shield", "summary": "Diffusion model distillation has emerged as a powerful technique for creating efficient few-step and single-step generators. Among these, Distribution Matching Distillation (DMD) and its variants stand out for their impressive performance, which is widely attributed to their core mechanism of matching the student's output distribution to that of a pre-trained teacher model. In this work, we challenge this conventional understanding. Through a rigorous decomposition of the DMD training objective, we reveal that in complex tasks like text-to-image generation, where CFG is typically required for desirable few-step performance, the primary driver of few-step distillation is not distribution matching, but a previously overlooked component we identify as CFG Augmentation (CA). We demonstrate that this term acts as the core ``engine'' of distillation, while the Distribution Matching (DM) term functions as a ``regularizer'' that ensures training stability and mitigates artifacts. We further validate this decoupling by demonstrating that while the DM term is a highly effective regularizer, it is not unique; simpler non-parametric constraints or GAN-based objectives can serve the same stabilizing function, albeit with different trade-offs. This decoupling of labor motivates a more principled analysis of the properties of both terms, leading to a more systematic and in-depth understanding. This new understanding further enables us to propose principled modifications to the distillation process, such as decoupling the noise schedules for the engine and the regularizer, leading to further performance gains. Notably, our method has been adopted by the Z-Image ( https://github.com/Tongyi-MAI/Z-Image ) project to develop a top-tier 8-step image generation model, empirically validating the generalization and robustness of our findings.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.22677.png", "numComments": 1, "submittedBy": {"_id": "646f1bef075e11ca78da3bb7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/646f1bef075e11ca78da3bb7/gNS-ikyZXYeMrf4a7HTQE.jpeg", "fullname": "Dongyang Liu (Chris Liu)", "name": "Cxxs", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 13}, "organization": {"_id": "6925b20fed452d1567c012d3", "name": "Tongyi-MAI", "fullname": "Tongyi-MAI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64379d79fac5ea753f1c10f3/fxHO6QoYjdv9_LTyiUD3g.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2511.23319", "authors": [{"_id": "692d0cae4397b1ec214f67d1", "name": "Xiang Hu", "hidden": false}, {"_id": "692d0cae4397b1ec214f67d2", "name": "Zhanchao Zhou", "hidden": false}, {"_id": "692d0cae4397b1ec214f67d3", "name": "Ruiqi Liang", "hidden": false}, {"_id": "692d0cae4397b1ec214f67d4", "name": "Zehuan Li", "hidden": false}, {"_id": "692d0cae4397b1ec214f67d5", "name": "Wei Wu", "hidden": false}, {"_id": "692d0cae4397b1ec214f67d6", "name": "Jianguo Li", "hidden": false}], "publishedAt": "2025-11-28T16:17:53.000Z", "submittedOnDailyAt": "2025-12-01T01:13:38.539Z", "title": "Every Token Counts: Generalizing 16M Ultra-Long Context in Large Language Models", "submittedOnDailyBy": {"_id": "671b3d82101c0d9f78749256", "avatarUrl": "/avatars/902c1006280c6552885b0b946cd2bb16.svg", "isPro": false, "fullname": "Zhanchao Zhou", "user": "Zcchill", "type": "user"}, "summary": "This work explores the challenge of building ``Machines that Can Remember'', framing long-term memory as the problem of efficient ultra-long context modeling. We argue that this requires three key properties: sparsity, random-access flexibility, and length generalization. To address ultra-long-context modeling, we leverage Hierarchical Sparse Attention (HSA), a novel attention mechanism that satisfies all three properties. We integrate HSA into Transformers to build HSA-UltraLong, which is an 8B-parameter MoE model trained on over 8 trillion tokens and is rigorously evaluated on different tasks with in-domain and out-of-domain context lengths to demonstrate its capability in handling ultra-long contexts. Results show that our model performs comparably to full-attention baselines on in-domain lengths while achieving over 90\\% accuracy on most in-context retrieval tasks with contexts up to 16M. This report outlines our experimental insights and open problems, contributing a foundation for future research in ultra-long context modeling.", "upvotes": 2, "discussionId": "692d0cae4397b1ec214f67d7", "ai_summary": "Hierarchical Sparse Attention (HSA) is integrated into Transformers to efficiently handle ultra-long contexts, achieving high accuracy on in-context retrieval tasks.", "ai_keywords": ["Hierarchical Sparse Attention (HSA)", "Transformers", "ultra-long context modeling", "sparsity", "random-access flexibility", "length generalization", "MoE model"], "summary_zh": "<ul>\n    <li>\u672c\u7814\u7a76\u63a2\u8ba8\u4e86\u6784\u5efa\u201c\u80fd\u8bb0\u4f4f\u7684\u673a\u5668\u201d\u7684\u6311\u6218\uff0c\u91cd\u70b9\u662f\u9ad8\u6548\u7684\u8d85\u957f\u4e0a\u4e0b\u6587\u5efa\u6a21\u3002</li>\n    <li>\u6211\u4eec\u8ba4\u4e3a\u8d85\u957f\u4e0a\u4e0b\u6587\u5efa\u6a21\u9700\u8981\u4e09\u4e2a\u5173\u952e\u7279\u6027\uff1a\u7a00\u758f\u6027\u3001\u968f\u673a\u8bbf\u95ee\u7075\u6d3b\u6027\u548c\u957f\u5ea6\u6982\u62ec\u80fd\u529b\u3002</li>\n    <li>\u4e3a\u4e86\u89e3\u51b3\u8d85\u957f\u4e0a\u4e0b\u6587\u5efa\u6a21\u95ee\u9898\uff0c\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u6ce8\u610f\u529b\u673a\u5236\uff0c\u79f0\u4e3a\u5c42\u6b21\u7a00\u758f\u6ce8\u610f\u529b\uff08HSA\uff09\uff0c\u5b83\u6ee1\u8db3\u4e0a\u8ff0\u4e09\u4e2a\u7279\u6027\u3002</li>\n    <li>\u6211\u4eec\u5c06HSA\u96c6\u6210\u5230\u53d8\u6362\u5668\u4e2d\uff0c\u6784\u5efa\u4e86HSA-UltraLong\u6a21\u578b\uff0c\u8be5\u6a21\u578b\u5177\u670980\u4ebf\u53c2\u6570\uff0c\u5728\u8d85\u8fc78\u4e07\u4ebf\u4e2a\u6807\u8bb0\u4e0a\u8fdb\u884c\u8bad\u7ec3\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u8868\u660e\uff0c\u8be5\u6a21\u578b\u5728\u5904\u7406\u8d85\u957f\u4e0a\u4e0b\u6587\u65f6\u6027\u80fd\u826f\u597d\uff0c\u5c24\u5176\u662f\u5728\u4e0a\u4e0b\u6587\u957f\u5ea6\u8fbe\u523016M\u65f6\uff0c\u51c6\u786e\u7387\u8d85\u8fc790%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The study focuses on creating machines that can effectively remember by improving long-term memory through better context modeling.</li>\n    <li>Three important features for this memory improvement are identified: sparsity, random access flexibility, and the ability to generalize across different lengths.</li>\n    <li>The researchers developed a new attention mechanism called Hierarchical Sparse Attention (HSA) that meets these criteria, which they used in a new model called HSA-UltraLong.</li>\n    <li>This model, with 8 billion parameters, was trained on a massive dataset of over 8 trillion tokens and tested on various tasks to evaluate its performance with very long contexts.</li>\n    <li>The results showed that HSA-UltraLong performs well on tasks related to long contexts, achieving high accuracy in retrieval tasks while being competitive with traditional models.</li>\n</ul>"}, "publishedAt": "2025-11-28T11:17:53.000Z", "title": "Every Token Counts: Generalizing 16M Ultra-Long Context in Large Language Models", "summary": "This work explores the challenge of building ``Machines that Can Remember'', framing long-term memory as the problem of efficient ultra-long context modeling. We argue that this requires three key properties: sparsity, random-access flexibility, and length generalization. To address ultra-long-context modeling, we leverage Hierarchical Sparse Attention (HSA), a novel attention mechanism that satisfies all three properties. We integrate HSA into Transformers to build HSA-UltraLong, which is an 8B-parameter MoE model trained on over 8 trillion tokens and is rigorously evaluated on different tasks with in-domain and out-of-domain context lengths to demonstrate its capability in handling ultra-long contexts. Results show that our model performs comparably to full-attention baselines on in-domain lengths while achieving over 90\\% accuracy on most in-context retrieval tasks with contexts up to 16M. This report outlines our experimental insights and open problems, contributing a foundation for future research in ultra-long context modeling.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.23319.png", "numComments": 1, "submittedBy": {"_id": "671b3d82101c0d9f78749256", "avatarUrl": "/avatars/902c1006280c6552885b0b946cd2bb16.svg", "fullname": "Zhanchao Zhou", "name": "Zcchill", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false}, "isAuthorParticipating": false}, {"paper": {"id": "2511.22815", "authors": [{"_id": "692d10e04397b1ec214f6835", "name": "Yu-Cheng Chou", "hidden": false}, {"_id": "692d10e04397b1ec214f6836", "name": "Xingrui Wang", "hidden": false}, {"_id": "692d10e04397b1ec214f6837", "name": "Yitong Li", "hidden": false}, {"_id": "692d10e04397b1ec214f6838", "name": "Jiahao Wang", "hidden": false}, {"_id": "692d10e04397b1ec214f6839", "name": "Hanting Liu", "hidden": false}, {"_id": "692d10e04397b1ec214f683a", "name": "Cihang Xie", "hidden": false}, {"_id": "692d10e04397b1ec214f683b", "name": "Alan Yuille", "hidden": false}, {"_id": "692d10e04397b1ec214f683c", "name": "Junfei Xiao", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/4Tma8QScvmFvb5RVRp-gK.mp4"], "publishedAt": "2025-11-28T00:27:46.000Z", "submittedOnDailyAt": "2025-12-01T01:23:31.270Z", "title": "Captain Safari: A World Engine", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "World engines aim to synthesize long, 3D-consistent videos that support interactive exploration of a scene under user-controlled camera motion. However, existing systems struggle under aggressive 6-DoF trajectories and complex outdoor layouts: they lose long-range geometric coherence, deviate from the target path, or collapse into overly conservative motion. To this end, we introduce Captain Safari, a pose-conditioned world engine that generates videos by retrieving from a persistent world memory. Given a camera path, our method maintains a dynamic local memory and uses a retriever to fetch pose-aligned world tokens, which then condition video generation along the trajectory. This design enables the model to maintain stable 3D structure while accurately executing challenging camera maneuvers. To evaluate this setting, we curate OpenSafari, a new in-the-wild FPV dataset containing high-dynamic drone videos with verified camera trajectories, constructed through a multi-stage geometric and kinematic validation pipeline. Across video quality, 3D consistency, and trajectory following, Captain Safari substantially outperforms state-of-the-art camera-controlled generators. It reduces MEt3R from 0.3703 to 0.3690, improves AUC@30 from 0.181 to 0.200, and yields substantially lower FVD than all camera-controlled baselines. More importantly, in a 50-participant, 5-way human study where annotators select the best result among five anonymized models, 67.6% of preferences favor our method across all axes. Our results demonstrate that pose-conditioned world memory is a powerful mechanism for long-horizon, controllable video generation and provide OpenSafari as a challenging new benchmark for future world-engine research.", "upvotes": 2, "discussionId": "692d10e14397b1ec214f683d", "projectPage": "https://johnson111788.github.io/open-safari/", "ai_summary": "Captain Safari, a pose-conditioned world engine using a dynamic local memory and retriever for pose-aligned world tokens, generates high-quality, 3D-consistent long videos with accurate camera maneuvers, outperforming existing methods across quality, consistency, and trajectory following.", "ai_keywords": ["pose-conditioned world engine", "world memory", "dynamic local memory", "retriever", "pose-aligned world tokens", "video generation", "FPV dataset", "geometric validation", "kinematic validation", "MEt3R", "AUC@30", "FVD", "human study"], "summary_zh": "<ul>\n    <li>\u4e16\u754c\u5f15\u64ce\u65e8\u5728\u5408\u6210\u957f\u65f6\u95f4\u76843D\u4e00\u81f4\u6027\u89c6\u9891\uff0c\u652f\u6301\u7528\u6237\u63a7\u5236\u6444\u50cf\u673a\u8fd0\u52a8\u8fdb\u884c\u4e92\u52a8\u63a2\u7d22\u3002</li>\n    <li>\u73b0\u6709\u7cfb\u7edf\u5728\u590d\u6742\u7684\u6237\u5916\u73af\u5883\u548c\u6fc0\u8fdb\u76846\u81ea\u7531\u5ea6\u8def\u5f84\u4e0b\u8868\u73b0\u4e0d\u4f73\uff0c\u5e38\u5e38\u5931\u53bb\u51e0\u4f55\u4e00\u81f4\u6027\u6216\u504f\u79bb\u76ee\u6807\u8def\u5f84\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86Captain Safari\uff0c\u8fd9\u662f\u4e00\u79cd\u57fa\u4e8e\u59ff\u6001\u6761\u4ef6\u7684\u4e16\u754c\u5f15\u64ce\uff0c\u901a\u8fc7\u6301\u4e45\u7684\u4e16\u754c\u8bb0\u5fc6\u751f\u6210\u89c6\u9891\u3002</li>\n    <li>\u8be5\u65b9\u6cd5\u80fd\u591f\u4fdd\u6301\u7a33\u5b9a\u76843D\u7ed3\u6784\uff0c\u5e76\u51c6\u786e\u6267\u884c\u590d\u6742\u7684\u6444\u50cf\u673a\u52a8\u4f5c\uff0c\u663e\u8457\u4f18\u4e8e\u73b0\u6709\u7684\u751f\u6210\u6a21\u578b\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u521b\u5efa\u4e86OpenSafari\u6570\u636e\u96c6\uff0c\u5305\u542b\u7ecf\u8fc7\u9a8c\u8bc1\u7684\u9ad8\u52a8\u6001\u65e0\u4eba\u673a\u89c6\u9891\uff0c\u4e3a\u672a\u6765\u7684\u7814\u7a76\u63d0\u4f9b\u4e86\u65b0\u7684\u57fa\u51c6\u3002 </li>\n</ul>", "summary_simple": "<ul>\n    <li>Captain Safari is a new system that creates long, 3D videos allowing users to explore scenes with camera movements they control.</li>\n    <li>It solves problems faced by previous systems, such as losing 3D structure during complex camera movements in outdoor settings.</li>\n    <li>The system uses a memory of the world to help generate videos that stay aligned with the user's camera path.</li>\n    <li>OpenSafari is a new dataset created to test this system, featuring high-quality drone videos with accurate camera paths.</li>\n    <li>Captain Safari outperforms other video generation systems in quality and user preference, demonstrating its effectiveness for creating controllable videos.</li>\n</ul>"}, "publishedAt": "2025-11-27T19:27:46.000Z", "title": "Captain Safari: A World Engine", "summary": "World engines aim to synthesize long, 3D-consistent videos that support interactive exploration of a scene under user-controlled camera motion. However, existing systems struggle under aggressive 6-DoF trajectories and complex outdoor layouts: they lose long-range geometric coherence, deviate from the target path, or collapse into overly conservative motion. To this end, we introduce Captain Safari, a pose-conditioned world engine that generates videos by retrieving from a persistent world memory. Given a camera path, our method maintains a dynamic local memory and uses a retriever to fetch pose-aligned world tokens, which then condition video generation along the trajectory. This design enables the model to maintain stable 3D structure while accurately executing challenging camera maneuvers. To evaluate this setting, we curate OpenSafari, a new in-the-wild FPV dataset containing high-dynamic drone videos with verified camera trajectories, constructed through a multi-stage geometric and kinematic validation pipeline. Across video quality, 3D consistency, and trajectory following, Captain Safari substantially outperforms state-of-the-art camera-controlled generators. It reduces MEt3R from 0.3703 to 0.3690, improves AUC@30 from 0.181 to 0.200, and yields substantially lower FVD than all camera-controlled baselines. More importantly, in a 50-participant, 5-way human study where annotators select the best result among five anonymized models, 67.6% of preferences favor our method across all axes. Our results demonstrate that pose-conditioned world memory is a powerful mechanism for long-horizon, controllable video generation and provide OpenSafari as a challenging new benchmark for future world-engine research.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/4Tma8QScvmFvb5RVRp-gK.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.22815.png", "numComments": 1, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 172}, "isAuthorParticipating": false}, {"paper": {"id": "2511.22688", "authors": [{"_id": "692d0ac14397b1ec214f67b9", "name": "Amirmojtaba Sabour", "hidden": false}, {"_id": "692d0ac14397b1ec214f67ba", "name": "Michael S. Albergo", "hidden": false}, {"_id": "692d0ac14397b1ec214f67bb", "name": "Carles Domingo-Enrich", "hidden": false}, {"_id": "692d0ac14397b1ec214f67bc", "name": "Nicholas M. Boffi", "hidden": false}, {"_id": "692d0ac14397b1ec214f67bd", "name": "Sanja Fidler", "hidden": false}, {"_id": "692d0ac14397b1ec214f67be", "name": "Karsten Kreis", "hidden": false}, {"_id": "692d0ac14397b1ec214f67bf", "name": "Eric Vanden-Eijnden", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/656015f28138827138c70858/v4LaQJJywUY72czXHHlAV.jpeg", "https://cdn-uploads.huggingface.co/production/uploads/656015f28138827138c70858/xGWJLesdUtQKHyfpGBNWx.jpeg"], "publishedAt": "2025-11-27T18:44:12.000Z", "submittedOnDailyAt": "2025-12-01T00:59:28.500Z", "title": "Test-time scaling of diffusions with flow maps", "submittedOnDailyBy": {"_id": "656015f28138827138c70858", "avatarUrl": "/avatars/b8471ae4d80f078c7c928fc3d8f49126.svg", "isPro": false, "fullname": "Amirmojtaba Sabour", "user": "amsabour", "type": "user"}, "summary": "A common recipe to improve diffusion models at test-time so that samples score highly against a user-specified reward is to introduce the gradient of the reward into the dynamics of the diffusion itself. This procedure is often ill posed, as user-specified rewards are usually only well defined on the data distribution at the end of generation. While common workarounds to this problem are to use a denoiser to estimate what a sample would have been at the end of generation, we propose a simple solution to this problem by working directly with a flow map. By exploiting a relationship between the flow map and velocity field governing the instantaneous transport, we construct an algorithm, Flow Map Trajectory Tilting (FMTT), which provably performs better ascent on the reward than standard test-time methods involving the gradient of the reward. The approach can be used to either perform exact sampling via importance weighting or principled search that identifies local maximizers of the reward-tilted distribution. We demonstrate the efficacy of our approach against other look-ahead techniques, and show how the flow map enables engagement with complicated reward functions that make possible new forms of image editing, e.g. by interfacing with vision language models.", "upvotes": 2, "discussionId": "692d0ac14397b1ec214f67c0", "projectPage": "https://flow-map-trajectory-tilting.github.io/", "ai_summary": "The proposed Flow Map Trajectory Tilting (FMTT) algorithm improves diffusion models at test-time by leveraging flow maps to better align with user-specified rewards, enabling more effective sampling and image editing.", "ai_keywords": ["diffusion models", "gradient of the reward", "flow map", "velocity field", "Flow Map Trajectory Tilting (FMTT)", "importance weighting", "reward-tilted distribution", "vision language models"], "summary_zh": "<ul>\n    <li>\u4e3a\u4e86\u63d0\u9ad8\u6269\u6563\u6a21\u578b\u5728\u6d4b\u8bd5\u65f6\u7684\u8868\u73b0\uff0c\u901a\u5e38\u4f1a\u5c06\u7528\u6237\u6307\u5b9a\u7684\u5956\u52b1\u7684\u68af\u5ea6\u5f15\u5165\u6269\u6563\u8fc7\u7a0b\u3002</li>\n    <li>\u8fd9\u4e2a\u8fc7\u7a0b\u5e38\u5e38\u5b58\u5728\u95ee\u9898\uff0c\u56e0\u4e3a\u7528\u6237\u6307\u5b9a\u7684\u5956\u52b1\u901a\u5e38\u4ec5\u5728\u751f\u6210\u7ed3\u675f\u540e\u7684\u6570\u636e\u5206\u5e03\u4e0a\u5b9a\u4e49\u5f97\u5f88\u597d\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u7b80\u5355\u7684\u89e3\u51b3\u65b9\u6848\uff0c\u901a\u8fc7\u76f4\u63a5\u4f7f\u7528\u6d41\u56fe\u6765\u89e3\u51b3\u8fd9\u4e2a\u95ee\u9898\u3002</li>\n    <li>\u6211\u4eec\u6784\u5efa\u4e86\u4e00\u79cd\u7b97\u6cd5\uff0c\u79f0\u4e3a\u6d41\u56fe\u8f68\u8ff9\u503e\u659c\uff08FMTT\uff09\uff0c\u5176\u5728\u63d0\u5347\u5956\u52b1\u65b9\u9762\u6bd4\u6807\u51c6\u6d4b\u8bd5\u65b9\u6cd5\u8868\u73b0\u66f4\u597d\u3002</li>\n    <li>\u8be5\u65b9\u6cd5\u53ef\u4ee5\u7528\u4e8e\u901a\u8fc7\u91cd\u8981\u6027\u52a0\u6743\u8fdb\u884c\u7cbe\u786e\u91c7\u6837\u6216\u8bc6\u522b\u5956\u52b1\u503e\u659c\u5206\u5e03\u7684\u5c40\u90e8\u6700\u5927\u503c\uff0c\u4ece\u800c\u5b9e\u73b0\u65b0\u7684\u56fe\u50cf\u7f16\u8f91\u5f62\u5f0f\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>To improve diffusion models during testing, researchers often add the reward's gradient to the diffusion process.</li>\n    <li>This method can be problematic because rewards are usually only clear after the generation is complete.</li>\n    <li>The authors propose a new method called Flow Map Trajectory Tilting (FMTT) that directly uses a flow map for better performance.</li>\n    <li>FMTT is shown to outperform traditional methods in maximizing rewards and can be used for precise sampling and searching for reward-maximizing options.</li>\n    <li>The approach allows for advanced image editing techniques by linking with vision language models.</li>\n</ul>"}, "publishedAt": "2025-11-27T13:44:12.000Z", "title": "Test-time scaling of diffusions with flow maps", "summary": "A common recipe to improve diffusion models at test-time so that samples score highly against a user-specified reward is to introduce the gradient of the reward into the dynamics of the diffusion itself. This procedure is often ill posed, as user-specified rewards are usually only well defined on the data distribution at the end of generation. While common workarounds to this problem are to use a denoiser to estimate what a sample would have been at the end of generation, we propose a simple solution to this problem by working directly with a flow map. By exploiting a relationship between the flow map and velocity field governing the instantaneous transport, we construct an algorithm, Flow Map Trajectory Tilting (FMTT), which provably performs better ascent on the reward than standard test-time methods involving the gradient of the reward. The approach can be used to either perform exact sampling via importance weighting or principled search that identifies local maximizers of the reward-tilted distribution. We demonstrate the efficacy of our approach against other look-ahead techniques, and show how the flow map enables engagement with complicated reward functions that make possible new forms of image editing, e.g. by interfacing with vision language models.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/656015f28138827138c70858/v4LaQJJywUY72czXHHlAV.jpeg", "https://cdn-uploads.huggingface.co/production/uploads/656015f28138827138c70858/xGWJLesdUtQKHyfpGBNWx.jpeg"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.22688.png", "numComments": 1, "submittedBy": {"_id": "656015f28138827138c70858", "avatarUrl": "/avatars/b8471ae4d80f078c7c928fc3d8f49126.svg", "fullname": "Amirmojtaba Sabour", "name": "amsabour", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1}, "isAuthorParticipating": false}, {"paper": {"id": "2511.22281", "authors": [{"_id": "692d0f6f4397b1ec214f681c", "name": "Wei Guo", "hidden": false}, {"_id": "692d0f6f4397b1ec214f681d", "name": "Shunqi Mao", "hidden": false}, {"_id": "692d0f6f4397b1ec214f681e", "name": "Zhuonan Liang", "hidden": false}, {"_id": "692d0f6f4397b1ec214f681f", "name": "Heng Wang", "hidden": false}, {"_id": "692d0f6f4397b1ec214f6820", "name": "Weidong Cai", "hidden": false}], "publishedAt": "2025-11-27T10:04:44.000Z", "submittedOnDailyAt": "2025-12-01T01:16:01.722Z", "title": "The Collapse of Patches", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "Observing certain patches in an image reduces the uncertainty of others. Their realization lowers the distribution entropy of each remaining patch feature, analogous to collapsing a particle's wave function in quantum mechanics. This phenomenon can intuitively be called patch collapse. To identify which patches are most relied on during a target region's collapse, we learn an autoencoder that softly selects a subset of patches to reconstruct each target patch. Graphing these learned dependencies for each patch's PageRank score reveals the optimal patch order to realize an image. We show that respecting this order benefits various masked image modeling methods. First, autoregressive image generation can be boosted by retraining the state-of-the-art model MAR. Next, we introduce a new setup for image classification by exposing Vision Transformers only to high-rank patches in the collapse order. Seeing 22\\% of such patches is sufficient to achieve high accuracy. With these experiments, we propose patch collapse as a novel image modeling perspective that promotes vision efficiency. Our project is available at https://github.com/wguo-ai/CoP .", "upvotes": 2, "discussionId": "692d0f6f4397b1ec214f6821", "githubRepo": "https://github.com/wguo-ai/CoP", "ai_summary": "Patch collapse, a phenomenon where observing certain image patches reduces uncertainty in others, improves masked image modeling and promotes vision efficiency through selective patch exposure.", "ai_keywords": ["autoencoder", "PageRank score", "patch collapse", "autoregressive image generation", "MAR", "Vision Transformers", "image classification", "masked image modeling"], "githubStars": 1, "summary_zh": "<ul>\n    <li>\u89c2\u5bdf\u56fe\u50cf\u4e2d\u7684\u67d0\u4e9b\u533a\u57df\u53ef\u4ee5\u964d\u4f4e\u5176\u4ed6\u533a\u57df\u7684\u4e0d\u786e\u5b9a\u6027\uff0c\u8fd9\u88ab\u79f0\u4e3a\u201c\u533a\u57df\u5d29\u6e83\u201d\u3002</li>\n    <li>\u901a\u8fc7\u5b66\u4e60\u81ea\u7f16\u7801\u5668\uff0c\u53ef\u4ee5\u8bc6\u522b\u5728\u76ee\u6807\u533a\u57df\u5d29\u6e83\u65f6\u6700\u4f9d\u8d56\u7684\u56fe\u50cf\u533a\u57df\u3002</li>\n    <li>\u6839\u636e\u6bcf\u4e2a\u533a\u57df\u7684\u4f9d\u8d56\u5173\u7cfb\uff0c\u53ef\u4ee5\u4f18\u5316\u56fe\u50cf\u7684\u5b9e\u73b0\u987a\u5e8f\uff0c\u4ece\u800c\u63d0\u9ad8\u56fe\u50cf\u751f\u6210\u548c\u5206\u7c7b\u7684\u6548\u679c\u3002</li>\n    <li>\u91cd\u65b0\u8bad\u7ec3\u6a21\u578b\u53ef\u4ee5\u63d0\u9ad8\u81ea\u56de\u5f52\u56fe\u50cf\u751f\u6210\u7684\u8868\u73b0\uff1b\u4ec5\u4f7f\u7528\u9ad8\u6392\u540d\u7684\u533a\u57df\u8fdb\u884c\u56fe\u50cf\u5206\u7c7b\u4e5f\u80fd\u5b9e\u73b0\u9ad8\u51c6\u786e\u7387\u3002</li>\n    <li>\u63d0\u51fa\u7684\u201c\u533a\u57df\u5d29\u6e83\u201d\u63d0\u4f9b\u4e86\u4e00\u79cd\u65b0\u7684\u56fe\u50cf\u5efa\u6a21\u89c6\u89d2\uff0c\u6709\u52a9\u4e8e\u63d0\u9ad8\u89c6\u89c9\u6548\u7387\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Observing certain parts of an image helps reduce uncertainty about other parts, similar to how observing particles affects their state in quantum mechanics.</li>\n    <li>This concept is termed \"patch collapse,\" where specific patches influence the overall understanding of an image.</li>\n    <li>An autoencoder is used to determine which patches are most important for reconstructing target patches, allowing for better image modeling.</li>\n    <li>Following a specific order of patches improves results in image generation and classification tasks, like enhancing a model called MAR.</li>\n    <li>Only seeing a small number (22%) of the most important patches can lead to high accuracy in classification tasks.</li>\n</ul>"}, "publishedAt": "2025-11-27T05:04:44.000Z", "title": "The Collapse of Patches", "summary": "Observing certain patches in an image reduces the uncertainty of others. Their realization lowers the distribution entropy of each remaining patch feature, analogous to collapsing a particle's wave function in quantum mechanics. This phenomenon can intuitively be called patch collapse. To identify which patches are most relied on during a target region's collapse, we learn an autoencoder that softly selects a subset of patches to reconstruct each target patch. Graphing these learned dependencies for each patch's PageRank score reveals the optimal patch order to realize an image. We show that respecting this order benefits various masked image modeling methods. First, autoregressive image generation can be boosted by retraining the state-of-the-art model MAR. Next, we introduce a new setup for image classification by exposing Vision Transformers only to high-rank patches in the collapse order. Seeing 22\\% of such patches is sufficient to achieve high accuracy. With these experiments, we propose patch collapse as a novel image modeling perspective that promotes vision efficiency. Our project is available at https://github.com/wguo-ai/CoP .", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.22281.png", "numComments": 2, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 172}, "isAuthorParticipating": false}],
    "week": [{"paper": {"id": "2511.20626", "authors": [{"_id": "6927ab26243b2216fb75cd1b", "name": "Wei He", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1c", "user": {"_id": "65e52e7d27dc8aa470a640e3", "avatarUrl": "/avatars/022a179d14de29b9ab9d96fcc85aa264.svg", "isPro": false, "fullname": "hankai", "user": "hankaixyz", "type": "user"}, "name": "Kai Han", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T09:59:11.052Z", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1d", "name": "Hang Zhou", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1e", "name": "Hanting Chen", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1f", "name": "Zhicheng Liu", "hidden": false}, {"_id": "6927ab26243b2216fb75cd20", "name": "Xinghao Chen", "hidden": false}, {"_id": "6927ab26243b2216fb75cd21", "name": "Yunhe Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65e52e7d27dc8aa470a640e3/r9QpXyUHL3SWym780xlxD.png"], "publishedAt": "2025-11-25T18:48:05.000Z", "submittedOnDailyAt": "2025-11-26T23:08:13.066Z", "title": "ROOT: Robust Orthogonalized Optimizer for Neural Network Training", "submittedOnDailyBy": {"_id": "65e52e7d27dc8aa470a640e3", "avatarUrl": "/avatars/022a179d14de29b9ab9d96fcc85aa264.svg", "isPro": false, "fullname": "hankai", "user": "hankaixyz", "type": "user"}, "summary": "The optimization of large language models (LLMs) remains a critical challenge, particularly as model scaling exacerbates sensitivity to algorithmic imprecision and training instability. Recent advances in optimizers have improved convergence efficiency through momentum orthogonalization, but suffer from two key robustness limitations: dimensional fragility in orthogonalization precision and vulnerability to outlier-induced noise. To address these robustness challenges, we introduce ROOT, a Robust Orthogonalized Optimizer that enhances training stability through dual robustness mechanisms. First, we develop a dimension-robust orthogonalization scheme using adaptive Newton iterations with fine-grained coefficients tailored to specific matrix sizes, ensuring consistent precision across diverse architectural configurations. Second, we introduce an optimization-robust framework via proximal optimization that suppresses outlier noise while preserving meaningful gradient directions. Extensive experiments demonstrate that ROOT achieves significantly improved robustness, with faster convergence and superior final performance compared to both Muon and Adam-based optimizers, particularly in noisy and non-convex scenarios. Our work establishes a new paradigm for developing robust and precise optimizers capable of handling the complexities of modern large-scale model training. The code will be available at https://github.com/huawei-noah/noah-research/tree/master/ROOT.", "upvotes": 154, "discussionId": "6927ab27243b2216fb75cd22", "projectPage": "https://github.com/huawei-noah/noah-research/tree/master/ROOT", "githubRepo": "https://github.com/huawei-noah/noah-research", "ai_summary": "ROOT, a robust optimizer, enhances training stability and convergence for large language models by addressing dimensional fragility and outlier noise through adaptive Newton iterations and proximal optimization.", "ai_keywords": ["large language models", "LLMs", "momentum orthogonalization", "dimensional fragility", "outlier-induced noise", "adaptive Newton iterations", "proximal optimization", "Muon", "Adam-based optimizers", "robust optimizer"], "githubStars": 909, "organization": {"_id": "5f83c275f0801648bf88454a", "name": "huawei-noah", "fullname": "HUAWEI Noah's Ark Lab", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1602470452594-5f83c19ff0801648bf884549.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\u7684\u4f18\u5316\u662f\u4e00\u4e2a\u91cd\u8981\u6311\u6218\uff0c\u6a21\u578b\u89c4\u6a21\u589e\u52a0\u52a0\u5267\u4e86\u7b97\u6cd5\u4e0d\u7cbe\u786e\u548c\u8bad\u7ec3\u4e0d\u7a33\u5b9a\u6027\u7684\u95ee\u9898\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e00\u79cd\u65b0\u7684\u4f18\u5316\u5668ROOT\uff0c\u65e8\u5728\u901a\u8fc7\u53cc\u91cd\u7a33\u5065\u673a\u5236\u6765\u589e\u5f3a\u8bad\u7ec3\u7a33\u5b9a\u6027\u3002</li>\n    <li>ROOT\u91c7\u7528\u81ea\u9002\u5e94\u725b\u987f\u8fed\u4ee3\u7684\u7ef4\u5ea6\u7a33\u5065\u6b63\u4ea4\u5316\u65b9\u6848\uff0c\u63d0\u9ad8\u4e86\u4e0d\u540c\u67b6\u6784\u914d\u7f6e\u4e0b\u7684\u7cbe\u786e\u5ea6\u3002</li>\n    <li>ROOT\u8fd8\u901a\u8fc7\u90bb\u8fd1\u4f18\u5316\u6846\u67b6\u6291\u5236\u5f02\u5e38\u503c\u566a\u58f0\uff0c\u540c\u65f6\u4fdd\u6301\u6709\u610f\u4e49\u7684\u68af\u5ea6\u65b9\u5411\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cROOT\u5728\u566a\u58f0\u548c\u975e\u51f8\u573a\u666f\u4e2d\u6bd4Muon\u548c\u57fa\u4e8eAdam\u7684\u4f18\u5316\u5668\u5177\u6709\u66f4\u5feb\u7684\u6536\u655b\u901f\u5ea6\u548c\u66f4\u597d\u7684\u6700\u7ec8\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language models (LLMs) face challenges with training stability and precision as they grow in size.</li>\n    <li>Recent optimizers have improved efficiency but struggle with robustness against noise and dimensional changes.</li>\n    <li>ROOT is a new optimizer that strengthens training stability using two innovative methods: dimension-robust orthogonalization and noise suppression.</li>\n    <li>Experiments show ROOT outperforms other optimizers like Muon and Adam in tough conditions, achieving faster training and better results.</li>\n    <li>The ROOT code will be available online for others to use and build upon.</li>\n</ul>"}, "publishedAt": "2025-11-25T13:48:05.000Z", "title": "ROOT: Robust Orthogonalized Optimizer for Neural Network Training", "summary": "The optimization of large language models (LLMs) remains a critical challenge, particularly as model scaling exacerbates sensitivity to algorithmic imprecision and training instability. Recent advances in optimizers have improved convergence efficiency through momentum orthogonalization, but suffer from two key robustness limitations: dimensional fragility in orthogonalization precision and vulnerability to outlier-induced noise. To address these robustness challenges, we introduce ROOT, a Robust Orthogonalized Optimizer that enhances training stability through dual robustness mechanisms. First, we develop a dimension-robust orthogonalization scheme using adaptive Newton iterations with fine-grained coefficients tailored to specific matrix sizes, ensuring consistent precision across diverse architectural configurations. Second, we introduce an optimization-robust framework via proximal optimization that suppresses outlier noise while preserving meaningful gradient directions. Extensive experiments demonstrate that ROOT achieves significantly improved robustness, with faster convergence and superior final performance compared to both Muon and Adam-based optimizers, particularly in noisy and non-convex scenarios. Our work establishes a new paradigm for developing robust and precise optimizers capable of handling the complexities of modern large-scale model training. The code will be available at https://github.com/huawei-noah/noah-research/tree/master/ROOT.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65e52e7d27dc8aa470a640e3/r9QpXyUHL3SWym780xlxD.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20626.png", "numComments": 2, "submittedBy": {"_id": "65e52e7d27dc8aa470a640e3", "avatarUrl": "/avatars/022a179d14de29b9ab9d96fcc85aa264.svg", "fullname": "hankai", "name": "hankaixyz", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "organization": {"_id": "5f83c275f0801648bf88454a", "name": "huawei-noah", "fullname": "HUAWEI Noah's Ark Lab", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1602470452594-5f83c19ff0801648bf884549.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.20639", "authors": [{"_id": "6927c504243b2216fb75cd62", "user": {"_id": "65c288280aa2d53135734a42", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65c288280aa2d53135734a42/5WHmau52EaRS01TOMI3Qg.jpeg", "isPro": false, "fullname": "Jiaru Zou", "user": "jiaruz2", "type": "user"}, "name": "Jiaru Zou", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T09:58:44.029Z", "hidden": false}, {"_id": "6927c504243b2216fb75cd63", "name": "Xiyuan Yang", "hidden": false}, {"_id": "6927c504243b2216fb75cd64", "name": "Ruizhong Qiu", "hidden": false}, {"_id": "6927c504243b2216fb75cd65", "name": "Gaotang Li", "hidden": false}, {"_id": "6927c504243b2216fb75cd66", "name": "Katherine Tieu", "hidden": false}, {"_id": "6927c504243b2216fb75cd67", "user": {"_id": "60f5f68fa7fd83d025749234", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/60f5f68fa7fd83d025749234/gCeJAZfzaANAcEvI6v5-P.jpeg", "isPro": false, "fullname": "Pan Lu", "user": "lupantech", "type": "user"}, "name": "Pan Lu", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T09:58:40.924Z", "hidden": false}, {"_id": "6927c504243b2216fb75cd68", "name": "Ke Shen", "hidden": false}, {"_id": "6927c504243b2216fb75cd69", "name": "Hanghang Tong", "hidden": false}, {"_id": "6927c504243b2216fb75cd6a", "name": "Yejin Choi", "hidden": false}, {"_id": "6927c504243b2216fb75cd6b", "name": "Jingrui He", "hidden": false}, {"_id": "6927c504243b2216fb75cd6c", "name": "James Zou", "hidden": false}, {"_id": "6927c504243b2216fb75cd6d", "name": "Mengdi Wang", "hidden": false}, {"_id": "6927c504243b2216fb75cd6e", "name": "Ling Yang", "hidden": false}], "publishedAt": "2025-11-25T18:56:57.000Z", "submittedOnDailyAt": "2025-11-27T01:00:26.981Z", "title": "Latent Collaboration in Multi-Agent Systems", "submittedOnDailyBy": {"_id": "65c288280aa2d53135734a42", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65c288280aa2d53135734a42/5WHmau52EaRS01TOMI3Qg.jpeg", "isPro": false, "fullname": "Jiaru Zou", "user": "jiaruz2", "type": "user"}, "summary": "Multi-agent systems (MAS) extend large language models (LLMs) from independent single-model reasoning to coordinative system-level intelligence. While existing LLM agents depend on text-based mediation for reasoning and communication, we take a step forward by enabling models to collaborate directly within the continuous latent space. We introduce LatentMAS, an end-to-end training-free framework that enables pure latent collaboration among LLM agents. In LatentMAS, each agent first performs auto-regressive latent thoughts generation through last-layer hidden embeddings. A shared latent working memory then preserves and transfers each agent's internal representations, ensuring lossless information exchange. We provide theoretical analyses establishing that LatentMAS attains higher expressiveness and lossless information preservation with substantially lower complexity than vanilla text-based MAS. In addition, empirical evaluations across 9 comprehensive benchmarks spanning math and science reasoning, commonsense understanding, and code generation show that LatentMAS consistently outperforms strong single-model and text-based MAS baselines, achieving up to 14.6% higher accuracy, reducing output token usage by 70.8%-83.7%, and providing 4x-4.3x faster end-to-end inference. These results demonstrate that our new latent collaboration framework enhances system-level reasoning quality while offering substantial efficiency gains without any additional training. Code and data are fully open-sourced at https://github.com/Gen-Verse/LatentMAS.", "upvotes": 64, "discussionId": "6927c504243b2216fb75cd6f", "githubRepo": "https://github.com/Gen-Verse/LatentMAS", "ai_summary": "LatentMAS enables efficient and effective collaboration among LLM agents using latent space representations, enhancing reasoning quality and reducing computational costs.", "ai_keywords": ["multi-agent systems", "large language models", "latent space", "LatentMAS", "auto-regressive latent thoughts generation", "last-layer hidden embeddings", "shared latent working memory", "expressiveness", "information preservation", "complexity", "math and science reasoning", "commonsense understanding", "code generation", "accuracy", "output token usage", "end-to-end inference"], "githubStars": 115, "organization": {"_id": "67a21d7efeeacb7707bf40de", "name": "Gen-Verse", "fullname": "Princeton-AI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64fde4e252e82dd432b74ce9/TAEScS71YX5NPRM4TXZc8.png"}, "summary_zh": "<ul>\n    <li>\u591a\u667a\u80fd\u4f53\u7cfb\u7edf\uff08MAS\uff09\u901a\u8fc7\u76f4\u63a5\u5728\u6f5c\u5728\u7a7a\u95f4\u4e2d\u534f\u4f5c\uff0c\u8d85\u8d8a\u4e86\u4f20\u7edf\u7684\u6587\u672c\u57fa\u7840\u63a8\u7406\u548c\u4ea4\u6d41\u3002</li>\n    <li>LatentMAS\u662f\u4e00\u79cd\u65e0\u9700\u8bad\u7ec3\u7684\u6846\u67b6\uff0c\u652f\u6301LLM\u667a\u80fd\u4f53\u4e4b\u95f4\u7684\u7eaf\u6f5c\u5728\u534f\u4f5c\u3002</li>\n    <li>\u6bcf\u4e2a\u667a\u80fd\u4f53\u901a\u8fc7\u6700\u540e\u4e00\u5c42\u7684\u9690\u85cf\u5d4c\u5165\u751f\u6210\u6f5c\u5728\u601d\u7ef4\uff0c\u5e76\u901a\u8fc7\u5171\u4eab\u7684\u6f5c\u5728\u5de5\u4f5c\u8bb0\u5fc6\u8fdb\u884c\u4fe1\u606f\u4ea4\u6362\u3002</li>\n    <li>\u7406\u8bba\u5206\u6790\u8868\u660e\uff0cLatentMAS\u5728\u4fe1\u606f\u8868\u8fbe\u548c\u4fdd\u7559\u65b9\u9762\u7684\u590d\u6742\u6027\u66f4\u4f4e\uff0c\u4e14\u8868\u73b0\u66f4\u4f18\u3002</li>\n    <li>\u57289\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cLatentMAS\u5728\u51c6\u786e\u6027\u4e0a\u63d0\u9ad8\u4e8614.6%\uff0c\u51cf\u5c11\u4e86\u8f93\u51fa\u4ee4\u724c\u4f7f\u7528\u91cf\uff0c\u5e76\u52a0\u5feb\u4e86\u63a8\u7406\u901f\u5ea6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multi-agent systems (MAS) improve collaboration among large language models (LLMs) beyond just single-model thinking.</li>\n    <li>LatentMAS allows LLM agents to work together directly in a shared space without relying on text communication.</li>\n    <li>It uses a shared memory to exchange information seamlessly while maintaining the quality of data.</li>\n    <li>LatentMAS shows better performance in various tasks, with up to 14.6% higher accuracy and significantly faster processing times.</li>\n    <li>The framework is open-source and does not require additional training to operate effectively.</li>\n</ul>"}, "publishedAt": "2025-11-25T13:56:57.000Z", "title": "Latent Collaboration in Multi-Agent Systems", "summary": "Multi-agent systems (MAS) extend large language models (LLMs) from independent single-model reasoning to coordinative system-level intelligence. While existing LLM agents depend on text-based mediation for reasoning and communication, we take a step forward by enabling models to collaborate directly within the continuous latent space. We introduce LatentMAS, an end-to-end training-free framework that enables pure latent collaboration among LLM agents. In LatentMAS, each agent first performs auto-regressive latent thoughts generation through last-layer hidden embeddings. A shared latent working memory then preserves and transfers each agent's internal representations, ensuring lossless information exchange. We provide theoretical analyses establishing that LatentMAS attains higher expressiveness and lossless information preservation with substantially lower complexity than vanilla text-based MAS. In addition, empirical evaluations across 9 comprehensive benchmarks spanning math and science reasoning, commonsense understanding, and code generation show that LatentMAS consistently outperforms strong single-model and text-based MAS baselines, achieving up to 14.6% higher accuracy, reducing output token usage by 70.8%-83.7%, and providing 4x-4.3x faster end-to-end inference. These results demonstrate that our new latent collaboration framework enhances system-level reasoning quality while offering substantial efficiency gains without any additional training. Code and data are fully open-sourced at https://github.com/Gen-Verse/LatentMAS.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20639.png", "numComments": 5, "submittedBy": {"_id": "65c288280aa2d53135734a42", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65c288280aa2d53135734a42/5WHmau52EaRS01TOMI3Qg.jpeg", "fullname": "Jiaru Zou", "name": "jiaruz2", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9}, "organization": {"_id": "67a21d7efeeacb7707bf40de", "name": "Gen-Verse", "fullname": "Princeton-AI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64fde4e252e82dd432b74ce9/TAEScS71YX5NPRM4TXZc8.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.19900", "authors": [{"_id": "6926877a243b2216fb75caca", "user": {"_id": "684ff37fa383bc5d6b0ff77f", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/0JPr-cd_rxQz3k6rmzBOF.png", "isPro": false, "fullname": "JiaqiLiu", "user": "JiaaqiLiu", "type": "user"}, "name": "Jiaqi Liu", "status": "claimed_verified", "statusLastChangedAt": "2025-11-26T09:27:22.964Z", "hidden": false}, {"_id": "6926877a243b2216fb75cacb", "name": "Kaiwen Xiong", "hidden": false}, {"_id": "6926877a243b2216fb75cacc", "user": {"_id": "643e9ee6f6bb3c31a26e7bc4", "avatarUrl": "/avatars/acfaa7d6a23dada24c86b954c3be116a.svg", "isPro": false, "fullname": "Peng Xia", "user": "richardxp888", "type": "user"}, "name": "Peng Xia", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T09:59:53.380Z", "hidden": false}, {"_id": "6926877a243b2216fb75cacd", "name": "Yiyang Zhou", "hidden": false}, {"_id": "6926877a243b2216fb75cace", "name": "Haonian Ji", "hidden": false}, {"_id": "6926877a243b2216fb75cacf", "name": "Lu Feng", "hidden": false}, {"_id": "6926877a243b2216fb75cad0", "name": "Siwei Han", "hidden": false}, {"_id": "6926877a243b2216fb75cad1", "name": "Mingyu Ding", "hidden": false}, {"_id": "6926877a243b2216fb75cad2", "name": "Huaxiu Yao", "hidden": false}], "publishedAt": "2025-11-25T04:15:14.000Z", "submittedOnDailyAt": "2025-11-26T02:25:56.245Z", "title": "Agent0-VL: Exploring Self-Evolving Agent for Tool-Integrated Vision-Language Reasoning", "submittedOnDailyBy": {"_id": "684ff37fa383bc5d6b0ff77f", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/0JPr-cd_rxQz3k6rmzBOF.png", "isPro": false, "fullname": "JiaqiLiu", "user": "JiaaqiLiu", "type": "user"}, "summary": "Vision-language agents have achieved remarkable progress in a variety of multimodal reasoning tasks; however, their learning remains constrained by the limitations of human-annotated supervision. Recent self-rewarding approaches attempt to overcome this constraint by allowing models to act as their own critics or reward providers. Yet, purely text-based self-evaluation struggles to verify complex visual reasoning steps and often suffers from evaluation hallucinations. To address these challenges, inspired by recent advances in tool-integrated reasoning, we propose Agent0-VL, a self-evolving vision-language agent that achieves continual improvement with tool-integrated reasoning. Agent0-VL incorporates tool usage not only into reasoning but also into self-evaluation and self-repair, enabling the model to introspect, verify, and refine its reasoning through evidence-grounded analysis. It unifies two synergistic roles within a single LVLM: a Solver that performs multi-turn tool-integrated reasoning, and a Verifier that generates structured feedback and fine-grained self-rewards through tool-grounded critique. These roles interact through a Self-Evolving Reasoning Cycle, where tool-based verification and reinforcement learning jointly align the reasoning and evaluation distributions for stable self-improvement. Through this zero-external-reward evolution, Agent0-VL aligns its reasoning and verification behaviors without any human annotation or external reward models, achieving continual self-improvement. Experiments on geometric problem solving and visual scientific analysis show that Agent0-VL achieves an 12.5% improvement over the base model. Our code is available at https://github.com/aiming-lab/Agent0/Agent0-VL{this https URL}.", "upvotes": 42, "discussionId": "6926877a243b2216fb75cad3", "projectPage": "https://github.com/aiming-lab/Agent0/tree/main/Agent0-VL", "githubRepo": "https://github.com/aiming-lab/Agent0/tree/main/Agent0-VL", "ai_summary": "Agent0-VL, a self-evolving vision-language agent, incorporates tool usage into both reasoning and self-evaluation, enabling continual improvement through evidence-grounded analysis and reinforcement learning.", "ai_keywords": ["self-rewarding approaches", "tool-integrated reasoning", "self-evaluation", "self-repair", "introspect", "evidence-grounded analysis", "Solver", "Verifier", "Self-Evolving Reasoning Cycle", "reinforcement learning", "geometric problem solving", "visual scientific analysis"], "githubStars": 544, "organization": {"_id": "669f9d1fec8789263c0e355a", "name": "UNC-ChapelHill", "fullname": "University of North Carolina at Chapel Hill", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/669f9c85bd649dba3b88e581/H5uB8_MCewnMtxEUnAvTL.png"}, "summary_zh": "<ul>\n    <li>\u89c6\u89c9\u8bed\u8a00\u4ee3\u7406\u5728\u591a\u6a21\u6001\u63a8\u7406\u4efb\u52a1\u4e0a\u53d6\u5f97\u4e86\u663e\u8457\u8fdb\u5c55\uff0c\u4f46\u4ecd\u53d7\u9650\u4e8e\u4eba\u5de5\u6807\u6ce8\u7684\u76d1\u7763\u3002</li>\n    <li>\u8fd1\u671f\u7684\u81ea\u6211\u5956\u52b1\u65b9\u6cd5\u8bd5\u56fe\u901a\u8fc7\u8ba9\u6a21\u578b\u81ea\u6211\u8bc4\u4ef7\u6765\u514b\u670d\u8fd9\u4e00\u9650\u5236\uff0c\u4f46\u7eaf\u6587\u672c\u8bc4\u4ef7\u96be\u4ee5\u9a8c\u8bc1\u590d\u6742\u89c6\u89c9\u63a8\u7406\u6b65\u9aa4\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86Agent0-VL\uff0c\u8fd9\u662f\u4e00\u79cd\u81ea\u6211\u8fdb\u5316\u7684\u89c6\u89c9\u8bed\u8a00\u4ee3\u7406\uff0c\u5229\u7528\u5de5\u5177\u96c6\u6210\u63a8\u7406\u5b9e\u73b0\u6301\u7eed\u6539\u8fdb\u3002</li>\n    <li>Agent0-VL\u7ed3\u5408\u4e86\u63a8\u7406\u3001\u81ea\u6211\u8bc4\u4ef7\u548c\u81ea\u6211\u4fee\u6b63\uff0c\u901a\u8fc7\u57fa\u4e8e\u8bc1\u636e\u7684\u5206\u6790\u6765\u63d0\u9ad8\u5176\u63a8\u7406\u80fd\u529b\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cAgent0-VL\u5728\u51e0\u4f55\u95ee\u9898\u89e3\u51b3\u548c\u89c6\u89c9\u79d1\u5b66\u5206\u6790\u4e2d\u6bd4\u57fa\u7840\u6a21\u578b\u63d0\u9ad8\u4e8612.5%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Vision-language agents have made great progress but still rely on human supervision.</li>\n    <li>Self-rewarding methods allow models to evaluate themselves, but they can struggle with complex visual tasks.</li>\n    <li>Agent0-VL is a new agent that improves itself by using tools for reasoning, evaluation, and correction.</li>\n    <li>It has two main roles: a Solver for reasoning and a Verifier for giving feedback and rewards.</li>\n    <li>Agent0-VL shows a 12.5% improvement in tasks without needing human help or external rewards.</li>\n</ul>"}, "publishedAt": "2025-11-24T23:15:14.000Z", "title": "Agent0-VL: Exploring Self-Evolving Agent for Tool-Integrated Vision-Language Reasoning", "summary": "Vision-language agents have achieved remarkable progress in a variety of multimodal reasoning tasks; however, their learning remains constrained by the limitations of human-annotated supervision. Recent self-rewarding approaches attempt to overcome this constraint by allowing models to act as their own critics or reward providers. Yet, purely text-based self-evaluation struggles to verify complex visual reasoning steps and often suffers from evaluation hallucinations. To address these challenges, inspired by recent advances in tool-integrated reasoning, we propose Agent0-VL, a self-evolving vision-language agent that achieves continual improvement with tool-integrated reasoning. Agent0-VL incorporates tool usage not only into reasoning but also into self-evaluation and self-repair, enabling the model to introspect, verify, and refine its reasoning through evidence-grounded analysis. It unifies two synergistic roles within a single LVLM: a Solver that performs multi-turn tool-integrated reasoning, and a Verifier that generates structured feedback and fine-grained self-rewards through tool-grounded critique. These roles interact through a Self-Evolving Reasoning Cycle, where tool-based verification and reinforcement learning jointly align the reasoning and evaluation distributions for stable self-improvement. Through this zero-external-reward evolution, Agent0-VL aligns its reasoning and verification behaviors without any human annotation or external reward models, achieving continual self-improvement. Experiments on geometric problem solving and visual scientific analysis show that Agent0-VL achieves an 12.5% improvement over the base model. Our code is available at https://github.com/aiming-lab/Agent0/Agent0-VL{this https URL}.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.19900.png", "numComments": 2, "submittedBy": {"_id": "684ff37fa383bc5d6b0ff77f", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/0JPr-cd_rxQz3k6rmzBOF.png", "fullname": "JiaqiLiu", "name": "JiaaqiLiu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2}, "organization": {"_id": "669f9d1fec8789263c0e355a", "name": "UNC-ChapelHill", "fullname": "University of North Carolina at Chapel Hill", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/669f9c85bd649dba3b88e581/H5uB8_MCewnMtxEUnAvTL.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.20714", "authors": [{"_id": "6927bc37243b2216fb75cd3c", "name": "Inferix Team", "hidden": false}, {"_id": "6927bc37243b2216fb75cd3d", "name": "Tianyu Feng", "hidden": false}, {"_id": "6927bc37243b2216fb75cd3e", "name": "Yizeng Han", "hidden": false}, {"_id": "6927bc37243b2216fb75cd3f", "name": "Jiahao He", "hidden": false}, {"_id": "6927bc37243b2216fb75cd40", "name": "Yuanyu He", "hidden": false}, {"_id": "6927bc37243b2216fb75cd41", "name": "Xi Lin", "hidden": false}, {"_id": "6927bc37243b2216fb75cd42", "name": "Teng Liu", "hidden": false}, {"_id": "6927bc37243b2216fb75cd43", "name": "Hanfeng Lu", "hidden": false}, {"_id": "6927bc37243b2216fb75cd44", "name": "Jiasheng Tang", "hidden": false}, {"_id": "6927bc37243b2216fb75cd45", "name": "Wei Wang", "hidden": false}, {"_id": "6927bc37243b2216fb75cd46", "name": "Zhiyuan Wang", "hidden": false}, {"_id": "6927bc37243b2216fb75cd47", "name": "Jichao Wu", "hidden": false}, {"_id": "6927bc37243b2216fb75cd48", "name": "Mingyang Yang", "hidden": false}, {"_id": "6927bc37243b2216fb75cd49", "name": "Yinghao Yu", "hidden": false}, {"_id": "6927bc37243b2216fb75cd4a", "user": {"_id": "64ec877bb93654d4ca5c92e9", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64ec877bb93654d4ca5c92e9/GvHk_KSdE9Rhnk_o-NaZX.jpeg", "isPro": false, "fullname": "Zeyu Zhang", "user": "SteveZeyuZhang", "type": "user"}, "name": "Zeyu Zhang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T09:59:06.036Z", "hidden": false}, {"_id": "6927bc37243b2216fb75cd4b", "name": "Bohan Zhuang", "hidden": false}], "publishedAt": "2025-11-25T01:45:04.000Z", "submittedOnDailyAt": "2025-11-27T00:19:36.886Z", "title": "Inferix: A Block-Diffusion based Next-Generation Inference Engine for World Simulation", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "World models serve as core simulators for fields such as agentic AI, embodied AI, and gaming, capable of generating long, physically realistic, and interactive high-quality videos. Moreover, scaling these models could unlock emergent capabilities in visual perception, understanding, and reasoning, paving the way for a new paradigm that moves beyond current LLM-centric vision foundation models. A key breakthrough empowering them is the semi-autoregressive (block-diffusion) decoding paradigm, which merges the strengths of diffusion and autoregressive methods by generating video tokens in block-applying diffusion within each block while conditioning on previous ones, resulting in more coherent and stable video sequences. Crucially, it overcomes limitations of standard video diffusion by reintroducing LLM-style KV Cache management, enabling efficient, variable-length, and high-quality generation.\n  Therefore, Inferix is specifically designed as a next-generation inference engine to enable immersive world synthesis through optimized semi-autoregressive decoding processes. This dedicated focus on world simulation distinctly sets it apart from systems engineered for high-concurrency scenarios (like vLLM or SGLang) and from classic video diffusion models (such as xDiTs). Inferix further enhances its offering with interactive video streaming and profiling, enabling real-time interaction and realistic simulation to accurately model world dynamics. Additionally, it supports efficient benchmarking through seamless integration of LV-Bench, a new fine-grained evaluation benchmark tailored for minute-long video generation scenarios. We hope the community will work together to advance Inferix and foster world model exploration.", "upvotes": 38, "discussionId": "6927bc38243b2216fb75cd4c", "githubRepo": "https://github.com/alibaba-damo-academy/Inferix", "ai_summary": "Inferix is a next-generation inference engine designed for immersive world synthesis using semi-autoregressive decoding, combining diffusion and autoregressive methods for high-quality, real-time video generation and interaction.", "ai_keywords": ["world models", "agentic AI", "embodied AI", "gaming", "visual perception", "understanding", "reasoning", "semi-autoregressive", "block-diffusion", "diffusion", "autoregressive methods", "video tokens", "KV Cache management", "Inferix", "vLLM", "SGLang", "xDiTs", "interactive video streaming", "profiling", "LV-Bench", "minute-long video generation"], "githubStars": 24, "summary_zh": "<ul>\n    <li>\u4e16\u754c\u6a21\u578b\u662f\u4ee3\u7406 AI\u3001\u5177\u8eab AI \u548c\u6e38\u620f\u7b49\u9886\u57df\u7684\u6838\u5fc3\u6a21\u62df\u5668\uff0c\u80fd\u591f\u751f\u6210\u957f\u800c\u771f\u5b9e\u4e92\u52a8\u7684\u9ad8\u8d28\u91cf\u89c6\u9891\u3002</li>\n    <li>\u6269\u5c55\u8fd9\u4e9b\u6a21\u578b\u53ef\u80fd\u4f1a\u89e3\u9501\u65b0\u7684\u89c6\u89c9\u611f\u77e5\u3001\u7406\u89e3\u548c\u63a8\u7406\u80fd\u529b\uff0c\u63a8\u52a8\u8d85\u8d8a\u5f53\u524d LLM \u89c6\u89d2\u7684\u57fa\u7840\u6a21\u578b\u7684\u65b0\u8303\u5f0f\u3002</li>\n    <li>\u534a\u81ea\u56de\u5f52\uff08\u5757\u6269\u6563\uff09\u89e3\u7801\u65b9\u6cd5\u662f\u5173\u952e\u7a81\u7834\uff0c\u5b83\u7ed3\u5408\u4e86\u6269\u6563\u548c\u81ea\u56de\u5f52\u65b9\u6cd5\u7684\u4f18\u70b9\uff0c\u751f\u6210\u66f4\u8fde\u8d2f\u548c\u7a33\u5b9a\u7684\u89c6\u9891\u5e8f\u5217\u3002</li>\n    <li>Inferix \u662f\u4e0b\u4e00\u4ee3\u63a8\u7406\u5f15\u64ce\uff0c\u4e13\u4e3a\u4f18\u5316\u534a\u81ea\u56de\u5f52\u89e3\u7801\u8fc7\u7a0b\u800c\u8bbe\u8ba1\uff0c\u80fd\u591f\u5b9e\u73b0\u6c89\u6d78\u5f0f\u7684\u4e16\u754c\u5408\u6210\u3002</li>\n    <li>\u5b83\u652f\u6301\u5b9e\u65f6\u4e92\u52a8\u548c\u73b0\u5b9e\u6a21\u62df\uff0c\u5e76\u901a\u8fc7 LV-Bench \u96c6\u6210\u9ad8\u6548\u7684\u57fa\u51c6\u6d4b\u8bd5\uff0c\u63a8\u52a8\u4e16\u754c\u6a21\u578b\u7684\u63a2\u7d22\u3002 </li>\n</ul>", "summary_simple": "<ul>\n    <li>World models can create realistic and interactive videos, useful in AI, gaming, and simulation.</li>\n    <li>Scaling these models can improve visual perception and reasoning, moving beyond current methods focused on language models.</li>\n    <li>The new semi-autoregressive decoding combines diffusion and autoregressive techniques to create better video sequences.</li>\n    <li>Inferix is a new engine designed for efficient world simulation using this advanced decoding method.</li>\n    <li>It offers real-time video streaming and integrates a new evaluation benchmark for testing video generation quality.</li>\n</ul>"}, "publishedAt": "2025-11-24T20:45:04.000Z", "title": "Inferix: A Block-Diffusion based Next-Generation Inference Engine for World Simulation", "summary": "World models serve as core simulators for fields such as agentic AI, embodied AI, and gaming, capable of generating long, physically realistic, and interactive high-quality videos. Moreover, scaling these models could unlock emergent capabilities in visual perception, understanding, and reasoning, paving the way for a new paradigm that moves beyond current LLM-centric vision foundation models. A key breakthrough empowering them is the semi-autoregressive (block-diffusion) decoding paradigm, which merges the strengths of diffusion and autoregressive methods by generating video tokens in block-applying diffusion within each block while conditioning on previous ones, resulting in more coherent and stable video sequences. Crucially, it overcomes limitations of standard video diffusion by reintroducing LLM-style KV Cache management, enabling efficient, variable-length, and high-quality generation.\n  Therefore, Inferix is specifically designed as a next-generation inference engine to enable immersive world synthesis through optimized semi-autoregressive decoding processes. This dedicated focus on world simulation distinctly sets it apart from systems engineered for high-concurrency scenarios (like vLLM or SGLang) and from classic video diffusion models (such as xDiTs). Inferix further enhances its offering with interactive video streaming and profiling, enabling real-time interaction and realistic simulation to accurately model world dynamics. Additionally, it supports efficient benchmarking through seamless integration of LV-Bench, a new fine-grained evaluation benchmark tailored for minute-long video generation scenarios. We hope the community will work together to advance Inferix and foster world model exploration.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20714.png", "numComments": 2, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 171}, "isAuthorParticipating": false}, {"paper": {"id": "2511.21541", "authors": [{"_id": "69294e361f3fae537858b58c", "user": {"_id": "66f6627e08be8ab9ab0833f2", "avatarUrl": "/avatars/871a0862c22e0e4f8829144953f81d85.svg", "isPro": false, "fullname": "mi", "user": "mxy123", "type": "user"}, "name": "Xiaoyue Mi", "status": "claimed_verified", "statusLastChangedAt": "2025-11-28T13:48:39.358Z", "hidden": false}, {"_id": "69294e361f3fae537858b58d", "name": "Wenqing Yu", "hidden": false}, {"_id": "69294e361f3fae537858b58e", "name": "Jiesong Lian", "hidden": false}, {"_id": "69294e361f3fae537858b58f", "name": "Shibo Jie", "hidden": false}, {"_id": "69294e361f3fae537858b590", "name": "Ruizhe Zhong", "hidden": false}, {"_id": "69294e361f3fae537858b591", "user": {"_id": "6468c76bff18750165a64df3", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6468c76bff18750165a64df3/dHhE62SHOSJZjyU60vgh7.jpeg", "isPro": true, "fullname": "Zijun Liu", "user": "BBQGOD", "type": "user"}, "name": "Zijun Liu", "status": "claimed_verified", "statusLastChangedAt": "2025-11-28T13:48:41.129Z", "hidden": false}, {"_id": "69294e361f3fae537858b592", "user": {"_id": "6684152a443492c24cdac044", "avatarUrl": "/avatars/1d5abbde12a808aa743769603e494ddb.svg", "isPro": false, "fullname": "Guozhen Zhang", "user": "zgzaacm", "type": "user"}, "name": "Guozhen Zhang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-28T13:48:43.019Z", "hidden": false}, {"_id": "69294e361f3fae537858b593", "name": "Zixiang Zhou", "hidden": false}, {"_id": "69294e361f3fae537858b594", "name": "Zhiyong Xu", "hidden": false}, {"_id": "69294e361f3fae537858b595", "name": "Yuan Zhou", "hidden": false}, {"_id": "69294e361f3fae537858b596", "name": "Qinglin Lu", "hidden": false}, {"_id": "69294e361f3fae537858b597", "name": "Fan Tang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6684152a443492c24cdac044/YJExuDfzC5B_ujgy-bCBS.png"], "publishedAt": "2025-11-26T16:14:18.000Z", "submittedOnDailyAt": "2025-11-28T05:01:44.583Z", "title": "Video Generation Models Are Good Latent Reward Models", "submittedOnDailyBy": {"_id": "6684152a443492c24cdac044", "avatarUrl": "/avatars/1d5abbde12a808aa743769603e494ddb.svg", "isPro": false, "fullname": "Guozhen Zhang", "user": "zgzaacm", "type": "user"}, "summary": "Reward feedback learning (ReFL) has proven effective for aligning image generation with human preferences. However, its extension to video generation faces significant challenges. Existing video reward models rely on vision-language models designed for pixel-space inputs, confining ReFL optimization to near-complete denoising steps after computationally expensive VAE decoding. This pixel-space approach incurs substantial memory overhead and increased training time, and its late-stage optimization lacks early-stage supervision, refining only visual quality rather than fundamental motion dynamics and structural coherence. In this work, we show that pre-trained video generation models are naturally suited for reward modeling in the noisy latent space, as they are explicitly designed to process noisy latent representations at arbitrary timesteps and inherently preserve temporal information through their sequential modeling capabilities. Accordingly, we propose Process Reward Feedback Learning~(PRFL), a framework that conducts preference optimization entirely in latent space, enabling efficient gradient backpropagation throughout the full denoising chain without VAE decoding. Extensive experiments demonstrate that PRFL significantly improves alignment with human preferences, while achieving substantial reductions in memory consumption and training time compared to RGB ReFL.", "upvotes": 37, "discussionId": "69294e361f3fae537858b598", "projectPage": "https://kululumi.github.io/PRFL/#", "ai_summary": "PRFL optimizes video generation preferences in latent space, improving alignment with human preferences while reducing memory consumption and training time.", "ai_keywords": ["reward feedback learning", "ReFL", "video generation", "vision-language models", "pixel space", "VAE decoding", "latent space", "noisy latent representations", "sequential modeling", "gradient backpropagation", "PRFL"], "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "summary_zh": "<ul>\n    <li>\u5956\u52b1\u53cd\u9988\u5b66\u4e60\uff08ReFL\uff09\u5728\u56fe\u50cf\u751f\u6210\u4e2d\u6709\u6548\uff0c\u4f46\u5728\u89c6\u9891\u751f\u6210\u4e2d\u9762\u4e34\u6311\u6218\u3002</li>\n    <li>\u73b0\u6709\u7684\u89c6\u9891\u5956\u52b1\u6a21\u578b\u4f9d\u8d56\u4e8e\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\uff0c\u5bfc\u81f4\u8bad\u7ec3\u65f6\u95f4\u957f\u4e14\u5185\u5b58\u5360\u7528\u5927\u3002</li>\n    <li>\u73b0\u6709\u65b9\u6cd5\u5728\u4f18\u5316\u7684\u665a\u671f\u7f3a\u4e4f\u65e9\u671f\u76d1\u7763\uff0c\u53ea\u5173\u6ce8\u89c6\u89c9\u8d28\u91cf\uff0c\u5ffd\u89c6\u8fd0\u52a8\u52a8\u6001\u548c\u7ed3\u6784\u4e00\u81f4\u6027\u3002</li>\n    <li>\u672c\u7814\u7a76\u63d0\u51fa\u4e86\u8fc7\u7a0b\u5956\u52b1\u53cd\u9988\u5b66\u4e60\uff08PRFL\uff09\uff0c\u5728\u6f5c\u5728\u7a7a\u95f4\u4e2d\u8fdb\u884c\u4f18\u5316\uff0c\u63d0\u5347\u6548\u7387\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cPRFL\u663e\u8457\u63d0\u9ad8\u4e86\u4e0e\u4eba\u7c7b\u504f\u597d\u7684\u5bf9\u9f50\uff0c\u540c\u65f6\u51cf\u5c11\u4e86\u5185\u5b58\u6d88\u8017\u548c\u8bad\u7ec3\u65f6\u95f4\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Reward feedback learning (ReFL) helps improve image generation to match human preferences, but it's challenging to apply to video generation.</li>\n    <li>Current video reward models use pixel-space inputs, which leads to high memory use, longer training times, and limited optimization for motion dynamics.</li>\n    <li>This study introduces Process Reward Feedback Learning (PRFL), which optimizes preferences in latent space instead of pixel space.</li>\n    <li>PRFL allows for efficient training using pre-trained video models that handle noisy data and maintain temporal information.</li>\n    <li>Experiments show PRFL greatly enhances alignment with human preferences and reduces memory and training time compared to traditional methods.</li>\n</ul>"}, "publishedAt": "2025-11-26T11:14:18.000Z", "title": "Video Generation Models Are Good Latent Reward Models", "summary": "Reward feedback learning (ReFL) has proven effective for aligning image generation with human preferences. However, its extension to video generation faces significant challenges. Existing video reward models rely on vision-language models designed for pixel-space inputs, confining ReFL optimization to near-complete denoising steps after computationally expensive VAE decoding. This pixel-space approach incurs substantial memory overhead and increased training time, and its late-stage optimization lacks early-stage supervision, refining only visual quality rather than fundamental motion dynamics and structural coherence. In this work, we show that pre-trained video generation models are naturally suited for reward modeling in the noisy latent space, as they are explicitly designed to process noisy latent representations at arbitrary timesteps and inherently preserve temporal information through their sequential modeling capabilities. Accordingly, we propose Process Reward Feedback Learning~(PRFL), a framework that conducts preference optimization entirely in latent space, enabling efficient gradient backpropagation throughout the full denoising chain without VAE decoding. Extensive experiments demonstrate that PRFL significantly improves alignment with human preferences, while achieving substantial reductions in memory consumption and training time compared to RGB ReFL.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6684152a443492c24cdac044/YJExuDfzC5B_ujgy-bCBS.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.21541.png", "numComments": 4, "submittedBy": {"_id": "6684152a443492c24cdac044", "avatarUrl": "/avatars/1d5abbde12a808aa743769603e494ddb.svg", "fullname": "Guozhen Zhang", "name": "zgzaacm", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2}, "organization": {"_id": "6645f953c39288df638dbdd5", "name": "Tencent-Hunyuan", "fullname": "Tencent Hunyuan", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/62d22496c58f969c152bcefd/woKSjt2wXvBNKussyYPsa.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.20635", "authors": [{"_id": "69266dec243b2216fb75ca56", "name": "Zhoujie Fu", "hidden": false}, {"_id": "69266dec243b2216fb75ca57", "name": "Xianfang Zeng", "hidden": false}, {"_id": "69266dec243b2216fb75ca58", "name": "Jinghong Lan", "hidden": false}, {"_id": "69266dec243b2216fb75ca59", "name": "Xinyao Liao", "hidden": false}, {"_id": "69266dec243b2216fb75ca5a", "name": "Cheng Chen", "hidden": false}, {"_id": "69266dec243b2216fb75ca5b", "name": "Junyi Chen", "hidden": false}, {"_id": "69266dec243b2216fb75ca5c", "name": "Jiacheng Wei", "hidden": false}, {"_id": "69266dec243b2216fb75ca5d", "user": {"_id": "64b914c8ace99c0723ad83a9", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64b914c8ace99c0723ad83a9/B4gxNByeVY_xaOcjwiN1j.jpeg", "isPro": false, "fullname": "Wei Cheng", "user": "wchengad", "type": "user"}, "name": "Wei Cheng", "status": "claimed_verified", "statusLastChangedAt": "2025-11-26T09:27:36.745Z", "hidden": false}, {"_id": "69266dec243b2216fb75ca5e", "name": "Shiyu Liu", "hidden": false}, {"_id": "69266dec243b2216fb75ca5f", "name": "Yunuo Chen", "hidden": false}, {"_id": "69266dec243b2216fb75ca60", "name": "Gang Yu", "hidden": false}, {"_id": "69266dec243b2216fb75ca61", "name": "Guosheng Lin", "hidden": false}], "publishedAt": "2025-11-25T18:54:16.000Z", "submittedOnDailyAt": "2025-11-26T00:33:21.436Z", "title": "iMontage: Unified, Versatile, Highly Dynamic Many-to-many Image Generation", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "Pre-trained video models learn powerful priors for generating high-quality, temporally coherent content. While these models excel at temporal coherence, their dynamics are often constrained by the continuous nature of their training data. We hypothesize that by injecting the rich and unconstrained content diversity from image data into this coherent temporal framework, we can generate image sets that feature both natural transitions and a far more expansive dynamic range. To this end, we introduce iMontage, a unified framework designed to repurpose a powerful video model into an all-in-one image generator. The framework consumes and produces variable-length image sets, unifying a wide array of image generation and editing tasks. To achieve this, we propose an elegant and minimally invasive adaptation strategy, complemented by a tailored data curation process and training paradigm. This approach allows the model to acquire broad image manipulation capabilities without corrupting its invaluable original motion priors. iMontage excels across several mainstream many-in-many-out tasks, not only maintaining strong cross-image contextual consistency but also generating scenes with extraordinary dynamics that surpass conventional scopes. Find our homepage at: https://kr1sjfu.github.io/iMontage-web/.", "upvotes": 29, "discussionId": "69266dec243b2216fb75ca62", "projectPage": "https://kr1sjfu.github.io/iMontage-web/", "githubRepo": "https://github.com/Kr1sJFU/iMontage", "ai_summary": "iMontage repurposes pre-trained video models to generate high-quality, diverse image sets with natural transitions and enhanced dynamics through a unified framework and tailored adaptation strategy.", "ai_keywords": ["pre-trained video models", "temporal coherence", "continuous nature", "image data", "content diversity", "iMontage", "unified framework", "image generator", "variable-length image sets", "image generation", "image editing", "adaptation strategy", "data curation", "training paradigm", "image manipulation", "motion priors", "cross-image contextual consistency"], "githubStars": 53, "organization": {"_id": "66e43eae9d477f566f937935", "name": "stepfun-ai", "fullname": "StepFun", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/66935cee39002fc0569c2943/Qv8QPbkgoKE3wR4jTzHiy.png"}, "summary_zh": "<ul>\n    <li>iMontage\u662f\u4e00\u4e2a\u65b0\u6846\u67b6\uff0c\u5c06\u5f3a\u5927\u7684\u89c6\u9891\u6a21\u578b\u8f6c\u5316\u4e3a\u56fe\u50cf\u751f\u6210\u5668\u3002</li>\n    <li>\u8be5\u6846\u67b6\u53ef\u4ee5\u751f\u6210\u591a\u79cd\u957f\u5ea6\u7684\u56fe\u50cf\u96c6\uff0c\u9002\u7528\u4e8e\u591a\u79cd\u56fe\u50cf\u751f\u6210\u548c\u7f16\u8f91\u4efb\u52a1\u3002</li>\n    <li>\u901a\u8fc7\u6ce8\u5165\u56fe\u50cf\u6570\u636e\u7684\u591a\u6837\u6027\uff0ciMontage\u63d0\u5347\u4e86\u751f\u6210\u56fe\u50cf\u7684\u81ea\u7136\u8fc7\u6e21\u548c\u52a8\u6001\u8303\u56f4\u3002</li>\n    <li>\u8be5\u6a21\u578b\u4fdd\u6301\u4e86\u826f\u597d\u7684\u56fe\u50cf\u95f4\u4e00\u81f4\u6027\uff0c\u5e76\u80fd\u751f\u6210\u8d85\u51fa\u5e38\u89c4\u8303\u56f4\u7684\u52a8\u6001\u573a\u666f\u3002</li>\n    <li>\u8be5\u6280\u672f\u7684\u9002\u5e94\u7b56\u7565\u548c\u6570\u636e\u5904\u7406\u8fc7\u7a0b\u975e\u5e38\u4f18\u96c5\uff0c\u786e\u4fdd\u4e86\u6a21\u578b\u7684\u539f\u59cb\u8fd0\u52a8\u4f18\u5148\u7ea7\u4e0d\u88ab\u7834\u574f\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>iMontage is a new framework that transforms a powerful video model into a versatile image generator.</li>\n    <li>It combines the strength of video models with diverse image data to create high-quality image sets with smooth transitions.</li>\n    <li>The framework can handle various image generation and editing tasks while maintaining the model's original motion quality.</li>\n    <li>iMontage is designed to work well with many different tasks, producing images with great detail and dynamic range.</li>\n    <li>The approach includes a careful training process and data selection to enhance image manipulation abilities.</li>\n</ul>"}, "publishedAt": "2025-11-25T13:54:16.000Z", "title": "iMontage: Unified, Versatile, Highly Dynamic Many-to-many Image Generation", "summary": "Pre-trained video models learn powerful priors for generating high-quality, temporally coherent content. While these models excel at temporal coherence, their dynamics are often constrained by the continuous nature of their training data. We hypothesize that by injecting the rich and unconstrained content diversity from image data into this coherent temporal framework, we can generate image sets that feature both natural transitions and a far more expansive dynamic range. To this end, we introduce iMontage, a unified framework designed to repurpose a powerful video model into an all-in-one image generator. The framework consumes and produces variable-length image sets, unifying a wide array of image generation and editing tasks. To achieve this, we propose an elegant and minimally invasive adaptation strategy, complemented by a tailored data curation process and training paradigm. This approach allows the model to acquire broad image manipulation capabilities without corrupting its invaluable original motion priors. iMontage excels across several mainstream many-in-many-out tasks, not only maintaining strong cross-image contextual consistency but also generating scenes with extraordinary dynamics that surpass conventional scopes. Find our homepage at: https://kr1sjfu.github.io/iMontage-web/.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20635.png", "numComments": 2, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 171}, "organization": {"_id": "66e43eae9d477f566f937935", "name": "stepfun-ai", "fullname": "StepFun", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/66935cee39002fc0569c2943/Qv8QPbkgoKE3wR4jTzHiy.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2511.20561", "authors": [{"_id": "692671a3243b2216fb75ca91", "name": "Yuwei Niu", "hidden": false}, {"_id": "692671a3243b2216fb75ca92", "user": {"_id": "66608add236f958513d21d2e", "avatarUrl": "/avatars/53eca0891c98cbb93be899885160a983.svg", "isPro": false, "fullname": "Weiyang Jin", "user": "Wayne-King", "type": "user"}, "name": "Weiyang Jin", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T09:59:57.589Z", "hidden": false}, {"_id": "692671a3243b2216fb75ca93", "name": "Jiaqi Liao", "hidden": false}, {"_id": "692671a3243b2216fb75ca94", "name": "Chaoran Feng", "hidden": false}, {"_id": "692671a3243b2216fb75ca95", "name": "Peng Jin", "hidden": false}, {"_id": "692671a3243b2216fb75ca96", "name": "Bin Lin", "hidden": false}, {"_id": "692671a3243b2216fb75ca97", "name": "Zongjian Li", "hidden": false}, {"_id": "692671a3243b2216fb75ca98", "name": "Bin Zhu", "hidden": false}, {"_id": "692671a3243b2216fb75ca99", "name": "Weihao Yu", "hidden": false}, {"_id": "692671a3243b2216fb75ca9a", "name": "Li Yuan", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66608add236f958513d21d2e/LUJu9PnWzLTa49ONkbY5H.png"], "publishedAt": "2025-11-25T17:58:48.000Z", "submittedOnDailyAt": "2025-11-26T01:19:47.715Z", "title": "Does Understanding Inform Generation in Unified Multimodal Models? From Analysis to Path Forward", "submittedOnDailyBy": {"_id": "66608add236f958513d21d2e", "avatarUrl": "/avatars/53eca0891c98cbb93be899885160a983.svg", "isPro": false, "fullname": "Weiyang Jin", "user": "Wayne-King", "type": "user"}, "summary": "Recent years have witnessed significant progress in Unified Multimodal Models, yet a fundamental question remains: Does understanding truly inform generation? To investigate this, we introduce UniSandbox, a decoupled evaluation framework paired with controlled, synthetic datasets to avoid data leakage and enable detailed analysis. Our findings reveal a significant understanding-generation gap, which is mainly reflected in two key dimensions: reasoning generation and knowledge transfer. Specifically, for reasoning generation tasks, we observe that explicit Chain-of-Thought (CoT) in the understanding module effectively bridges the gap, and further demonstrate that a self-training approach can successfully internalize this ability, enabling implicit reasoning during generation. Additionally, for knowledge transfer tasks, we find that CoT assists the generative process by helping retrieve newly learned knowledge, and also discover that query-based architectures inherently exhibit latent CoT-like properties that affect this transfer. UniSandbox provides preliminary insights for designing future unified architectures and training strategies that truly bridge the gap between understanding and generation. Code and data are available at https://github.com/PKU-YuanGroup/UniSandBox", "upvotes": 28, "discussionId": "692671a3243b2216fb75ca9b", "githubRepo": "https://github.com/PKU-YuanGroup/UniSandBox", "ai_summary": "UniSandbox evaluates Unified Multimodal Models, revealing a gap between understanding and generation, and identifies Chain-of-Thought and self-training as means to bridge this gap.", "ai_keywords": ["Unified Multimodal Models", "UniSandbox", "decoupled evaluation framework", "synthetic datasets", "understanding-generation gap", "reasoning generation", "knowledge transfer", "Chain-of-Thought", "self-training", "query-based architectures"], "githubStars": 25, "organization": {"_id": "61dcd8e344f59573371b5cb6", "name": "PekingUniversity", "fullname": "Peking University", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/noauth/vavgrBsnkSejriUF4lXDE.png"}, "summary_zh": "<ul>\n    <li>\u6700\u8fd1\uff0c\u7edf\u4e00\u591a\u6a21\u6001\u6a21\u578b\u53d6\u5f97\u4e86\u663e\u8457\u8fdb\u5c55\uff0c\u4f46\u7406\u89e3\u4e0e\u751f\u6210\u4e4b\u95f4\u7684\u5173\u7cfb\u4ecd\u7136\u662f\u4e00\u4e2a\u91cd\u8981\u95ee\u9898\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86UniSandbox\uff0c\u4e00\u4e2a\u89e3\u8026\u7684\u8bc4\u4f30\u6846\u67b6\uff0c\u914d\u5408\u53d7\u63a7\u7684\u5408\u6210\u6570\u636e\u96c6\u8fdb\u884c\u8be6\u7ec6\u5206\u6790\u3002</li>\n    <li>\u7814\u7a76\u53d1\u73b0\u7406\u89e3\u4e0e\u751f\u6210\u4e4b\u95f4\u5b58\u5728\u663e\u8457\u5dee\u8ddd\uff0c\u4e3b\u8981\u4f53\u73b0\u5728\u63a8\u7406\u751f\u6210\u548c\u77e5\u8bc6\u8f6c\u79fb\u4e24\u4e2a\u65b9\u9762\u3002</li>\n    <li>\u63a8\u7406\u751f\u6210\u4efb\u52a1\u4e2d\uff0c\u94fe\u5f0f\u601d\u7ef4\uff08CoT\uff09\u5728\u7406\u89e3\u6a21\u5757\u4e2d\u80fd\u591f\u6709\u6548\u7f29\u5c0f\u8fd9\u4e00\u5dee\u8ddd\u3002</li>\n    <li>UniSandbox\u4e3a\u672a\u6765\u7edf\u4e00\u67b6\u6784\u548c\u8bad\u7ec3\u7b56\u7565\u7684\u8bbe\u8ba1\u63d0\u4f9b\u4e86\u521d\u6b65\u6d1e\u5bdf\uff0c\u65e8\u5728\u771f\u6b63\u5f25\u5408\u7406\u89e3\u4e0e\u751f\u6210\u4e4b\u95f4\u7684\u5dee\u8ddd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>New research introduces UniSandbox, a testing framework to study how understanding impacts generation in Unified Multimodal Models.</li>\n    <li>The study finds a significant gap between understanding and generating responses, particularly in reasoning tasks and knowledge transfer.</li>\n    <li>Using Chain-of-Thought (CoT) techniques helps improve reasoning tasks by making the understanding process clearer.</li>\n    <li>CoT also aids in knowledge transfer by retrieving newly learned information during generation.</li>\n    <li>UniSandbox offers insights for developing better models and training methods to connect understanding and generation more effectively.</li>\n</ul>"}, "publishedAt": "2025-11-25T12:58:48.000Z", "title": "Does Understanding Inform Generation in Unified Multimodal Models? From Analysis to Path Forward", "summary": "Recent years have witnessed significant progress in Unified Multimodal Models, yet a fundamental question remains: Does understanding truly inform generation? To investigate this, we introduce UniSandbox, a decoupled evaluation framework paired with controlled, synthetic datasets to avoid data leakage and enable detailed analysis. Our findings reveal a significant understanding-generation gap, which is mainly reflected in two key dimensions: reasoning generation and knowledge transfer. Specifically, for reasoning generation tasks, we observe that explicit Chain-of-Thought (CoT) in the understanding module effectively bridges the gap, and further demonstrate that a self-training approach can successfully internalize this ability, enabling implicit reasoning during generation. Additionally, for knowledge transfer tasks, we find that CoT assists the generative process by helping retrieve newly learned knowledge, and also discover that query-based architectures inherently exhibit latent CoT-like properties that affect this transfer. UniSandbox provides preliminary insights for designing future unified architectures and training strategies that truly bridge the gap between understanding and generation. Code and data are available at https://github.com/PKU-YuanGroup/UniSandBox", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66608add236f958513d21d2e/LUJu9PnWzLTa49ONkbY5H.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20561.png", "numComments": 2, "submittedBy": {"_id": "66608add236f958513d21d2e", "avatarUrl": "/avatars/53eca0891c98cbb93be899885160a983.svg", "fullname": "Weiyang Jin", "name": "Wayne-King", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4}, "organization": {"_id": "61dcd8e344f59573371b5cb6", "name": "PekingUniversity", "fullname": "Peking University", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/noauth/vavgrBsnkSejriUF4lXDE.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.20347", "authors": [{"_id": "69268ffb243b2216fb75cb0b", "name": "Chang Gao", "hidden": false}, {"_id": "69268ffb243b2216fb75cb0c", "name": "Chujie Zheng", "hidden": false}, {"_id": "69268ffb243b2216fb75cb0d", "name": "Xiong-Hui Chen", "hidden": false}, {"_id": "69268ffb243b2216fb75cb0e", "name": "Kai Dang", "hidden": false}, {"_id": "69268ffb243b2216fb75cb0f", "name": "Shixuan Liu", "hidden": false}, {"_id": "69268ffb243b2216fb75cb10", "name": "Bowen Yu", "hidden": false}, {"_id": "69268ffb243b2216fb75cb11", "user": {"_id": "62088594a5943c8a8fc94560", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/1644733028938-62088594a5943c8a8fc94560.png", "isPro": false, "fullname": "An Yang", "user": "yangapku", "type": "user"}, "name": "An Yang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-26T11:31:25.265Z", "hidden": false}, {"_id": "69268ffb243b2216fb75cb12", "name": "Shuai Bai", "hidden": false}, {"_id": "69268ffb243b2216fb75cb13", "name": "Jingren Zhou", "hidden": false}, {"_id": "69268ffb243b2216fb75cb14", "name": "Junyang Lin", "hidden": false}], "publishedAt": "2025-11-25T14:25:19.000Z", "submittedOnDailyAt": "2025-11-26T04:31:56.255Z", "title": "Soft Adaptive Policy Optimization", "submittedOnDailyBy": {"_id": "63451cf0a05b51f7ded25505", "avatarUrl": "/avatars/dec4bbee4a82b773fc58dfc2dce9dbeb.svg", "isPro": false, "fullname": "shuai bai", "user": "ShuaiBai623", "type": "user"}, "summary": "Reinforcement learning (RL) plays an increasingly important role in enhancing the reasoning capabilities of large language models (LLMs), yet stable and performant policy optimization remains challenging. Token-level importance ratios often exhibit high variance-a phenomenon exacerbated in Mixture-of-Experts models-leading to unstable updates. Existing group-based policy optimization methods, such as GSPO and GRPO, alleviate this problem via hard clipping, making it difficult to maintain both stability and effective learning. We propose Soft Adaptive Policy Optimization (SAPO), which replaces hard clipping with a smooth, temperature-controlled gate that adaptively attenuates off-policy updates while preserving useful learning signals. Compared with GSPO and GRPO, SAPO is both sequence-coherent and token-adaptive. Like GSPO, SAPO maintains sequence-level coherence, but its soft gating forms a continuous trust region that avoids the brittle hard clipping band used in GSPO. When a sequence contains a few highly off-policy tokens, GSPO suppresses all gradients for that sequence, whereas SAPO selectively down-weights only the offending tokens and preserves the learning signal from the near-on-policy ones, improving sample efficiency. Relative to GRPO, SAPO replaces hard token-level clipping with smooth, temperature-controlled scaling, enabling more informative and stable updates. Empirical results on mathematical reasoning benchmarks indicate that SAPO exhibits improved training stability and higher Pass@1 performance under comparable training budgets. Moreover, we employ SAPO to train the Qwen3-VL model series, demonstrating that SAPO yields consistent performance gains across diverse tasks and different model sizes. Overall, SAPO provides a more reliable, scalable, and effective optimization strategy for RL training of LLMs.", "upvotes": 26, "discussionId": "69268ffb243b2216fb75cb15", "ai_summary": "Soft Adaptive Policy Optimization (SAPO) enhances the stability and performance of reinforcement learning in large language models by adaptively attenuating off-policy updates with a smooth, temperature-controlled gate, leading to improved training stability and performance.", "ai_keywords": ["reinforcement learning", "large language models", "policy optimization", "token-level importance ratios", "Mixture-of-Experts models", "GSPO", "GRPO", "Soft Adaptive Policy Optimization", "sequence-coherent", "token-adaptive", "sequence-level coherence", "off-policy updates", "sample efficiency", "Pass@1 performance", "Qwen3-VL model series"], "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/620760a26e3b7210c2ff1943/-s1gyJfvbE1RgO5iBeNOi.png"}, "summary_zh": "<ul>\n    <li>\u5f3a\u5316\u5b66\u4e60\uff08RL\uff09\u5728\u63d0\u5347\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u7684\u63a8\u7406\u80fd\u529b\u4e2d\u8d8a\u6765\u8d8a\u91cd\u8981\uff0c\u4f46\u653f\u7b56\u4f18\u5316\u4ecd\u7136\u5177\u6709\u6311\u6218\u6027\u3002</li>\n    <li>\u73b0\u6709\u7684\u57fa\u4e8e\u7fa4\u4f53\u7684\u653f\u7b56\u4f18\u5316\u65b9\u6cd5\uff08\u5982GSPO\u548cGRPO\uff09\u4f7f\u7528\u786c\u526a\u5207\uff0c\u5bfc\u81f4\u5b66\u4e60\u7a33\u5b9a\u6027\u548c\u6709\u6548\u6027\u96be\u4ee5\u517c\u987e\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u8f6f\u81ea\u9002\u5e94\u653f\u7b56\u4f18\u5316\uff08SAPO\uff09\uff0c\u7528\u5e73\u6ed1\u7684\u6e29\u63a7\u95e8\u66ff\u4ee3\u786c\u526a\u5207\uff0c\u4fdd\u7559\u6709\u7528\u7684\u5b66\u4e60\u4fe1\u53f7\u3002</li>\n    <li>SAPO\u5728\u5e8f\u5217\u4e00\u81f4\u6027\u548c\u4ee4\u724c\u9002\u5e94\u6027\u65b9\u9762\u4f18\u4e8eGSPO\u548cGRPO\uff0c\u80fd\u591f\u66f4\u9ad8\u6548\u5730\u5904\u7406\u504f\u79bb\u653f\u7b56\u7684\u4ee4\u724c\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\uff0cSAPO\u5728\u6570\u5b66\u63a8\u7406\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u51fa\u66f4\u597d\u7684\u8bad\u7ec3\u7a33\u5b9a\u6027\u548c\u66f4\u9ad8\u7684\u6027\u80fd\uff0c\u9002\u7528\u4e8e\u4e0d\u540c\u4efb\u52a1\u548c\u6a21\u578b\u89c4\u6a21\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Reinforcement learning helps improve reasoning in large language models, but optimizing policies can be difficult due to high variance in importance ratios.</li>\n    <li>Current methods like GSPO and GRPO use hard clipping, which can hinder both stability and effective learning.</li>\n    <li>Soft Adaptive Policy Optimization (SAPO) replaces hard clipping with a smooth, adjustable gate that better manages updates without losing valuable learning signals.</li>\n    <li>SAPO is more flexible than existing methods by selectively down-weighting problematic tokens rather than suppressing all gradients, leading to better sample efficiency.</li>\n    <li>Tests show that SAPO improves training stability and performance in various tasks while being effective across different model sizes.</li>\n</ul>"}, "publishedAt": "2025-11-25T09:25:19.000Z", "title": "Soft Adaptive Policy Optimization", "summary": "Reinforcement learning (RL) plays an increasingly important role in enhancing the reasoning capabilities of large language models (LLMs), yet stable and performant policy optimization remains challenging. Token-level importance ratios often exhibit high variance-a phenomenon exacerbated in Mixture-of-Experts models-leading to unstable updates. Existing group-based policy optimization methods, such as GSPO and GRPO, alleviate this problem via hard clipping, making it difficult to maintain both stability and effective learning. We propose Soft Adaptive Policy Optimization (SAPO), which replaces hard clipping with a smooth, temperature-controlled gate that adaptively attenuates off-policy updates while preserving useful learning signals. Compared with GSPO and GRPO, SAPO is both sequence-coherent and token-adaptive. Like GSPO, SAPO maintains sequence-level coherence, but its soft gating forms a continuous trust region that avoids the brittle hard clipping band used in GSPO. When a sequence contains a few highly off-policy tokens, GSPO suppresses all gradients for that sequence, whereas SAPO selectively down-weights only the offending tokens and preserves the learning signal from the near-on-policy ones, improving sample efficiency. Relative to GRPO, SAPO replaces hard token-level clipping with smooth, temperature-controlled scaling, enabling more informative and stable updates. Empirical results on mathematical reasoning benchmarks indicate that SAPO exhibits improved training stability and higher Pass@1 performance under comparable training budgets. Moreover, we employ SAPO to train the Qwen3-VL model series, demonstrating that SAPO yields consistent performance gains across diverse tasks and different model sizes. Overall, SAPO provides a more reliable, scalable, and effective optimization strategy for RL training of LLMs.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20347.png", "numComments": 3, "submittedBy": {"_id": "63451cf0a05b51f7ded25505", "avatarUrl": "/avatars/dec4bbee4a82b773fc58dfc2dce9dbeb.svg", "fullname": "shuai bai", "name": "ShuaiBai623", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 39}, "organization": {"_id": "64c8b5837fe12ecd0a7e92eb", "name": "Qwen", "fullname": "Qwen", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/620760a26e3b7210c2ff1943/-s1gyJfvbE1RgO5iBeNOi.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2511.21691", "authors": [{"_id": "6927cfb1243b2216fb75cd97", "user": {"_id": "65454d7c117ecae648892170", "avatarUrl": "/avatars/83a7091a24bf86801176ca85234b417a.svg", "isPro": false, "fullname": "Yusuf Dalva", "user": "ydalva", "type": "user"}, "name": "Yusuf Dalva", "status": "claimed_verified", "statusLastChangedAt": "2025-11-30T20:10:27.019Z", "hidden": false}, {"_id": "6927cfb1243b2216fb75cd98", "name": "Guocheng Gordon Qian", "hidden": false}, {"_id": "6927cfb1243b2216fb75cd99", "name": "Maya Goldenberg", "hidden": false}, {"_id": "6927cfb1243b2216fb75cd9a", "name": "Tsai-Shien Chen", "hidden": false}, {"_id": "6927cfb1243b2216fb75cd9b", "name": "Kfir Aberman", "hidden": false}, {"_id": "6927cfb1243b2216fb75cd9c", "name": "Sergey Tulyakov", "hidden": false}, {"_id": "6927cfb1243b2216fb75cd9d", "name": "Pinar Yanardag", "hidden": false}, {"_id": "6927cfb1243b2216fb75cd9e", "name": "Kuan-Chieh Jackson Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65454d7c117ecae648892170/wYbC0015-eECU_RvLEOZD.mp4"], "publishedAt": "2025-11-26T18:59:56.000Z", "submittedOnDailyAt": "2025-11-28T03:38:16.212Z", "title": "Canvas-to-Image: Compositional Image Generation with Multimodal Controls", "submittedOnDailyBy": {"_id": "65454d7c117ecae648892170", "avatarUrl": "/avatars/83a7091a24bf86801176ca85234b417a.svg", "isPro": false, "fullname": "Yusuf Dalva", "user": "ydalva", "type": "user"}, "summary": "While modern diffusion models excel at generating high-quality and diverse images, they still struggle with high-fidelity compositional and multimodal control, particularly when users simultaneously specify text prompts, subject references, spatial arrangements, pose constraints, and layout annotations. We introduce Canvas-to-Image, a unified framework that consolidates these heterogeneous controls into a single canvas interface, enabling users to generate images that faithfully reflect their intent. Our key idea is to encode diverse control signals into a single composite canvas image that the model can directly interpret for integrated visual-spatial reasoning. We further curate a suite of multi-task datasets and propose a Multi-Task Canvas Training strategy that optimizes the diffusion model to jointly understand and integrate heterogeneous controls into text-to-image generation within a unified learning paradigm. This joint training enables Canvas-to-Image to reason across multiple control modalities rather than relying on task-specific heuristics, and it generalizes well to multi-control scenarios during inference. Extensive experiments show that Canvas-to-Image significantly outperforms state-of-the-art methods in identity preservation and control adherence across challenging benchmarks, including multi-person composition, pose-controlled composition, layout-constrained generation, and multi-control generation.", "upvotes": 26, "discussionId": "6927cfb2243b2216fb75cd9f", "projectPage": "https://snap-research.github.io/canvas-to-image/", "ai_summary": "Canvas-to-Image is a unified framework that encodes diverse control signals into a composite canvas image for high-fidelity multimodal image generation, outperforming existing methods in various benchmarks.", "ai_keywords": ["diffusion models", "high-fidelity compositional", "multimodal control", "text prompts", "subject references", "spatial arrangements", "pose constraints", "layout annotations", "unified framework", "composite canvas image", "visual-spatial reasoning", "multi-task datasets", "Multi-Task Canvas Training", "text-to-image generation", "identity preservation", "control adherence", "multi-person composition", "pose-controlled composition", "layout-constrained generation", "multi-control generation"], "summary_zh": "<ul>\n    <li>\u73b0\u4ee3\u6269\u6563\u6a21\u578b\u5728\u751f\u6210\u9ad8\u8d28\u91cf\u548c\u591a\u6837\u5316\u56fe\u50cf\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u5728\u5904\u7406\u590d\u6742\u7684\u7528\u6237\u63a7\u5236\u65f6\u4ecd\u7136\u5b58\u5728\u56f0\u96be\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u201c\u753b\u5e03\u5230\u56fe\u50cf\u201d\u6846\u67b6\uff0c\u5c06\u591a\u79cd\u63a7\u5236\u65b9\u5f0f\u6574\u5408\u5230\u4e00\u4e2a\u753b\u5e03\u754c\u9762\u4e2d\uff0c\u4f7f\u7528\u6237\u80fd\u591f\u751f\u6210\u66f4\u7b26\u5408\u610f\u56fe\u7684\u56fe\u50cf\u3002</li>\n    <li>\u8be5\u6846\u67b6\u901a\u8fc7\u7f16\u7801\u4e0d\u540c\u7684\u63a7\u5236\u4fe1\u53f7\u4e3a\u4e00\u4e2a\u590d\u5408\u753b\u5e03\u56fe\u50cf\uff0c\u4f7f\u6a21\u578b\u80fd\u591f\u8fdb\u884c\u7efc\u5408\u7684\u89c6\u89c9\u7a7a\u95f4\u63a8\u7406\u3002</li>\n    <li>\u6211\u4eec\u8fd8\u5236\u5b9a\u4e86\u591a\u4efb\u52a1\u6570\u636e\u96c6\u548c\u591a\u4efb\u52a1\u753b\u5e03\u8bad\u7ec3\u7b56\u7565\uff0c\u4f18\u5316\u6269\u6563\u6a21\u578b\u4ee5\u5171\u540c\u7406\u89e3\u548c\u6574\u5408\u4e0d\u540c\u7684\u63a7\u5236\u65b9\u5f0f\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u201c\u753b\u5e03\u5230\u56fe\u50cf\u201d\u5728\u8eab\u4efd\u4fdd\u6301\u548c\u63a7\u5236\u9075\u5faa\u65b9\u9762\u660e\u663e\u4f18\u4e8e\u73b0\u6709\u7684\u6700\u5148\u8fdb\u65b9\u6cd5\uff0c\u7279\u522b\u662f\u5728\u591a\u4eba\u7269\u6784\u56fe\u548c\u59ff\u52bf\u63a7\u5236\u751f\u6210\u7b49\u590d\u6742\u573a\u666f\u4e2d\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Modern diffusion models are good at creating quality images but have trouble with detailed controls when users want specific features.</li>\n    <li>Canvas-to-Image is a new system that allows users to combine different controls in one easy-to-use interface to create images that match their needs.</li>\n    <li>The system uses a single composite canvas image to help the model understand and generate visuals based on multiple different inputs.</li>\n    <li>Canvas-to-Image includes a special training method that helps it learn to handle various controls together instead of needing separate approaches for each task.</li>\n    <li>Tests show that Canvas-to-Image works better than other methods in keeping identities and following user instructions in complex scenarios.</li>\n</ul>"}, "publishedAt": "2025-11-26T13:59:56.000Z", "title": "Canvas-to-Image: Compositional Image Generation with Multimodal Controls", "summary": "While modern diffusion models excel at generating high-quality and diverse images, they still struggle with high-fidelity compositional and multimodal control, particularly when users simultaneously specify text prompts, subject references, spatial arrangements, pose constraints, and layout annotations. We introduce Canvas-to-Image, a unified framework that consolidates these heterogeneous controls into a single canvas interface, enabling users to generate images that faithfully reflect their intent. Our key idea is to encode diverse control signals into a single composite canvas image that the model can directly interpret for integrated visual-spatial reasoning. We further curate a suite of multi-task datasets and propose a Multi-Task Canvas Training strategy that optimizes the diffusion model to jointly understand and integrate heterogeneous controls into text-to-image generation within a unified learning paradigm. This joint training enables Canvas-to-Image to reason across multiple control modalities rather than relying on task-specific heuristics, and it generalizes well to multi-control scenarios during inference. Extensive experiments show that Canvas-to-Image significantly outperforms state-of-the-art methods in identity preservation and control adherence across challenging benchmarks, including multi-person composition, pose-controlled composition, layout-constrained generation, and multi-control generation.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65454d7c117ecae648892170/wYbC0015-eECU_RvLEOZD.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.21691.png", "numComments": 6, "submittedBy": {"_id": "65454d7c117ecae648892170", "avatarUrl": "/avatars/83a7091a24bf86801176ca85234b417a.svg", "fullname": "Yusuf Dalva", "name": "ydalva", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5}, "isAuthorParticipating": true}, {"paper": {"id": "2511.20256", "authors": [{"_id": "6926617a243b2216fb75c9f6", "name": "Weijia Mao", "hidden": false}, {"_id": "6926617a243b2216fb75c9f7", "name": "Hao Chen", "hidden": false}, {"_id": "6926617a243b2216fb75c9f8", "name": "Zhenheng Yang", "hidden": false}, {"_id": "6926617a243b2216fb75c9f9", "name": "Mike Zheng Shou", "hidden": false}], "publishedAt": "2025-11-25T12:35:57.000Z", "submittedOnDailyAt": "2025-11-25T23:57:53.540Z", "title": "The Image as Its Own Reward: Reinforcement Learning with Adversarial Reward for Image Generation", "submittedOnDailyBy": {"_id": "63f320ee0be81bdc5d8ecb88", "avatarUrl": "/avatars/9d08cff6ed23a51887c869947bc03228.svg", "isPro": true, "fullname": "Mao Weijia", "user": "benzweijia", "type": "user"}, "summary": "A reliable reward function is essential for reinforcement learning (RL) in image generation. Most current RL approaches depend on pre-trained preference models that output scalar rewards to approximate human preferences. However, these rewards often fail to capture human perception and are vulnerable to reward hacking, where higher scores do not correspond to better images. To address this, we introduce Adv-GRPO, an RL framework with an adversarial reward that iteratively updates both the reward model and the generator. The reward model is supervised using reference images as positive samples and can largely avoid being hacked. Unlike KL regularization that constrains parameter updates, our learned reward directly guides the generator through its visual outputs, leading to higher-quality images. Moreover, while optimizing existing reward functions can alleviate reward hacking, their inherent biases remain. For instance, PickScore may degrade image quality, whereas OCR-based rewards often reduce aesthetic fidelity. To address this, we take the image itself as a reward, using reference images and vision foundation models (e.g., DINO) to provide rich visual rewards. These dense visual signals, instead of a single scalar, lead to consistent gains across image quality, aesthetics, and task-specific metrics. Finally, we show that combining reference samples with foundation-model rewards enables distribution transfer and flexible style customization. In human evaluation, our method outperforms Flow-GRPO and SD3, achieving 70.0% and 72.4% win rates in image quality and aesthetics, respectively. Code and models have been released.", "upvotes": 25, "discussionId": "6926617a243b2216fb75c9fa", "ai_summary": "An adversarial reward learning framework in reinforcement learning for image generation improves image quality and aesthetics by using dense visual signals from vision foundation models.", "ai_keywords": ["reinforcement learning", "reward function", "preference models", "reward hacking", "Adv-GRPO", "adversarial reward", "reward model", "generator", "KL regularization", "PickScore", "OCR-based rewards", "image quality", "aesthetics", "task-specific metrics", "distribution transfer", "style customization", "vision foundation models", "DINO"], "summary_zh": "<ul>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u5f3a\u5316\u5b66\u4e60\u6846\u67b6Adv-GRPO\uff0c\u4f7f\u7528\u5bf9\u6297\u6027\u5956\u52b1\u6765\u63d0\u9ad8\u56fe\u50cf\u751f\u6210\u8d28\u91cf\u3002</li>\n    <li>\u8be5\u6846\u67b6\u901a\u8fc7\u53c2\u8003\u56fe\u50cf\u8bad\u7ec3\u5956\u52b1\u6a21\u578b\uff0c\u80fd\u591f\u6709\u6548\u907f\u514d\u5956\u52b1\u88ab\u64cd\u7eb5\u3002</li>\n    <li>\u4f7f\u7528\u56fe\u50cf\u672c\u8eab\u4f5c\u4e3a\u5956\u52b1\uff0c\u5229\u7528\u89c6\u89c9\u57fa\u7840\u6a21\u578b\u63d0\u4f9b\u4e30\u5bcc\u7684\u89c6\u89c9\u4fe1\u53f7\uff0c\u63d0\u5347\u56fe\u50cf\u8d28\u91cf\u548c\u7f8e\u5b66\u6548\u679c\u3002</li>\n    <li>\u7ed3\u5408\u53c2\u8003\u6837\u672c\u548c\u57fa\u7840\u6a21\u578b\u5956\u52b1\uff0c\u5b9e\u73b0\u4e86\u5206\u5e03\u8f6c\u79fb\u548c\u7075\u6d3b\u7684\u98ce\u683c\u5b9a\u5236\u3002</li>\n    <li>\u5728\u4eba\u5de5\u8bc4\u4f30\u4e2d\uff0cAdv-GRPO\u5728\u56fe\u50cf\u8d28\u91cf\u548c\u7f8e\u5b66\u4e0a\u8868\u73b0\u4f18\u4e8e\u5176\u4ed6\u65b9\u6cd5\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>A reliable reward function is crucial for reinforcement learning in generating images.</li>\n  <li>Current methods often use pre-trained models that give simple scores, but these can misrepresent human preferences and are prone to manipulation.</li>\n  <li>The new Adv-GRPO framework uses an adversarial reward system that updates both the reward model and the image generator, improving image quality.</li>\n  <li>Instead of using a single score, Adv-GRPO uses multiple visual signals from reference images, which leads to better overall image quality and aesthetics.</li>\n  <li>In tests, this method performed better than existing approaches, achieving higher success rates in image quality and aesthetics, and the code is publicly available.</li>\n</ul>"}, "publishedAt": "2025-11-25T07:35:57.000Z", "title": "The Image as Its Own Reward: Reinforcement Learning with Adversarial Reward for Image Generation", "summary": "A reliable reward function is essential for reinforcement learning (RL) in image generation. Most current RL approaches depend on pre-trained preference models that output scalar rewards to approximate human preferences. However, these rewards often fail to capture human perception and are vulnerable to reward hacking, where higher scores do not correspond to better images. To address this, we introduce Adv-GRPO, an RL framework with an adversarial reward that iteratively updates both the reward model and the generator. The reward model is supervised using reference images as positive samples and can largely avoid being hacked. Unlike KL regularization that constrains parameter updates, our learned reward directly guides the generator through its visual outputs, leading to higher-quality images. Moreover, while optimizing existing reward functions can alleviate reward hacking, their inherent biases remain. For instance, PickScore may degrade image quality, whereas OCR-based rewards often reduce aesthetic fidelity. To address this, we take the image itself as a reward, using reference images and vision foundation models (e.g., DINO) to provide rich visual rewards. These dense visual signals, instead of a single scalar, lead to consistent gains across image quality, aesthetics, and task-specific metrics. Finally, we show that combining reference samples with foundation-model rewards enables distribution transfer and flexible style customization. In human evaluation, our method outperforms Flow-GRPO and SD3, achieving 70.0% and 72.4% win rates in image quality and aesthetics, respectively. Code and models have been released.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20256.png", "numComments": 3, "submittedBy": {"_id": "63f320ee0be81bdc5d8ecb88", "avatarUrl": "/avatars/9d08cff6ed23a51887c869947bc03228.svg", "fullname": "Mao Weijia", "name": "benzweijia", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "isAuthorParticipating": false}],
    "month": [{"paper": {"id": "2511.14993", "authors": [{"_id": "691e819a3c64d32b036458c0", "name": "Vladimir Arkhipkin", "hidden": false}, {"_id": "691e819a3c64d32b036458c1", "user": {"_id": "67bcb1012906865678a11f91", "avatarUrl": "/avatars/80fb0cc24f0d16c4740f9115b680df0f.svg", "isPro": false, "fullname": "Vladimir Korviakov", "user": "korviakov", "type": "user"}, "name": "Vladimir Korviakov", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T09:02:03.925Z", "hidden": false}, {"_id": "691e819a3c64d32b036458c2", "user": {"_id": "63cfa7ef3b7adfa99c0eb524", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/1674553277288-noauth.jpeg", "isPro": false, "fullname": "Nikolai Gerasimenko", "user": "nikgerasimenko", "type": "user"}, "name": "Nikolai Gerasimenko", "status": "claimed_verified", "statusLastChangedAt": "2025-11-24T07:58:55.225Z", "hidden": false}, {"_id": "691e819a3c64d32b036458c3", "name": "Denis Parkhomenko", "hidden": false}, {"_id": "691e819a3c64d32b036458c4", "user": {"_id": "64e4c7764af6c29a0697f57b", "avatarUrl": "/avatars/efc4e9f9b105586fd090b22a1bc7dbb7.svg", "isPro": false, "fullname": "Viacheslav Vasilev", "user": "vvasilev", "type": "user"}, "name": "Viacheslav Vasilev", "status": "claimed_verified", "statusLastChangedAt": "2025-11-20T08:49:10.246Z", "hidden": false}, {"_id": "691e819a3c64d32b036458c5", "user": {"_id": "68838d809080cc7010edf5e2", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/68838d809080cc7010edf5e2/xBqg5ggt_PfLkiDLmsZxx.jpeg", "isPro": false, "fullname": "Alexey Letunovskiy", "user": "AlexeyLetunovskiy", "type": "user"}, "name": "Alexey Letunovskiy", "status": "claimed_verified", "statusLastChangedAt": "2025-11-20T08:49:55.594Z", "hidden": false}, {"_id": "691e819a3c64d32b036458c6", "user": {"_id": "678781c9e3c3c0163db4f99c", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/no-auth/5Vi5J_XS9fbN2gDHfzHlh.png", "isPro": false, "fullname": "Kovaleva Maria", "user": "makovka2000", "type": "user"}, "name": "Maria Kovaleva", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T10:15:36.018Z", "hidden": false}, {"_id": "691e819a3c64d32b036458c7", "user": {"_id": "67f38b14da604b256d393662", "avatarUrl": "/avatars/63445143f68995becc7702868387555b.svg", "isPro": false, "fullname": "Nikolay Vaulin", "user": "nvvaulin", "type": "user"}, "name": "Nikolai Vaulin", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T09:02:01.695Z", "hidden": false}, {"_id": "691e819a3c64d32b036458c8", "user": {"_id": "62653f745f6f2e14d6ae128c", "avatarUrl": "/avatars/944b564ab810a5b31fa5e45f63bdf4ee.svg", "isPro": false, "fullname": "Ivan Kirillov", "user": "funnylittleman", "type": "user"}, "name": "Ivan Kirillov", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T20:40:14.372Z", "hidden": false}, {"_id": "691e819a3c64d32b036458c9", "user": {"_id": "60991602f7c9c7bf29603a88", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/60991602f7c9c7bf29603a88/me8VFG_06ZOovTLldF-L7.jpeg", "isPro": false, "fullname": "Lev Novitskiy", "user": "leffff", "type": "user"}, "name": "Lev Novitskiy", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T09:01:59.489Z", "hidden": false}, {"_id": "691e819a3c64d32b036458ca", "name": "Denis Koposov", "hidden": false}, {"_id": "691e819a3c64d32b036458cb", "user": {"_id": "6628b73c35d27082500034f2", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6628b73c35d27082500034f2/CznOeIbjzJ9DmJaGzlWPD.jpeg", "isPro": false, "fullname": "Nikita Kiselev", "user": "kisnikser", "type": "user"}, "name": "Nikita Kiselev", "status": "claimed_verified", "statusLastChangedAt": "2025-11-20T08:49:11.927Z", "hidden": false}, {"_id": "691e819a3c64d32b036458cc", "user": {"_id": "654d4993938fbf1e695b589a", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/qY3MC94Uz3FGf_HQtHseK.png", "isPro": false, "fullname": "Varlamov Alexander", "user": "Alphonsce", "type": "user"}, "name": "Alexander Varlamov", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T09:02:08.889Z", "hidden": false}, {"_id": "691e819a3c64d32b036458cd", "user": {"_id": "6616719945336ca7746eaa38", "avatarUrl": "/avatars/ac77ebda8507d75376973144263beb83.svg", "isPro": false, "fullname": "Dmitrii Mikhailov", "user": "Botsman11", "type": "user"}, "name": "Dmitrii Mikhailov", "status": "claimed_verified", "statusLastChangedAt": "2025-11-24T07:58:56.980Z", "hidden": false}, {"_id": "691e819a3c64d32b036458ce", "name": "Vladimir Polovnikov", "hidden": false}, {"_id": "691e819a3c64d32b036458cf", "name": "Andrey Shutkin", "hidden": false}, {"_id": "691e819a3c64d32b036458d0", "name": "Ilya Vasiliev", "hidden": false}, {"_id": "691e819a3c64d32b036458d1", "name": "Julia Agafonova", "hidden": false}, {"_id": "691e819a3c64d32b036458d2", "name": "Anastasiia Kargapoltseva", "hidden": false}, {"_id": "691e819a3c64d32b036458d3", "user": {"_id": "65df46ac43bf08064bd8e656", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df46ac43bf08064bd8e656/yR72X3fnBhdy_i34VqBxT.jpeg", "isPro": false, "fullname": "Anna Dmitrienko", "user": "dmitrienkoae", "type": "user"}, "name": "Anna Dmitrienko", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T16:49:09.131Z", "hidden": false}, {"_id": "691e819a3c64d32b036458d4", "name": "Anastasia Maltseva", "hidden": false}, {"_id": "691e819a3c64d32b036458d5", "user": {"_id": "66f1a9c87ce3d2d3938999ce", "avatarUrl": "/avatars/3016b15d4bae2591313537a4ea59b268.svg", "isPro": false, "fullname": "Anna Averchenkova", "user": "aaveraa", "type": "user"}, "name": "Anna Averchenkova", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T16:49:11.123Z", "hidden": false}, {"_id": "691e819a3c64d32b036458d6", "name": "Olga Kim", "hidden": false}, {"_id": "691e819a3c64d32b036458d7", "name": "Tatiana Nikulina", "hidden": false}, {"_id": "691e819a3c64d32b036458d8", "user": {"_id": "6669a678465d1d802181e456", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6669a678465d1d802181e456/ZCthBBhDFQnh0bBkgUQUU.png", "isPro": false, "fullname": "Denis Dimitrov", "user": "dendimitrov", "type": "user"}, "name": "Denis Dimitrov", "status": "claimed_verified", "statusLastChangedAt": "2025-11-20T08:49:08.661Z", "hidden": false}], "publishedAt": "2025-11-19T00:23:22.000Z", "submittedOnDailyAt": "2025-11-20T00:19:10.078Z", "title": "Kandinsky 5.0: A Family of Foundation Models for Image and Video Generation", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "This report introduces Kandinsky 5.0, a family of state-of-the-art foundation models for high-resolution image and 10-second video synthesis. The framework comprises three core line-up of models: Kandinsky 5.0 Image Lite - a line-up of 6B parameter image generation models, Kandinsky 5.0 Video Lite - a fast and lightweight 2B parameter text-to-video and image-to-video models, and Kandinsky 5.0 Video Pro - 19B parameter models that achieves superior video generation quality. We provide a comprehensive review of the data curation lifecycle - including collection, processing, filtering and clustering - for the multi-stage training pipeline that involves extensive pre-training and incorporates quality-enhancement techniques such as self-supervised fine-tuning (SFT) and reinforcement learning (RL)-based post-training. We also present novel architectural, training, and inference optimizations that enable Kandinsky 5.0 to achieve high generation speeds and state-of-the-art performance across various tasks, as demonstrated by human evaluation. As a large-scale, publicly available generative framework, Kandinsky 5.0 leverages the full potential of its pre-training and subsequent stages to be adapted for a wide range of generative applications. We hope that this report, together with the release of our open-source code and training checkpoints, will substantially advance the development and accessibility of high-quality generative models for the research community.", "upvotes": 209, "discussionId": "691e819b3c64d32b036458d9", "projectPage": "https://kandinskylab.ai/", "githubRepo": "https://github.com/kandinskylab/kandinsky-5", "ai_summary": "Kandinsky 5.0 is a family of state-of-the-art generative models for high-resolution images and short videos, featuring model lineups with varying parameters and enhanced training techniques to achieve superior quality and performance.", "ai_keywords": ["foundation models", "high-resolution image synthesis", "10-second video synthesis", "image generation models", "text-to-video models", "image-to-video models", "multi-stage training pipeline", "self-supervised fine-tuning", "reinforcement learning", "pre-training", "quality-enhancement techniques", "architectural optimizations", "training optimizations", "inference optimizations", "human evaluation", "generative framework", "open-source code", "training checkpoints"], "githubStars": 477, "summary_zh": "<ul>\n    <li>\u4ecb\u7ecdKandinsky 5.0\uff0c\u8fd9\u662f\u4e00\u4e2a\u7528\u4e8e\u9ad8\u5206\u8fa8\u7387\u56fe\u50cf\u548c10\u79d2\u89c6\u9891\u5408\u6210\u7684\u5148\u8fdb\u57fa\u7840\u6a21\u578b\u7cfb\u5217\u3002</li>\n    <li>Kandinsky 5.0\u5305\u62ec\u4e09\u79cd\u6838\u5fc3\u6a21\u578b\uff1a6B\u53c2\u6570\u7684\u56fe\u50cf\u751f\u6210\u6a21\u578b\u30012B\u53c2\u6570\u7684\u5feb\u901f\u6587\u672c\u5230\u89c6\u9891\u6a21\u578b\u548c19B\u53c2\u6570\u7684\u9ad8\u8d28\u91cf\u89c6\u9891\u751f\u6210\u6a21\u578b\u3002</li>\n    <li>\u8be6\u7ec6\u8bf4\u660e\u4e86\u6570\u636e\u6574\u7406\u751f\u547d\u5468\u671f\uff0c\u5305\u62ec\u6570\u636e\u6536\u96c6\u3001\u5904\u7406\u3001\u8fc7\u6ee4\u548c\u805a\u7c7b\uff0c\u4ee5\u652f\u6301\u591a\u9636\u6bb5\u8bad\u7ec3\u6d41\u7a0b\u3002</li>\n    <li>\u5c55\u793a\u4e86\u65b0\u9896\u7684\u67b6\u6784\u3001\u8bad\u7ec3\u548c\u63a8\u7406\u4f18\u5316\uff0c\u4f7fKandinsky 5.0\u5728\u751f\u6210\u901f\u5ea6\u548c\u6027\u80fd\u4e0a\u8fbe\u5230\u6700\u5148\u8fdb\u6c34\u5e73\u3002</li>\n    <li>\u5e0c\u671b\u901a\u8fc7\u53d1\u5e03\u5f00\u6e90\u4ee3\u7801\u548c\u8bad\u7ec3\u68c0\u67e5\u70b9\uff0c\u63a8\u52a8\u9ad8\u8d28\u91cf\u751f\u6210\u6a21\u578b\u7684\u53d1\u5c55\u548c\u4fbf\u5229\u6027\u3002 </li>\n</ul>", "summary_simple": "<ul>\n    <li>Kandinsky 5.0 is a new set of advanced models for creating high-quality images and short videos.</li>\n    <li>It includes three main models: Kandinsky 5.0 Image Lite for image generation, Kandinsky 5.0 Video Lite for quick video creation, and Kandinsky 5.0 Video Pro for top-quality video generation.</li>\n    <li>The report details the process of gathering and preparing data for training these models, including various techniques to improve quality.</li>\n    <li>Kandinsky 5.0 features improvements in its design and training methods, allowing it to generate high-quality content quickly.</li>\n    <li>The models are open-source, making them accessible for researchers and developers to use in different creative projects.</li>\n</ul>"}, "publishedAt": "2025-11-18T19:23:22.000Z", "title": "Kandinsky 5.0: A Family of Foundation Models for Image and Video Generation", "summary": "This report introduces Kandinsky 5.0, a family of state-of-the-art foundation models for high-resolution image and 10-second video synthesis. The framework comprises three core line-up of models: Kandinsky 5.0 Image Lite - a line-up of 6B parameter image generation models, Kandinsky 5.0 Video Lite - a fast and lightweight 2B parameter text-to-video and image-to-video models, and Kandinsky 5.0 Video Pro - 19B parameter models that achieves superior video generation quality. We provide a comprehensive review of the data curation lifecycle - including collection, processing, filtering and clustering - for the multi-stage training pipeline that involves extensive pre-training and incorporates quality-enhancement techniques such as self-supervised fine-tuning (SFT) and reinforcement learning (RL)-based post-training. We also present novel architectural, training, and inference optimizations that enable Kandinsky 5.0 to achieve high generation speeds and state-of-the-art performance across various tasks, as demonstrated by human evaluation. As a large-scale, publicly available generative framework, Kandinsky 5.0 leverages the full potential of its pre-training and subsequent stages to be adapted for a wide range of generative applications. We hope that this report, together with the release of our open-source code and training checkpoints, will substantially advance the development and accessibility of high-quality generative models for the research community.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.14993.png", "numComments": 5, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 171}, "isAuthorParticipating": true}, {"paper": {"id": "2511.04570", "authors": [{"_id": "690d5b51ad2597bf6c464ca9", "name": "Jingqi Tong", "hidden": false}, {"_id": "690d5b51ad2597bf6c464caa", "name": "Yurong Mou", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cab", "name": "Hangcheng Li", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cac", "user": {"_id": "65e4134472e748aae53e24f3", "avatarUrl": "/avatars/3346f4f4cdbffc4c51276be01a6c5f10.svg", "isPro": false, "fullname": "Mingzhe Li", "user": "Mubuky", "type": "user"}, "name": "Mingzhe Li", "status": "claimed_verified", "statusLastChangedAt": "2025-11-07T10:28:47.508Z", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cad", "user": {"_id": "65ab2dd614d782df061265cd", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65ab2dd614d782df061265cd/7T8kMx0wFNTa5zsVQrnOr.jpeg", "isPro": false, "fullname": "Yongzhuo Yang", "user": "YangYongzhuo", "type": "user"}, "name": "Yongzhuo Yang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-10T09:31:39.261Z", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cae", "name": "Ming Zhang", "hidden": false}, {"_id": "690d5b51ad2597bf6c464caf", "name": "Qiguang Chen", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cb0", "name": "Tianyi Liang", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cb1", "name": "Xiaomeng Hu", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cb2", "name": "Yining Zheng", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cb3", "name": "Xinchi Chen", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cb4", "name": "Jun Zhao", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cb5", "name": "Xuanjing Huang", "hidden": false}, {"_id": "690d5b51ad2597bf6c464cb6", "name": "Xipeng Qiu", "hidden": false}], "publishedAt": "2025-11-06T17:25:23.000Z", "submittedOnDailyAt": "2025-11-07T00:18:17.549Z", "title": "Thinking with Video: Video Generation as a Promising Multimodal\n  Reasoning Paradigm", "submittedOnDailyBy": {"_id": "6690e13ccbcaf7ab0ec1c971", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/e8KDV6J29tviXlIpLZPq6.png", "isPro": false, "fullname": "Tony.Li", "user": "lkdhy", "type": "user"}, "summary": "\"Thinking with Text\" and \"Thinking with Images\" paradigm significantly\nimprove the reasoning ability of large language models (LLMs) and Vision\nLanguage Models (VLMs). However, these paradigms have inherent limitations. (1)\nImages capture only single moments and fail to represent dynamic processes or\ncontinuous changes, and (2) The separation of text and vision as distinct\nmodalities, hindering unified multimodal understanding and generation. To\novercome these limitations, we introduce \"Thinking with Video\", a new paradigm\nthat leverages video generation models, such as Sora-2, to bridge visual and\ntextual reasoning in a unified temporal framework. To support this exploration,\nwe developed the Video Thinking Benchmark (VideoThinkBench). VideoThinkBench\nencompasses two task categories: (1) vision-centric tasks (e.g., Eyeballing\nPuzzles), and (2) text-centric tasks (e.g., subsets of GSM8K, MMMU). Our\nevaluation establishes Sora-2 as a capable reasoner. On vision-centric tasks,\nSora-2 is generally comparable to state-of-the-art (SOTA) VLMs, and even\nsurpasses VLMs on several tasks, such as Eyeballing Games. On text-centric\ntasks, Sora-2 achieves 92% accuracy on MATH, and 75.53% accuracy on MMMU.\nFurthermore, we systematically analyse the source of these abilities. We also\nfind that self-consistency and in-context learning can improve Sora-2's\nperformance. In summary, our findings demonstrate that the video generation\nmodel is the potential unified multimodal understanding and generation model,\npositions \"thinking with video\" as a unified multimodal reasoning paradigm.", "upvotes": 203, "discussionId": "690d5b51ad2597bf6c464cb7", "projectPage": "https://thinking-with-video.github.io/", "githubRepo": "https://github.com/tongjingqi/Thinking-with-Video", "ai_summary": "The \"Thinking with Video\" paradigm enhances multimodal reasoning by integrating video generation models, demonstrated through the Video Thinking Benchmark and improved performance on both vision and text tasks.", "ai_keywords": ["Thinking with Text", "Thinking with Images", "large language models", "Vision Language Models", "Thinking with Video", "video generation models", "Video Thinking Benchmark", "vision-centric tasks", "text-centric tasks", "Eyeballing Puzzles", "GSM8K", "MMMU", "self-consistency", "in-context learning"], "githubStars": 211, "organization": {"_id": "613b0dee83ec35d460684607", "name": "OpenMOSS-Team", "fullname": "OpenMOSS", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/61457b8deff2c9fdb4de4988/N5b9663zQ4uq5_OTNlnmw.png"}, "summary_zh": "<ul>\n    <li>\u63d0\u51fa\u4e86\u201c\u89c6\u9891\u601d\u7ef4\u201d\u65b0\u8303\u5f0f\uff0c\u4ee5\u514b\u670d\u73b0\u6709\u6587\u672c\u548c\u56fe\u50cf\u601d\u7ef4\u7684\u5c40\u9650\u6027\u3002</li>\n    <li>\u89c6\u9891\u601d\u7ef4\u5229\u7528\u89c6\u9891\u751f\u6210\u6a21\u578b\uff08\u5982Sora-2\uff09\u6765\u5b9e\u73b0\u89c6\u89c9\u548c\u6587\u672c\u63a8\u7406\u7684\u7edf\u4e00\u3002</li>\n    <li>\u5f00\u53d1\u4e86\u89c6\u9891\u601d\u7ef4\u57fa\u51c6\uff08VideoThinkBench\uff09\uff0c\u5305\u542b\u89c6\u89c9\u548c\u6587\u672c\u4efb\u52a1\u4e24\u7c7b\u3002</li>\n    <li>Sora-2\u5728\u89c6\u89c9\u4efb\u52a1\u4e0a\u4e0e\u6700\u5148\u8fdb\u7684VLMs\u76f8\u5f53\uff0c\u5e76\u5728\u67d0\u4e9b\u4efb\u52a1\u4e0a\u8d85\u8d8a\u5b83\u4eec\u3002</li>\n    <li>Sora-2\u5728\u6587\u672c\u4efb\u52a1\u4e0a\u4e5f\u8868\u73b0\u51fa\u8272\uff0c\u51c6\u786e\u7387\u8fbe\u523092%\u548c75.53%\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li> \"Thinking with Text\" and \"Thinking with Images\" improve reasoning in language and vision models but have limitations.</li>\n    <li> Images can only show single moments and don't capture ongoing changes; separating text and images limits understanding.</li>\n    <li> The new \"Thinking with Video\" approach uses video generation to connect visual and textual reasoning over time.</li>\n    <li> We created the Video Thinking Benchmark to test this approach with vision-centric and text-centric tasks.</li>\n    <li> The Sora-2 model performs well, matching or exceeding other models in many tasks, showing potential for unified multimodal reasoning.</li>\n</ul>"}, "publishedAt": "2025-11-06T12:25:23.000Z", "title": "Thinking with Video: Video Generation as a Promising Multimodal\n  Reasoning Paradigm", "summary": "\"Thinking with Text\" and \"Thinking with Images\" paradigm significantly\nimprove the reasoning ability of large language models (LLMs) and Vision\nLanguage Models (VLMs). However, these paradigms have inherent limitations. (1)\nImages capture only single moments and fail to represent dynamic processes or\ncontinuous changes, and (2) The separation of text and vision as distinct\nmodalities, hindering unified multimodal understanding and generation. To\novercome these limitations, we introduce \"Thinking with Video\", a new paradigm\nthat leverages video generation models, such as Sora-2, to bridge visual and\ntextual reasoning in a unified temporal framework. To support this exploration,\nwe developed the Video Thinking Benchmark (VideoThinkBench). VideoThinkBench\nencompasses two task categories: (1) vision-centric tasks (e.g., Eyeballing\nPuzzles), and (2) text-centric tasks (e.g., subsets of GSM8K, MMMU). Our\nevaluation establishes Sora-2 as a capable reasoner. On vision-centric tasks,\nSora-2 is generally comparable to state-of-the-art (SOTA) VLMs, and even\nsurpasses VLMs on several tasks, such as Eyeballing Games. On text-centric\ntasks, Sora-2 achieves 92% accuracy on MATH, and 75.53% accuracy on MMMU.\nFurthermore, we systematically analyse the source of these abilities. We also\nfind that self-consistency and in-context learning can improve Sora-2's\nperformance. In summary, our findings demonstrate that the video generation\nmodel is the potential unified multimodal understanding and generation model,\npositions \"thinking with video\" as a unified multimodal reasoning paradigm.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.04570.png", "numComments": 4, "submittedBy": {"_id": "6690e13ccbcaf7ab0ec1c971", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/e8KDV6J29tviXlIpLZPq6.png", "fullname": "Tony.Li", "name": "lkdhy", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "organization": {"_id": "613b0dee83ec35d460684607", "name": "OpenMOSS-Team", "fullname": "OpenMOSS", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/61457b8deff2c9fdb4de4988/N5b9663zQ4uq5_OTNlnmw.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2511.08892", "authors": [{"_id": "69154dffa1b06ca3cc81351e", "name": "Weihao Tan", "hidden": false}, {"_id": "69154dffa1b06ca3cc81351f", "name": "Xiangyang Li", "hidden": false}, {"_id": "69154dffa1b06ca3cc813520", "name": "Yunhao Fang", "hidden": false}, {"_id": "69154dffa1b06ca3cc813521", "name": "Heyuan Yao", "hidden": false}, {"_id": "69154dffa1b06ca3cc813522", "name": "Shi Yan", "hidden": false}, {"_id": "69154dffa1b06ca3cc813523", "name": "Hao Luo", "hidden": false}, {"_id": "69154dffa1b06ca3cc813524", "name": "Tenglong Ao", "hidden": false}, {"_id": "69154dffa1b06ca3cc813525", "name": "Huihui Li", "hidden": false}, {"_id": "69154dffa1b06ca3cc813526", "name": "Hongbin Ren", "hidden": false}, {"_id": "69154dffa1b06ca3cc813527", "user": {"_id": "6369d92f64aad59d4d44d362", "avatarUrl": "/avatars/73956400cfbfd53116aefc17b3c9f0fd.svg", "isPro": false, "fullname": "Yi", "user": "Bairen", "type": "user"}, "name": "Bairen Yi", "status": "claimed_verified", "statusLastChangedAt": "2025-11-17T10:31:49.043Z", "hidden": false}, {"_id": "69154dffa1b06ca3cc813528", "name": "Yujia Qin", "hidden": false}, {"_id": "69154dffa1b06ca3cc813529", "name": "Bo An", "hidden": false}, {"_id": "69154dffa1b06ca3cc81352a", "name": "Libin Liu", "hidden": false}, {"_id": "69154dffa1b06ca3cc81352b", "name": "Guang Shi", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/FVxpP05KrXQ1HkQ1G1uNl.mp4"], "publishedAt": "2025-11-12T02:01:26.000Z", "submittedOnDailyAt": "2025-11-13T00:49:21.639Z", "title": "Lumine: An Open Recipe for Building Generalist Agents in 3D Open Worlds", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "We introduce Lumine, the first open recipe for developing generalist agents capable of completing hours-long complex missions in real time within challenging 3D open-world environments. Lumine adopts a human-like interaction paradigm that unifies perception, reasoning, and action in an end-to-end manner, powered by a vision-language model. It processes raw pixels at 5 Hz to produce precise 30 Hz keyboard-mouse actions and adaptively invokes reasoning only when necessary. Trained in Genshin Impact, Lumine successfully completes the entire five-hour Mondstadt main storyline on par with human-level efficiency and follows natural language instructions to perform a broad spectrum of tasks in both 3D open-world exploration and 2D GUI manipulation across collection, combat, puzzle-solving, and NPC interaction. In addition to its in-domain performance, Lumine demonstrates strong zero-shot cross-game generalization. Without any fine-tuning, it accomplishes 100-minute missions in Wuthering Waves and the full five-hour first chapter of Honkai: Star Rail. These promising results highlight Lumine's effectiveness across distinct worlds and interaction dynamics, marking a concrete step toward generalist agents in open-ended environments.", "upvotes": 185, "discussionId": "69154dffa1b06ca3cc81352c", "projectPage": "https://www.lumine-ai.org/", "ai_summary": "Lumine, a vision-language model-based agent, completes complex missions in real-time across different 3D open-world environments with human-like efficiency and zero-shot cross-game generalization.", "ai_keywords": ["vision-language model", "end-to-end", "3D open-world environments", "human-like interaction", "real-time", "zero-shot cross-game generalization"], "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "summary_zh": "<ul>\n    <li>Lumine\u662f\u7b2c\u4e00\u4e2a\u5f00\u653e\u7684\u901a\u7528\u667a\u80fd\u4f53\u5f00\u53d1\u914d\u65b9\uff0c\u80fd\u591f\u5728\u590d\u6742\u76843D\u5f00\u653e\u4e16\u754c\u73af\u5883\u4e2d\u5b9e\u65f6\u5b8c\u6210\u957f\u8fbe\u6570\u5c0f\u65f6\u7684\u4efb\u52a1\u3002</li>\n    <li>\u5b83\u91c7\u7528\u7c7b\u4f3c\u4eba\u7c7b\u7684\u4ea4\u4e92\u65b9\u5f0f\uff0c\u5c06\u611f\u77e5\u3001\u63a8\u7406\u548c\u884c\u52a8\u7edf\u4e00\u5728\u4e00\u4e2a\u7aef\u5230\u7aef\u7684\u7cfb\u7edf\u4e2d\uff0c\u4f7f\u7528\u89c6\u89c9\u8bed\u8a00\u6a21\u578b\u9a71\u52a8\u3002</li>\n    <li>Lumine\u5728\u300a\u539f\u795e\u300b\u4e2d\u8bad\u7ec3\uff0c\u80fd\u591f\u4e0e\u4eba\u7c7b\u6548\u7387\u76f8\u5f53\u5730\u5b8c\u6210\u4e94\u5c0f\u65f6\u7684\u4e3b\u7ebf\u4efb\u52a1\uff0c\u5e76\u6839\u636e\u81ea\u7136\u8bed\u8a00\u6307\u4ee4\u6267\u884c\u5404\u79cd\u4efb\u52a1\u3002</li>\n    <li>\u5b83\u4e0d\u4ec5\u5728\u7279\u5b9a\u6e38\u620f\u4e2d\u8868\u73b0\u51fa\u8272\uff0c\u8fd8\u80fd\u591f\u5728\u6ca1\u6709\u5fae\u8c03\u7684\u60c5\u51b5\u4e0b\uff0c\u5728\u5176\u4ed6\u6e38\u620f\u4e2d\u5b8c\u6210\u957f\u8fbe100\u5206\u949f\u7684\u4efb\u52a1\u3002</li>\n    <li>Lumine\u7684\u6210\u529f\u5c55\u793a\u4e86\u5728\u5f00\u653e\u73af\u5883\u4e2d\u5f00\u53d1\u901a\u7528\u667a\u80fd\u4f53\u7684\u6f5c\u529b\uff0c\u63a8\u52a8\u4e86\u8be5\u9886\u57df\u7684\u53d1\u5c55\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Lumine is a new open recipe for creating generalist agents that can handle long, complex tasks in 3D open-world games.</li>\n    <li>It uses a human-like approach to combine sensing, thinking, and acting, using a vision-language model.</li>\n    <li>Lumine processes visual information quickly and efficiently to perform actions based on natural language commands.</li>\n    <li>It can complete the five-hour main storyline of Genshin Impact at a level similar to human players and follow various instructions across different tasks.</li>\n    <li>Lumine shows strong performance in other games without needing extra training, successfully completing missions in Wuthering Waves and Honkai: Star Rail.</li>\n</ul>"}, "publishedAt": "2025-11-11T21:01:26.000Z", "title": "Lumine: An Open Recipe for Building Generalist Agents in 3D Open Worlds", "summary": "We introduce Lumine, the first open recipe for developing generalist agents capable of completing hours-long complex missions in real time within challenging 3D open-world environments. Lumine adopts a human-like interaction paradigm that unifies perception, reasoning, and action in an end-to-end manner, powered by a vision-language model. It processes raw pixels at 5 Hz to produce precise 30 Hz keyboard-mouse actions and adaptively invokes reasoning only when necessary. Trained in Genshin Impact, Lumine successfully completes the entire five-hour Mondstadt main storyline on par with human-level efficiency and follows natural language instructions to perform a broad spectrum of tasks in both 3D open-world exploration and 2D GUI manipulation across collection, combat, puzzle-solving, and NPC interaction. In addition to its in-domain performance, Lumine demonstrates strong zero-shot cross-game generalization. Without any fine-tuning, it accomplishes 100-minute missions in Wuthering Waves and the full five-hour first chapter of Honkai: Star Rail. These promising results highlight Lumine's effectiveness across distinct worlds and interaction dynamics, marking a concrete step toward generalist agents in open-ended environments.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6039478ab3ecf716b1a5fd4d/FVxpP05KrXQ1HkQ1G1uNl.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.08892.png", "numComments": 12, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 171}, "organization": {"_id": "67d1140985ea0644e2f14b99", "name": "ByteDance-Seed", "fullname": "ByteDance Seed", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/6535c9e88bde2fae19b6fb25/flkDUqd_YEuFsjeNET3r-.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2511.20626", "authors": [{"_id": "6927ab26243b2216fb75cd1b", "name": "Wei He", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1c", "user": {"_id": "65e52e7d27dc8aa470a640e3", "avatarUrl": "/avatars/022a179d14de29b9ab9d96fcc85aa264.svg", "isPro": false, "fullname": "hankai", "user": "hankaixyz", "type": "user"}, "name": "Kai Han", "status": "claimed_verified", "statusLastChangedAt": "2025-11-27T09:59:11.052Z", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1d", "name": "Hang Zhou", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1e", "name": "Hanting Chen", "hidden": false}, {"_id": "6927ab26243b2216fb75cd1f", "name": "Zhicheng Liu", "hidden": false}, {"_id": "6927ab26243b2216fb75cd20", "name": "Xinghao Chen", "hidden": false}, {"_id": "6927ab26243b2216fb75cd21", "name": "Yunhe Wang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65e52e7d27dc8aa470a640e3/r9QpXyUHL3SWym780xlxD.png"], "publishedAt": "2025-11-25T18:48:05.000Z", "submittedOnDailyAt": "2025-11-26T23:08:13.066Z", "title": "ROOT: Robust Orthogonalized Optimizer for Neural Network Training", "submittedOnDailyBy": {"_id": "65e52e7d27dc8aa470a640e3", "avatarUrl": "/avatars/022a179d14de29b9ab9d96fcc85aa264.svg", "isPro": false, "fullname": "hankai", "user": "hankaixyz", "type": "user"}, "summary": "The optimization of large language models (LLMs) remains a critical challenge, particularly as model scaling exacerbates sensitivity to algorithmic imprecision and training instability. Recent advances in optimizers have improved convergence efficiency through momentum orthogonalization, but suffer from two key robustness limitations: dimensional fragility in orthogonalization precision and vulnerability to outlier-induced noise. To address these robustness challenges, we introduce ROOT, a Robust Orthogonalized Optimizer that enhances training stability through dual robustness mechanisms. First, we develop a dimension-robust orthogonalization scheme using adaptive Newton iterations with fine-grained coefficients tailored to specific matrix sizes, ensuring consistent precision across diverse architectural configurations. Second, we introduce an optimization-robust framework via proximal optimization that suppresses outlier noise while preserving meaningful gradient directions. Extensive experiments demonstrate that ROOT achieves significantly improved robustness, with faster convergence and superior final performance compared to both Muon and Adam-based optimizers, particularly in noisy and non-convex scenarios. Our work establishes a new paradigm for developing robust and precise optimizers capable of handling the complexities of modern large-scale model training. The code will be available at https://github.com/huawei-noah/noah-research/tree/master/ROOT.", "upvotes": 154, "discussionId": "6927ab27243b2216fb75cd22", "projectPage": "https://github.com/huawei-noah/noah-research/tree/master/ROOT", "githubRepo": "https://github.com/huawei-noah/noah-research", "ai_summary": "ROOT, a robust optimizer, enhances training stability and convergence for large language models by addressing dimensional fragility and outlier noise through adaptive Newton iterations and proximal optimization.", "ai_keywords": ["large language models", "LLMs", "momentum orthogonalization", "dimensional fragility", "outlier-induced noise", "adaptive Newton iterations", "proximal optimization", "Muon", "Adam-based optimizers", "robust optimizer"], "githubStars": 909, "organization": {"_id": "5f83c275f0801648bf88454a", "name": "huawei-noah", "fullname": "HUAWEI Noah's Ark Lab", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1602470452594-5f83c19ff0801648bf884549.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\u7684\u4f18\u5316\u662f\u4e00\u4e2a\u91cd\u8981\u6311\u6218\uff0c\u6a21\u578b\u89c4\u6a21\u589e\u52a0\u52a0\u5267\u4e86\u7b97\u6cd5\u4e0d\u7cbe\u786e\u548c\u8bad\u7ec3\u4e0d\u7a33\u5b9a\u6027\u7684\u95ee\u9898\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e00\u79cd\u65b0\u7684\u4f18\u5316\u5668ROOT\uff0c\u65e8\u5728\u901a\u8fc7\u53cc\u91cd\u7a33\u5065\u673a\u5236\u6765\u589e\u5f3a\u8bad\u7ec3\u7a33\u5b9a\u6027\u3002</li>\n    <li>ROOT\u91c7\u7528\u81ea\u9002\u5e94\u725b\u987f\u8fed\u4ee3\u7684\u7ef4\u5ea6\u7a33\u5065\u6b63\u4ea4\u5316\u65b9\u6848\uff0c\u63d0\u9ad8\u4e86\u4e0d\u540c\u67b6\u6784\u914d\u7f6e\u4e0b\u7684\u7cbe\u786e\u5ea6\u3002</li>\n    <li>ROOT\u8fd8\u901a\u8fc7\u90bb\u8fd1\u4f18\u5316\u6846\u67b6\u6291\u5236\u5f02\u5e38\u503c\u566a\u58f0\uff0c\u540c\u65f6\u4fdd\u6301\u6709\u610f\u4e49\u7684\u68af\u5ea6\u65b9\u5411\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cROOT\u5728\u566a\u58f0\u548c\u975e\u51f8\u573a\u666f\u4e2d\u6bd4Muon\u548c\u57fa\u4e8eAdam\u7684\u4f18\u5316\u5668\u5177\u6709\u66f4\u5feb\u7684\u6536\u655b\u901f\u5ea6\u548c\u66f4\u597d\u7684\u6700\u7ec8\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language models (LLMs) face challenges with training stability and precision as they grow in size.</li>\n    <li>Recent optimizers have improved efficiency but struggle with robustness against noise and dimensional changes.</li>\n    <li>ROOT is a new optimizer that strengthens training stability using two innovative methods: dimension-robust orthogonalization and noise suppression.</li>\n    <li>Experiments show ROOT outperforms other optimizers like Muon and Adam in tough conditions, achieving faster training and better results.</li>\n    <li>The ROOT code will be available online for others to use and build upon.</li>\n</ul>"}, "publishedAt": "2025-11-25T13:48:05.000Z", "title": "ROOT: Robust Orthogonalized Optimizer for Neural Network Training", "summary": "The optimization of large language models (LLMs) remains a critical challenge, particularly as model scaling exacerbates sensitivity to algorithmic imprecision and training instability. Recent advances in optimizers have improved convergence efficiency through momentum orthogonalization, but suffer from two key robustness limitations: dimensional fragility in orthogonalization precision and vulnerability to outlier-induced noise. To address these robustness challenges, we introduce ROOT, a Robust Orthogonalized Optimizer that enhances training stability through dual robustness mechanisms. First, we develop a dimension-robust orthogonalization scheme using adaptive Newton iterations with fine-grained coefficients tailored to specific matrix sizes, ensuring consistent precision across diverse architectural configurations. Second, we introduce an optimization-robust framework via proximal optimization that suppresses outlier noise while preserving meaningful gradient directions. Extensive experiments demonstrate that ROOT achieves significantly improved robustness, with faster convergence and superior final performance compared to both Muon and Adam-based optimizers, particularly in noisy and non-convex scenarios. Our work establishes a new paradigm for developing robust and precise optimizers capable of handling the complexities of modern large-scale model training. The code will be available at https://github.com/huawei-noah/noah-research/tree/master/ROOT.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65e52e7d27dc8aa470a640e3/r9QpXyUHL3SWym780xlxD.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.20626.png", "numComments": 2, "submittedBy": {"_id": "65e52e7d27dc8aa470a640e3", "avatarUrl": "/avatars/022a179d14de29b9ab9d96fcc85aa264.svg", "fullname": "hankai", "name": "hankaixyz", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "organization": {"_id": "5f83c275f0801648bf88454a", "name": "huawei-noah", "fullname": "HUAWEI Noah's Ark Lab", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1602470452594-5f83c19ff0801648bf884549.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.11793", "authors": [{"_id": "691be81b6bfd5965c0fd37e2", "name": "MiroMind Team", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37e3", "name": "Song Bai", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37e4", "name": "Lidong Bing", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37e5", "name": "Carson Chen", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37e6", "name": "Guanzheng Chen", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37e7", "user": {"_id": "632dab84fdb35759ea6646a0", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/632dab84fdb35759ea6646a0/IxO5mbtzHJsr0YHW-YtVk.jpeg", "isPro": false, "fullname": "Yuntao Chen", "user": "YuntaoChen", "type": "user"}, "name": "Yuntao Chen", "status": "claimed_verified", "statusLastChangedAt": "2025-11-19T08:40:45.403Z", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37e8", "name": "Zhe Chen", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37e9", "name": "Ziyi Chen", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37ea", "name": "Jifeng Dai", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37eb", "name": "Xuan Dong", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37ec", "name": "Yue Deng", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37ed", "name": "Yunjie Fu", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37ee", "name": "Junqi Ge", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37ef", "name": "Chenxia Han", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f0", "name": "Tammy Huang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f1", "name": "Zhenhang Huang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f2", "name": "Jerry Jiao", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f3", "name": "Shilei Jiang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f4", "name": "Tianyu Jiao", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f5", "user": {"_id": "64be2455b567ae97c34bb948", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64be2455b567ae97c34bb948/QuCdStDDGaXjDmp4V-dBj.jpeg", "isPro": false, "fullname": "Xiaoqi Jian", "user": "mx1024", "type": "user"}, "name": "Xiaoqi Jian", "status": "claimed_verified", "statusLastChangedAt": "2025-11-19T08:40:52.417Z", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f6", "name": "Lei Lei", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f7", "user": {"_id": "6466e7be1343dce20e59191b", "avatarUrl": "/avatars/6779560b203c3773dc76372c0b8cbe4e.svg", "isPro": false, "fullname": "Li Ruilin", "user": "Eric-LRL-130", "type": "user"}, "name": "Ruilin Li", "status": "claimed_verified", "statusLastChangedAt": "2025-11-19T08:40:43.774Z", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f8", "name": "Ryan Luo", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37f9", "name": "Tiantong Li", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37fa", "name": "Xiang Lin", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37fb", "name": "Ziyuan Liu", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37fc", "name": "Zhiqi Li", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37fd", "name": "Jie Ni", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37fe", "name": "Qiang Ren", "hidden": false}, {"_id": "691be81b6bfd5965c0fd37ff", "name": "Pax Sun", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3800", "name": "Shiqian Su", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3801", "name": "Chenxin Tao", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3802", "name": "Bin Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3803", "name": "Hellen Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3804", "name": "Haonan Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3805", "name": "James Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3806", "name": "Jin Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3807", "name": "Jojo Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3808", "name": "Letian Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3809", "name": "Shizun Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd380a", "user": {"_id": "63d34004b734eaa4d4faeccf", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/63d34004b734eaa4d4faeccf/zf6d1p0GN8gsagi8N6y4V.jpeg", "isPro": false, "fullname": "Weizhi Wang", "user": "weizhiwang", "type": "user"}, "name": "Weizhi Wang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-19T08:40:47.000Z", "hidden": false}, {"_id": "691be81b6bfd5965c0fd380b", "name": "Zixuan Wang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd380c", "name": "Jinfan Xu", "hidden": false}, {"_id": "691be81b6bfd5965c0fd380d", "name": "Sen Xing", "hidden": false}, {"_id": "691be81b6bfd5965c0fd380e", "user": {"_id": "637f347a52229c639211bee8", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/637f347a52229c639211bee8/I9_PET-_6SJQJ6hXrACV4.jpeg", "isPro": false, "fullname": "Chenyu Yang", "user": "cyyang822", "type": "user"}, "name": "Chenyu Yang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-19T08:40:48.746Z", "hidden": false}, {"_id": "691be81b6bfd5965c0fd380f", "user": {"_id": "6239888e7fef05b7bdd5fcff", "avatarUrl": "/avatars/54fcc756b8c0936b6bb410c6e0e02d75.svg", "isPro": false, "fullname": "Hai Ye", "user": "oceanpty", "type": "user"}, "name": "Hai Ye", "status": "claimed_verified", "statusLastChangedAt": "2025-11-19T08:40:50.623Z", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3810", "name": "Jiaheng Yu", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3811", "name": "Yue Yu", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3812", "name": "Muyan Zhong", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3813", "name": "Tianchen Zhao", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3814", "name": "Xizhou Zhu", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3815", "name": "Yanpeng Zhou", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3816", "name": "Yifan Zhang", "hidden": false}, {"_id": "691be81b6bfd5965c0fd3817", "name": "Zhi Zhu", "hidden": false}], "publishedAt": "2025-11-14T18:52:07.000Z", "submittedOnDailyAt": "2025-11-18T02:00:07.077Z", "title": "MiroThinker: Pushing the Performance Boundaries of Open-Source Research Agents via Model, Context, and Interactive Scaling", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user"}, "summary": "We present MiroThinker v1.0, an open-source research agent designed to advance tool-augmented reasoning and information-seeking capabilities. Unlike previous agents that only scale up model size or context length, MiroThinker explores interaction scaling at the model level, systematically training the model to handle deeper and more frequent agent-environment interactions as a third dimension of performance improvement. Unlike LLM test-time scaling, which operates in isolation and risks degradation with longer reasoning chains, interactive scaling leverages environment feedback and external information acquisition to correct errors and refine trajectories. Through reinforcement learning, the model achieves efficient interaction scaling: with a 256K context window, it can perform up to 600 tool calls per task, enabling sustained multi-turn reasoning and complex real-world research workflows. Across four representative benchmarks-GAIA, HLE, BrowseComp, and BrowseComp-ZH-the 72B variant achieves up to 81.9%, 37.7%, 47.1%, and 55.6% accuracy respectively, surpassing previous open-source agents and approaching commercial counterparts such as GPT-5-high. Our analysis reveals that MiroThinker benefits from interactive scaling consistently: research performance improves predictably as the model engages in deeper and more frequent agent-environment interactions, demonstrating that interaction depth exhibits scaling behaviors analogous to model size and context length. These findings establish interaction scaling as a third critical dimension for building next-generation open research agents, complementing model capacity and context windows.", "upvotes": 153, "discussionId": "691be81b6bfd5965c0fd3818", "projectPage": "https://dr.miromind.ai/", "githubRepo": "https://github.com/MiroMindAI/MiroThinker", "githubStars": 1133, "summary_zh": "<ul>\n    <li>\u6211\u4eec\u4ecb\u7ecd\u4e86MiroThinker v1.0\uff0c\u8fd9\u662f\u4e00\u4e2a\u5f00\u6e90\u7814\u7a76\u4ee3\u7406\uff0c\u65e8\u5728\u589e\u5f3a\u5de5\u5177\u8f85\u52a9\u63a8\u7406\u548c\u4fe1\u606f\u83b7\u53d6\u80fd\u529b\u3002</li>\n    <li>MiroThinker\u901a\u8fc7\u5728\u6a21\u578b\u5c42\u9762\u63a2\u7d22\u4ea4\u4e92\u6269\u5c55\uff0c\u80fd\u591f\u66f4\u597d\u5730\u5904\u7406\u4ee3\u7406\u4e0e\u73af\u5883\u4e4b\u95f4\u7684\u4e92\u52a8\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5229\u7528\u5f3a\u5316\u5b66\u4e60\u5b9e\u73b0\u9ad8\u6548\u7684\u4ea4\u4e92\u6269\u5c55\uff0c\u652f\u6301\u591a\u8fbe600\u6b21\u5de5\u5177\u8c03\u7528\uff0c\u9002\u5e94\u590d\u6742\u7684\u7814\u7a76\u5de5\u4f5c\u6d41\u7a0b\u3002</li>\n    <li>MiroThinker\u5728\u591a\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u51c6\u786e\u7387\u8d85\u8fc7\u4e86\u4ee5\u5f80\u7684\u5f00\u6e90\u4ee3\u7406\uff0c\u63a5\u8fd1\u5546\u4e1a\u6a21\u578b\u7684\u6c34\u5e73\u3002</li>\n    <li>\u7814\u7a76\u8868\u660e\uff0c\u4ea4\u4e92\u6df1\u5ea6\u7684\u6269\u5c55\u4e0e\u6a21\u578b\u7684\u89c4\u6a21\u548c\u4e0a\u4e0b\u6587\u957f\u5ea6\u5177\u6709\u76f8\u4f3c\u7684\u6269\u5c55\u7279\u6027\uff0c\u662f\u6784\u5efa\u4e0b\u4e00\u4ee3\u5f00\u653e\u7814\u7a76\u4ee3\u7406\u7684\u91cd\u8981\u7ef4\u5ea6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>MiroThinker v1.0 is an open-source research agent aimed at improving reasoning and information-seeking skills.</li>\n    <li>It focuses on enhancing how the model interacts with its environment, rather than just increasing model size or context length.</li>\n    <li>The model uses reinforcement learning to effectively manage many tool calls (up to 600) during tasks, supporting complex research activities.</li>\n    <li>MiroThinker outperforms previous open-source agents in various benchmarks, showing accuracy rates that approach those of advanced commercial models.</li>\n    <li>The research highlights that better performance comes from deeper and more frequent interactions with the environment, suggesting that this interaction is crucial for future research agent development.</li>\n</ul>"}, "publishedAt": "2025-11-14T13:52:07.000Z", "title": "MiroThinker: Pushing the Performance Boundaries of Open-Source Research Agents via Model, Context, and Interactive Scaling", "summary": "We present MiroThinker v1.0, an open-source research agent designed to advance tool-augmented reasoning and information-seeking capabilities. Unlike previous agents that only scale up model size or context length, MiroThinker explores interaction scaling at the model level, systematically training the model to handle deeper and more frequent agent-environment interactions as a third dimension of performance improvement. Unlike LLM test-time scaling, which operates in isolation and risks degradation with longer reasoning chains, interactive scaling leverages environment feedback and external information acquisition to correct errors and refine trajectories. Through reinforcement learning, the model achieves efficient interaction scaling: with a 256K context window, it can perform up to 600 tool calls per task, enabling sustained multi-turn reasoning and complex real-world research workflows. Across four representative benchmarks-GAIA, HLE, BrowseComp, and BrowseComp-ZH-the 72B variant achieves up to 81.9%, 37.7%, 47.1%, and 55.6% accuracy respectively, surpassing previous open-source agents and approaching commercial counterparts such as GPT-5-high. Our analysis reveals that MiroThinker benefits from interactive scaling consistently: research performance improves predictably as the model engages in deeper and more frequent agent-environment interactions, demonstrating that interaction depth exhibits scaling behaviors analogous to model size and context length. These findings establish interaction scaling as a third critical dimension for building next-generation open research agents, complementing model capacity and context windows.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.11793.png", "numComments": 4, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 171}, "isAuthorParticipating": false}, {"paper": {"id": "2511.18423", "authors": [{"_id": "692518ff16eb3a9f1310391c", "name": "B. Y. Yan", "hidden": false}, {"_id": "692518ff16eb3a9f1310391d", "name": "Chaofan Li", "hidden": false}, {"_id": "692518ff16eb3a9f1310391e", "name": "Hongjin Qian", "hidden": false}, {"_id": "692518ff16eb3a9f1310391f", "user": {"_id": "6145b3fd35135ec7e8d4ca45", "avatarUrl": "/avatars/5dc25d18d6a8418c9b1a29ece9a48f5a.svg", "isPro": false, "fullname": "Shuqi Lu", "user": "shuqi", "type": "user"}, "name": "Shuqi Lu", "status": "admin_assigned", "statusLastChangedAt": "2025-11-25T12:18:11.163Z", "hidden": false}, {"_id": "692518ff16eb3a9f13103920", "user": {"_id": "64a38c590111d5ff6c3d5f2b", "avatarUrl": "/avatars/ef13dc7ce243819bc0da9b04e778b432.svg", "isPro": false, "fullname": "zhengliu", "user": "lz1001", "type": "user"}, "name": "Zheng Liu", "status": "admin_assigned", "statusLastChangedAt": "2025-11-25T12:17:59.618Z", "hidden": false}], "publishedAt": "2025-11-23T12:29:33.000Z", "submittedOnDailyAt": "2025-11-25T00:25:04.757Z", "title": "General Agentic Memory Via Deep Research", "submittedOnDailyBy": {"_id": "64a38c590111d5ff6c3d5f2b", "avatarUrl": "/avatars/ef13dc7ce243819bc0da9b04e778b432.svg", "isPro": false, "fullname": "zhengliu", "user": "lz1001", "type": "user"}, "summary": "Memory is critical for AI agents, yet the widely-adopted static memory, aiming to create readily available memory in advance, is inevitably subject to severe information loss. To address this limitation, we propose a novel framework called general agentic memory (GAM). GAM follows the principle of \"just-in time (JIT) compilation\" where it focuses on creating optimized contexts for its client at runtime while keeping only simple but useful memory during the offline stage. To this end, GAM employs a duo-design with the following components. 1) Memorizer, which highlights key historical information using a lightweight memory, while maintaining complete historical information within a universal page-store. 2) Researcher, which retrieves and integrates useful information from the page-store for its online request guided by the pre-constructed memory. This design allows GAM to effectively leverage the agentic capabilities and test-time scalability of frontier large language models (LLMs), while also facilitating end-to-end performance optimization through reinforcement learning. In our experimental study, we demonstrate that GAM achieves substantial improvement on various memory-grounded task completion scenarios against existing memory systems.", "upvotes": 140, "discussionId": "692518ff16eb3a9f13103921", "projectPage": "https://github.com/VectorSpaceLab/general-agentic-memory", "githubRepo": "https://github.com/VectorSpaceLab/general-agentic-memory", "ai_summary": "GAM, a novel framework that employs JIT compilation principles, improves memory efficiency and task completion by leveraging a lightweight memorizer and researcher in conjunction with reinforcement learning.", "ai_keywords": ["general agentic memory", "GAM", "just-in time compilation", "JIT compilation", "memorizer", "researcher", "universal page-store", "large language models", "LLMs", "reinforcement learning"], "githubStars": 246, "organization": {"_id": "61be9739d2f9358e24ca0a4f", "name": "BAAI", "fullname": "Beijing Academy of Artificial Intelligence", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1664511063789-632c234f42c386ebd2710434.png"}, "summary_zh": "<ul>\n    <li>\u5185\u5b58\u5bf9\u4eba\u5de5\u667a\u80fd\u4ee3\u7406\u975e\u5e38\u91cd\u8981\uff0c\u4f46\u73b0\u6709\u9759\u6001\u5185\u5b58\u5bb9\u6613\u5bfc\u81f4\u4fe1\u606f\u4e22\u5931\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u6846\u67b6\uff0c\u79f0\u4e3a\u4e00\u822c\u4ee3\u7406\u5185\u5b58\uff08GAM\uff09\uff0c\u91c7\u7528\u201c\u53ca\u65f6\u7f16\u8bd1\u201d\uff08JIT\uff09\u539f\u5219\u3002</li>\n    <li>GAM\u8bbe\u8ba1\u4e86\u4e24\u4e2a\u4e3b\u8981\u7ec4\u4ef6\uff1a\u8bb0\u5fc6\u5668\u548c\u7814\u7a76\u8005\uff0c\u5206\u522b\u7528\u4e8e\u7ba1\u7406\u5386\u53f2\u4fe1\u606f\u548c\u5728\u7ebf\u68c0\u7d22\u6709\u7528\u4fe1\u606f\u3002</li>\n    <li>\u8fd9\u79cd\u8bbe\u8ba1\u80fd\u6709\u6548\u5229\u7528\u5927\u578b\u8bed\u8a00\u6a21\u578b\u7684\u4ee3\u7406\u80fd\u529b\uff0c\u5e76\u901a\u8fc7\u5f3a\u5316\u5b66\u4e60\u4f18\u5316\u6574\u4f53\u6027\u80fd\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cGAM\u5728\u591a\u79cd\u57fa\u4e8e\u8bb0\u5fc6\u7684\u4efb\u52a1\u5b8c\u6210\u573a\u666f\u4e2d\u663e\u8457\u4f18\u4e8e\u73b0\u6709\u5185\u5b58\u7cfb\u7edf\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Memory is very important for AI agents, but traditional static memory can lead to significant information loss.</li>\n  <li>We introduce a new system called general agentic memory (GAM) that creates memory when needed, rather than in advance.</li>\n  <li>GAM consists of two main parts: a Memorizer that keeps important past information, and a Researcher that finds useful information when needed.</li>\n  <li>This system helps AI agents use large language models more effectively and improves their overall performance.</li>\n  <li>Tests show that GAM performs much better in memory-related tasks compared to existing memory systems.</li>\n</ul>"}, "publishedAt": "2025-11-23T07:29:33.000Z", "title": "General Agentic Memory Via Deep Research", "summary": "Memory is critical for AI agents, yet the widely-adopted static memory, aiming to create readily available memory in advance, is inevitably subject to severe information loss. To address this limitation, we propose a novel framework called general agentic memory (GAM). GAM follows the principle of \"just-in time (JIT) compilation\" where it focuses on creating optimized contexts for its client at runtime while keeping only simple but useful memory during the offline stage. To this end, GAM employs a duo-design with the following components. 1) Memorizer, which highlights key historical information using a lightweight memory, while maintaining complete historical information within a universal page-store. 2) Researcher, which retrieves and integrates useful information from the page-store for its online request guided by the pre-constructed memory. This design allows GAM to effectively leverage the agentic capabilities and test-time scalability of frontier large language models (LLMs), while also facilitating end-to-end performance optimization through reinforcement learning. In our experimental study, we demonstrate that GAM achieves substantial improvement on various memory-grounded task completion scenarios against existing memory systems.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.18423.png", "numComments": 2, "submittedBy": {"_id": "64a38c590111d5ff6c3d5f2b", "avatarUrl": "/avatars/ef13dc7ce243819bc0da9b04e778b432.svg", "fullname": "zhengliu", "name": "lz1001", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 12}, "organization": {"_id": "61be9739d2f9358e24ca0a4f", "name": "BAAI", "fullname": "Beijing Academy of Artificial Intelligence", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1664511063789-632c234f42c386ebd2710434.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.13254", "authors": [{"_id": "691c1c836bfd5965c0fd39e4", "user": {"_id": "6419b34a9a27800807c34a63", "avatarUrl": "/avatars/ee1391a9a153bae0dd04323b1fa5b5d6.svg", "isPro": false, "fullname": "Shalini M", "user": "shalinimaiti", "type": "user"}, "name": "Shalini Maiti", "status": "claimed_verified", "statusLastChangedAt": "2025-11-18T14:06:47.486Z", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39e5", "user": {"_id": "6687ee79eee600e418404cc9", "avatarUrl": "/avatars/d73d3a360ab3b3ce353a6306c7270a13.svg", "isPro": false, "fullname": "Amar Budhiraja", "user": "ambud26", "type": "user"}, "name": "Amar Budhiraja", "status": "claimed_verified", "statusLastChangedAt": "2025-11-18T14:06:49.892Z", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39e6", "user": {"_id": "60720704227ff331937110f4", "avatarUrl": "/avatars/8010bfb98256c138049aa3d237737b37.svg", "isPro": false, "fullname": "Bhavul Gauri", "user": "bhavul", "type": "user"}, "name": "Bhavul Gauri", "status": "claimed_verified", "statusLastChangedAt": "2025-11-19T08:40:31.124Z", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39e7", "user": {"_id": "691c6b9b660c15d270b5838a", "avatarUrl": "/avatars/2dc40e079bd8b7af7ae4a4ac43acc552.svg", "isPro": false, "fullname": "Gaurav Chaurasia", "user": "gchauras", "type": "user"}, "name": "Gaurav Chaurasia", "status": "claimed_verified", "statusLastChangedAt": "2025-11-18T14:06:45.558Z", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39e8", "name": "Anton Protopopov", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39e9", "name": "Alexis Audran-Reiss", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39ea", "name": "Michael Slater", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39eb", "name": "Despoina Magka", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39ec", "name": "Tatiana Shavrina", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39ed", "name": "Roberta Raileanu", "hidden": false}, {"_id": "691c1c836bfd5965c0fd39ee", "name": "Yoram Bachrach", "hidden": false}], "publishedAt": "2025-11-17T11:13:34.000Z", "submittedOnDailyAt": "2025-11-18T04:47:00.815Z", "title": "Souper-Model: How Simple Arithmetic Unlocks State-of-the-Art LLM Performance", "submittedOnDailyBy": {"_id": "6687ee79eee600e418404cc9", "avatarUrl": "/avatars/d73d3a360ab3b3ce353a6306c7270a13.svg", "isPro": false, "fullname": "Amar Budhiraja", "user": "ambud26", "type": "user"}, "summary": "Large Language Models (LLMs) have demonstrated remarkable capabilities across diverse domains, but their training remains resource- and time-intensive, requiring massive compute power and careful orchestration of training procedures. Model souping-the practice of averaging weights from multiple models of the same architecture-has emerged as a promising pre- and post-training technique that can enhance performance without expensive retraining. In this paper, we introduce Soup Of Category Experts (SoCE), a principled approach for model souping that utilizes benchmark composition to identify optimal model candidates and applies non-uniform weighted averaging to maximize performance. Contrary to previous uniform-averaging approaches, our method leverages the observation that benchmark categories often exhibit low inter-correlations in model performance. SoCE identifies \"expert\" models for each weakly-correlated category cluster and combines them using optimized weighted averaging rather than uniform weights. We demonstrate that the proposed method improves performance and robustness across multiple domains, including multilingual capabilities, tool calling, and math and achieves state-of-the-art results on the Berkeley Function Calling Leaderboard.", "upvotes": 131, "discussionId": "691c1c846bfd5965c0fd39fc", "githubRepo": "https://github.com/facebookresearch/llm_souping", "githubStars": 60, "organization": {"_id": "5e63d8713071d5be688861b8", "name": "facebook", "fullname": "AI at Meta", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1592839207516-noauth.png"}, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u5728\u591a\u4e2a\u9886\u57df\u8868\u73b0\u51fa\u8272\uff0c\u4f46\u8bad\u7ec3\u8fc7\u7a0b\u8017\u65f6\u4e14\u9700\u8981\u5927\u91cf\u8ba1\u7b97\u8d44\u6e90\u3002</li>\n    <li>\u6a21\u578b\u201c\u6df7\u5408\u201d\uff08model souping\uff09\u901a\u8fc7\u5bf9\u591a\u4e2a\u76f8\u540c\u67b6\u6784\u7684\u6a21\u578b\u8fdb\u884c\u52a0\u6743\u5e73\u5747\uff0c\u80fd\u5728\u4e0d\u91cd\u65b0\u8bad\u7ec3\u7684\u60c5\u51b5\u4e0b\u63d0\u5347\u6027\u80fd\u3002</li>\n    <li>\u672c\u6587\u4ecb\u7ecd\u4e86\u201c\u7c7b\u522b\u4e13\u5bb6\u6df7\u5408\u201d\uff08SoCE\uff09\u65b9\u6cd5\uff0c\u901a\u8fc7\u57fa\u51c6\u7ec4\u5408\u6765\u9009\u62e9\u6700\u4f73\u6a21\u578b\uff0c\u5e76\u91c7\u7528\u975e\u5747\u5300\u52a0\u6743\u5e73\u5747\u6765\u4f18\u5316\u6027\u80fd\u3002</li>\n    <li>SoCE\u65b9\u6cd5\u5229\u7528\u57fa\u51c6\u7c7b\u522b\u4e4b\u95f4\u7684\u4f4e\u76f8\u5173\u6027\u6765\u8bc6\u522b\u201c\u4e13\u5bb6\u201d\u6a21\u578b\uff0c\u5e76\u5bf9\u5176\u8fdb\u884c\u4f18\u5316\u52a0\u6743\u5408\u5e76\u3002</li>\n    <li>\u8be5\u65b9\u6cd5\u5728\u591a\u8bed\u8a00\u80fd\u529b\u3001\u5de5\u5177\u8c03\u7528\u548c\u6570\u5b66\u7b49\u591a\u4e2a\u9886\u57df\u63d0\u9ad8\u4e86\u6027\u80fd\u548c\u9c81\u68d2\u6027\uff0c\u5e76\u5728\u4f2f\u514b\u5229\u51fd\u6570\u8c03\u7528\u6392\u884c\u699c\u4e0a\u53d6\u5f97\u4e86\u9886\u5148\u6210\u7ee9\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large Language Models (LLMs) are powerful but require a lot of resources and time to train.</li>\n    <li>Model souping, or averaging weights from multiple models, can improve performance without needing extensive retraining.</li>\n    <li>This paper presents Soup Of Category Experts (SoCE), a new method for model souping that selects the best models based on benchmark categories.</li>\n    <li>SoCE uses weighted averaging to combine models, focusing on those that perform well in related areas instead of using equal weights for all models.</li>\n    <li>The method shows better performance and reliability in various tasks, achieving top results in certain benchmarks.</li>\n</ul>"}, "publishedAt": "2025-11-17T06:13:34.000Z", "title": "Souper-Model: How Simple Arithmetic Unlocks State-of-the-Art LLM Performance", "summary": "Large Language Models (LLMs) have demonstrated remarkable capabilities across diverse domains, but their training remains resource- and time-intensive, requiring massive compute power and careful orchestration of training procedures. Model souping-the practice of averaging weights from multiple models of the same architecture-has emerged as a promising pre- and post-training technique that can enhance performance without expensive retraining. In this paper, we introduce Soup Of Category Experts (SoCE), a principled approach for model souping that utilizes benchmark composition to identify optimal model candidates and applies non-uniform weighted averaging to maximize performance. Contrary to previous uniform-averaging approaches, our method leverages the observation that benchmark categories often exhibit low inter-correlations in model performance. SoCE identifies \"expert\" models for each weakly-correlated category cluster and combines them using optimized weighted averaging rather than uniform weights. We demonstrate that the proposed method improves performance and robustness across multiple domains, including multilingual capabilities, tool calling, and math and achieves state-of-the-art results on the Berkeley Function Calling Leaderboard.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.13254.png", "numComments": 4, "submittedBy": {"_id": "6687ee79eee600e418404cc9", "avatarUrl": "/avatars/d73d3a360ab3b3ce353a6306c7270a13.svg", "fullname": "Amar Budhiraja", "name": "ambud26", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "organization": {"_id": "5e63d8713071d5be688861b8", "name": "facebook", "fullname": "AI at Meta", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/1592839207516-noauth.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2511.13612", "authors": [{"_id": "691bfdc96bfd5965c0fd3951", "user": {"_id": "65352acb7139c5dd8d9a8590", "avatarUrl": "/avatars/e2ff22b596aee45cdfb8f68dc15572f9.svg", "isPro": false, "fullname": "JiachengChen", "user": "JC-Chen", "type": "user"}, "name": "Jiacheng Chen", "status": "claimed_verified", "statusLastChangedAt": "2025-11-18T14:07:04.293Z", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3952", "name": "Qianjia Cheng", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3953", "name": "Fangchen Yu", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3954", "user": {"_id": "691b0f528411a45dc9ee9de8", "avatarUrl": "/avatars/261c28f7e616a8482970f50c1f8919fd.svg", "isPro": false, "fullname": "Haiyuan Wan", "user": "HY-Wan", "type": "user"}, "name": "Haiyuan Wan", "status": "claimed_verified", "statusLastChangedAt": "2025-11-21T10:15:34.294Z", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3955", "name": "Yuchen Zhang", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3956", "name": "Shenghe Zheng", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3957", "name": "Junchi Yao", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3958", "user": {"_id": "66554e83a2d7a882a876ffc3", "avatarUrl": "/avatars/9803448705f282b72d82a66cb22338b2.svg", "isPro": false, "fullname": "qingyang zhang", "user": "qingyangzhang", "type": "user"}, "name": "Qingyang Zhang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-20T08:50:04.900Z", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3959", "name": "Haonan He", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd395a", "name": "Yun Luo", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd395b", "name": "Yufeng Zhao", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd395c", "name": "Futing Wang", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd395d", "name": "Li Sheng", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd395e", "name": "Chengxing Xie", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd395f", "name": "Yuxin Zuo", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3960", "name": "Yizhuo Li", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3961", "name": "Wenxauan Zeng", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3962", "name": "Yulun Wu", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3963", "user": {"_id": "6731caae58ba0f0984c188ea", "avatarUrl": "/avatars/445275cca29f97c5f8754d6c27075887.svg", "isPro": false, "fullname": "Rui Huang", "user": "Rui1121", "type": "user"}, "name": "Rui Huang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-18T14:07:02.211Z", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3964", "name": "Dongzhan Zhou", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3965", "name": "Kai Chen", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3966", "name": "Yu Qiao", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3967", "name": "Lei Bai", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3968", "name": "Yu Cheng", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd3969", "name": "Ning Ding", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd396a", "name": "Bowen Zhou", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd396b", "name": "Peng Ye", "hidden": false}, {"_id": "691bfdc96bfd5965c0fd396c", "name": "Ganqu Cui", "hidden": false}], "publishedAt": "2025-11-17T17:18:13.000Z", "submittedOnDailyAt": "2025-11-18T02:37:44.601Z", "title": "P1: Mastering Physics Olympiads with Reinforcement Learning", "submittedOnDailyBy": {"_id": "65352acb7139c5dd8d9a8590", "avatarUrl": "/avatars/e2ff22b596aee45cdfb8f68dc15572f9.svg", "isPro": false, "fullname": "JiachengChen", "user": "JC-Chen", "type": "user"}, "summary": "Recent progress in large language models (LLMs) has moved the frontier from puzzle-solving to science-grade reasoning-the kind needed to tackle problems whose answers must stand against nature, not merely fit a rubric. Physics is the sharpest test of this shift, which binds symbols to reality in a fundamental way, serving as the cornerstone of most modern technologies. In this work, we manage to advance physics research by developing large language models with exceptional physics reasoning capabilities, especially excel at solving Olympiad-level physics problems. We introduce P1, a family of open-source physics reasoning models trained entirely through reinforcement learning (RL). Among them, P1-235B-A22B is the first open-source model with Gold-medal performance at the latest International Physics Olympiad (IPhO 2025), and wins 12 gold medals out of 13 international/regional physics competitions in 2024/2025. P1-30B-A3B also surpasses almost all other open-source models on IPhO 2025, getting a silver medal. Further equipped with an agentic framework PhysicsMinions, P1-235B-A22B+PhysicsMinions achieves overall No.1 on IPhO 2025, and obtains the highest average score over the 13 physics competitions. Besides physics, P1 models also present great performance on other reasoning tasks like math and coding, showing the great generalibility of P1 series.", "upvotes": 128, "discussionId": "691bfdca6bfd5965c0fd396d", "projectPage": "https://prime-rl.github.io/P1/", "githubRepo": "https://github.com/PRIME-RL/P1", "githubStars": 59, "summary_zh": "<ul>\n    <li>\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u5728\u79d1\u5b66\u63a8\u7406\u65b9\u9762\u53d6\u5f97\u4e86\u91cd\u5927\u8fdb\u5c55\uff0c\u5c24\u5176\u662f\u5728\u89e3\u51b3\u7269\u7406\u95ee\u9898\u4e0a\u3002</li>\n    <li>P1\u662f\u4e00\u4e2a\u5f00\u6e90\u7269\u7406\u63a8\u7406\u6a21\u578b\u7cfb\u5217\uff0c\u901a\u8fc7\u5f3a\u5316\u5b66\u4e60\u8bad\u7ec3\u800c\u6210\u3002</li>\n    <li>P1-235B-A22B\u662f\u9996\u4e2a\u5728\u56fd\u9645\u7269\u7406\u5965\u6797\u5339\u514b\u7ade\u8d5b\u4e2d\u83b7\u5f97\u91d1\u724c\u7684\u5f00\u6e90\u6a21\u578b\uff0c\u5e76\u57282024/2025\u5e74\u8d62\u5f97\u4e8612\u679a\u91d1\u724c\u3002</li>\n    <li>P1-30B-A3B\u5728\u56fd\u9645\u7269\u7406\u5965\u6797\u5339\u514b\u7ade\u8d5b\u4e2d\u83b7\u5f97\u94f6\u724c\uff0c\u8d85\u8d8a\u4e86\u51e0\u4e4e\u6240\u6709\u5176\u4ed6\u5f00\u6e90\u6a21\u578b\u3002</li>\n    <li>P1\u7cfb\u5217\u6a21\u578b\u5728\u6570\u5b66\u548c\u7f16\u7801\u7b49\u5176\u4ed6\u63a8\u7406\u4efb\u52a1\u4e0a\u4e5f\u8868\u73b0\u51fa\u8272\uff0c\u663e\u793a\u4e86\u5176\u5e7f\u6cdb\u7684\u9002\u7528\u6027\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Recent advancements in large language models (LLMs) have improved their ability to solve complex scientific problems, especially in physics.</li>\n    <li>The P1 models are a new series of open-source models designed specifically for physics reasoning, trained using reinforcement learning.</li>\n    <li>P1-235B-A22B is the first open-source model to achieve Gold-medal performance at the International Physics Olympiad (IPhO) 2025.</li>\n    <li>The P1 models also excel in other reasoning tasks such as math and coding, demonstrating their versatility.</li>\n    <li>P1-30B-A3B earned a silver medal at the IPhO 2025, showing strong performance among open-source models.</li>\n</ul>"}, "publishedAt": "2025-11-17T12:18:13.000Z", "title": "P1: Mastering Physics Olympiads with Reinforcement Learning", "summary": "Recent progress in large language models (LLMs) has moved the frontier from puzzle-solving to science-grade reasoning-the kind needed to tackle problems whose answers must stand against nature, not merely fit a rubric. Physics is the sharpest test of this shift, which binds symbols to reality in a fundamental way, serving as the cornerstone of most modern technologies. In this work, we manage to advance physics research by developing large language models with exceptional physics reasoning capabilities, especially excel at solving Olympiad-level physics problems. We introduce P1, a family of open-source physics reasoning models trained entirely through reinforcement learning (RL). Among them, P1-235B-A22B is the first open-source model with Gold-medal performance at the latest International Physics Olympiad (IPhO 2025), and wins 12 gold medals out of 13 international/regional physics competitions in 2024/2025. P1-30B-A3B also surpasses almost all other open-source models on IPhO 2025, getting a silver medal. Further equipped with an agentic framework PhysicsMinions, P1-235B-A22B+PhysicsMinions achieves overall No.1 on IPhO 2025, and obtains the highest average score over the 13 physics competitions. Besides physics, P1 models also present great performance on other reasoning tasks like math and coding, showing the great generalibility of P1 series.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.13612.png", "numComments": 4, "submittedBy": {"_id": "65352acb7139c5dd8d9a8590", "avatarUrl": "/avatars/e2ff22b596aee45cdfb8f68dc15572f9.svg", "fullname": "JiachengChen", "name": "JC-Chen", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "isAuthorParticipating": true}, {"paper": {"id": "2511.06221", "authors": [{"_id": "6912a1c7a644ba07c499c6e1", "user": {"_id": "67486775ed2e4d9e50fc9117", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/67486775ed2e4d9e50fc9117/WrCtPqY9X67ASbkUeloDF.jpeg", "isPro": false, "fullname": "Sen Xu", "user": "SenXbjtu", "type": "user"}, "name": "Sen Xu", "status": "claimed_verified", "statusLastChangedAt": "2025-11-11T19:44:27.021Z", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e2", "user": {"_id": "6406991ec3ab325efa9b6732", "avatarUrl": "/avatars/5ba29d9e25820c1172b5a98b078e416f.svg", "isPro": false, "fullname": "DenseHub", "user": "YiZhouDenseHub", "type": "user"}, "name": "Yi Zhou", "status": "claimed_verified", "statusLastChangedAt": "2025-11-11T19:44:32.245Z", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e3", "name": "Wei Wang", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e4", "user": {"_id": "6646fa14b096df5b522fd5f9", "avatarUrl": "/avatars/98f67b6f8cb9776575916a2ba027f738.svg", "isPro": false, "fullname": "MIN JIXIN", "user": "JIXIN0121", "type": "user"}, "name": "Jixin Min", "status": "claimed_verified", "statusLastChangedAt": "2025-11-12T12:21:33.041Z", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e5", "user": {"_id": "64d1faaa1ed6649d70d1fa2f", "avatarUrl": "/avatars/388ba18df077eaa8e16a89e59bf852fa.svg", "isPro": false, "fullname": "YinZhiBin", "user": "YinZhiBin", "type": "user"}, "name": "Zhibin Yin", "status": "claimed_verified", "statusLastChangedAt": "2025-11-11T19:44:34.446Z", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e6", "name": "Yingwei Dai", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e7", "user": {"_id": "6422eba32f38c0a50cfdc77d", "avatarUrl": "/avatars/0b1137ff258ba578c8b0e257a43716fa.svg", "isPro": false, "fullname": "lsx", "user": "lsx666", "type": "user"}, "name": "Shixi Liu", "status": "claimed_verified", "statusLastChangedAt": "2025-11-13T13:07:14.701Z", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e8", "user": {"_id": "636b5433d524b220830e7a61", "avatarUrl": "/avatars/09e9b392a189195aa09b93fc17b70cc3.svg", "isPro": false, "fullname": "pangly", "user": "pangly", "type": "user"}, "name": "Lianyu Pang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-12T12:21:31.027Z", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6e9", "name": "Yirong Chen", "hidden": false}, {"_id": "6912a1c7a644ba07c499c6ea", "user": {"_id": "668b5090101353874ced73d0", "avatarUrl": "/avatars/b2ec34a321890140e97ddd69884132a8.svg", "isPro": false, "fullname": "junlin zhang", "user": "junlinzhang", "type": "user"}, "name": "Junlin Zhang", "status": "claimed_verified", "statusLastChangedAt": "2025-11-11T19:44:24.601Z", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6406991ec3ab325efa9b6732/4yVJjn-Y2UONHvzebYMkU.png"], "publishedAt": "2025-11-09T04:37:36.000Z", "submittedOnDailyAt": "2025-11-12T00:53:44.764Z", "title": "Tiny Model, Big Logic: Diversity-Driven Optimization Elicits Large-Model\n  Reasoning Ability in VibeThinker-1.5B", "submittedOnDailyBy": {"_id": "6406991ec3ab325efa9b6732", "avatarUrl": "/avatars/5ba29d9e25820c1172b5a98b078e416f.svg", "isPro": false, "fullname": "DenseHub", "user": "YiZhouDenseHub", "type": "user"}, "summary": "Challenging the prevailing consensus that small models inherently lack robust\nreasoning, this report introduces VibeThinker-1.5B, a 1.5B-parameter dense\nmodel developed via our Spectrum-to-Signal Principle (SSP). This challenges the\nprevailing approach of scaling model parameters to enhance capabilities, as\nseen in models like DeepSeek R1 (671B) and Kimi k2 (>1T). The SSP framework\nfirst employs a Two-Stage Diversity-Exploring Distillation (SFT) to generate a\nbroad spectrum of solutions, followed by MaxEnt-Guided Policy Optimization (RL)\nto amplify the correct signal. With a total training cost of only $7,800,\nVibeThinker-1.5B demonstrates superior reasoning capabilities compared to\nclosed-source models like Magistral Medium and Claude Opus 4, and performs on\npar with open-source models like GPT OSS-20B Medium. Remarkably, it surpasses\nthe 400x larger DeepSeek R1 on three math benchmarks: AIME24 (80.3 vs. 79.8),\nAIME25 (74.4 vs. 70.0), and HMMT25 (50.4 vs. 41.7). This is a substantial\nimprovement over its base model (6.7, 4.3, and 0.6, respectively). On\nLiveCodeBench V6, it scores 51.1, outperforming Magistral Medium's 50.3 and its\nbase model's 0.0. These findings demonstrate that small models can achieve\nreasoning capabilities comparable to large models, drastically reducing\ntraining and inference costs and thereby democratizing advanced AI research.", "upvotes": 120, "discussionId": "6912a1c7a644ba07c499c6eb", "projectPage": "https://github.com/WeiboAI/VibeThinker", "githubRepo": "https://github.com/WeiboAI/VibeThinker", "ai_summary": "VibeThinker-1.5B, a 1.5B-parameter model using the Spectrum-to-Signal Principle, achieves superior reasoning capabilities compared to larger models at a significantly lower cost.", "ai_keywords": ["Spectrum-to-Signal Principle", "Two-Stage Diversity-Exploring Distillation", "MaxEnt-Guided Policy Optimization", "VibeThinker-1.5B", "DeepSeek R1", "Kimi k2", "Magistral Medium", "Claude Opus 4", "GPT OSS-20B Medium", "AIME24", "AIME25", "HMMT25", "LiveCodeBench V6"], "githubStars": 508, "organization": {"_id": "68c8059479c43cfa50f36156", "name": "WeiboAI", "fullname": "WeiboAI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64d1faaa1ed6649d70d1fa2f/lZVm6Yuiif9cdr5KsnfZr.png"}, "summary_zh": "<ul>\n    <li>\u62a5\u544a\u4ecb\u7ecd\u4e86VibeThinker-1.5B\uff0c\u4e00\u4e2a\u5177\u670915\u4ebf\u53c2\u6570\u7684\u5c0f\u578b\u6a21\u578b\uff0c\u6311\u6218\u4e86\u5c0f\u6a21\u578b\u7f3a\u4e4f\u63a8\u7406\u80fd\u529b\u7684\u4f20\u7edf\u89c2\u70b9\u3002</li>\n    <li>\u8be5\u6a21\u578b\u901a\u8fc7Spectrum-to-Signal Principle (SSP)\u5f00\u53d1\uff0c\u91c7\u7528\u4e86\u4e24\u9636\u6bb5\u7684\u591a\u6837\u6027\u63a2\u7d22\u84b8\u998f\u548c\u6700\u5927\u71b5\u5f15\u5bfc\u7684\u7b56\u7565\u4f18\u5316\u3002</li>\n    <li>VibeThinker-1.5B\u7684\u8bad\u7ec3\u6210\u672c\u4ec5\u4e3a7800\u7f8e\u5143\uff0c\u63a8\u7406\u80fd\u529b\u4f18\u4e8e\u4e00\u4e9b\u95ed\u6e90\u6a21\u578b\uff0c\u5e76\u4e0e\u5f00\u6e90\u6a21\u578b\u76f8\u5f53\u3002</li>\n    <li>\u5728\u4e09\u9879\u6570\u5b66\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cVibeThinker-1.5B\u7684\u8868\u73b0\u8d85\u8fc7\u4e86400\u500d\u66f4\u5927\u7684DeepSeek R1\u3002</li>\n    <li>\u8fd9\u4e9b\u53d1\u73b0\u8868\u660e\uff0c\u5c0f\u6a21\u578b\u53ef\u4ee5\u5b9e\u73b0\u4e0e\u5927\u6a21\u578b\u76f8\u4f3c\u7684\u63a8\u7406\u80fd\u529b\uff0c\u4ece\u800c\u964d\u4f4e\u8bad\u7ec3\u548c\u63a8\u7406\u6210\u672c\uff0c\u4fc3\u8fdb\u5148\u8fdbAI\u7814\u7a76\u7684\u666e\u53ca\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>VibeThinker-1.5B is a new 1.5 billion parameter model that challenges the idea that smaller models can't reason well.</li>\n    <li>This model uses a unique approach called the Spectrum-to-Signal Principle (SSP) to improve its performance without needing a massive number of parameters.</li>\n    <li>It was trained at a low cost of $7,800 and shows better reasoning than some larger closed-source models.</li>\n    <li>VibeThinker-1.5B outperformed the much larger DeepSeek R1 on three math tests, achieving better scores.</li>\n    <li>This research suggests that smaller models can match the reasoning abilities of larger ones, making advanced AI more accessible and cost-effective.</li>\n</ul>"}, "publishedAt": "2025-11-08T23:37:36.000Z", "title": "Tiny Model, Big Logic: Diversity-Driven Optimization Elicits Large-Model\n  Reasoning Ability in VibeThinker-1.5B", "summary": "Challenging the prevailing consensus that small models inherently lack robust\nreasoning, this report introduces VibeThinker-1.5B, a 1.5B-parameter dense\nmodel developed via our Spectrum-to-Signal Principle (SSP). This challenges the\nprevailing approach of scaling model parameters to enhance capabilities, as\nseen in models like DeepSeek R1 (671B) and Kimi k2 (>1T). The SSP framework\nfirst employs a Two-Stage Diversity-Exploring Distillation (SFT) to generate a\nbroad spectrum of solutions, followed by MaxEnt-Guided Policy Optimization (RL)\nto amplify the correct signal. With a total training cost of only $7,800,\nVibeThinker-1.5B demonstrates superior reasoning capabilities compared to\nclosed-source models like Magistral Medium and Claude Opus 4, and performs on\npar with open-source models like GPT OSS-20B Medium. Remarkably, it surpasses\nthe 400x larger DeepSeek R1 on three math benchmarks: AIME24 (80.3 vs. 79.8),\nAIME25 (74.4 vs. 70.0), and HMMT25 (50.4 vs. 41.7). This is a substantial\nimprovement over its base model (6.7, 4.3, and 0.6, respectively). On\nLiveCodeBench V6, it scores 51.1, outperforming Magistral Medium's 50.3 and its\nbase model's 0.0. These findings demonstrate that small models can achieve\nreasoning capabilities comparable to large models, drastically reducing\ntraining and inference costs and thereby democratizing advanced AI research.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/6406991ec3ab325efa9b6732/4yVJjn-Y2UONHvzebYMkU.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.06221.png", "numComments": 11, "submittedBy": {"_id": "6406991ec3ab325efa9b6732", "avatarUrl": "/avatars/5ba29d9e25820c1172b5a98b078e416f.svg", "fullname": "DenseHub", "name": "YiZhouDenseHub", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3}, "organization": {"_id": "68c8059479c43cfa50f36156", "name": "WeiboAI", "fullname": "WeiboAI", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/64d1faaa1ed6649d70d1fa2f/lZVm6Yuiif9cdr5KsnfZr.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2511.03276", "authors": [{"_id": "690c1cdc60494e4fa76756a9", "user": {"_id": "62a7362fd1e7a011fd4e31a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/62a7362fd1e7a011fd4e31a7/ZY_mwH-sI0o05SHpLqwc7.png", "isPro": false, "fullname": "Jinjie Ni", "user": "jinjieni", "type": "user"}, "name": "Jinjie Ni", "status": "claimed_verified", "statusLastChangedAt": "2025-11-06T11:47:00.935Z", "hidden": false}, {"_id": "690c1cdc60494e4fa76756aa", "user": {"_id": "612ee6a7b960e78c6d2319d4", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/612ee6a7b960e78c6d2319d4/2Hu9BaAyXbyh1vt0v1Qui.jpeg", "isPro": false, "fullname": "Qian Liu", "user": "SivilTaram", "type": "user"}, "name": "Qian Liu", "status": "claimed_verified", "statusLastChangedAt": "2025-11-07T10:31:23.866Z", "hidden": false}, {"_id": "690c1cdc60494e4fa76756ab", "user": {"_id": "6214e4ee1e35c843d42d1f88", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6214e4ee1e35c843d42d1f88/fj-9wuIdPhvogh3BrcXTB.jpeg", "isPro": false, "fullname": "Longxu Dou", "user": "dreamerdeo", "type": "user"}, "name": "Longxu Dou", "status": "claimed_verified", "statusLastChangedAt": "2025-11-18T14:09:50.728Z", "hidden": false}, {"_id": "690c1cdc60494e4fa76756ac", "name": "Chao Du", "hidden": false}, {"_id": "690c1cdc60494e4fa76756ad", "name": "Zili Wang", "hidden": false}, {"_id": "690c1cdc60494e4fa76756ae", "name": "Hang Yan", "hidden": false}, {"_id": "690c1cdc60494e4fa76756af", "name": "Tianyu Pang", "hidden": false}, {"_id": "690c1cdc60494e4fa76756b0", "name": "Michael Qizhe Shieh", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/62a7362fd1e7a011fd4e31a7/QrHOFNxOkfy93f6tPGJdN.jpeg"], "publishedAt": "2025-11-05T08:17:42.000Z", "submittedOnDailyAt": "2025-11-06T01:32:43.418Z", "title": "Diffusion Language Models are Super Data Learners", "submittedOnDailyBy": {"_id": "62a7362fd1e7a011fd4e31a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/62a7362fd1e7a011fd4e31a7/ZY_mwH-sI0o05SHpLqwc7.png", "isPro": false, "fullname": "Jinjie Ni", "user": "jinjieni", "type": "user"}, "summary": "Under strictly controlled pre-training settings, we observe a Crossover: when\nunique data is limited, diffusion language models (DLMs) consistently surpass\nautoregressive (AR) models by training for more epochs. The crossover shifts\nlater with more or higher-quality data, earlier with larger models, and\npersists across dense and sparse architectures. We attribute the gains to three\ncompounding factors: (1) any-order modeling, (2) super-dense compute from\niterative bidirectional denoising, and (3) built-in Monte Carlo augmentation;\ninput or parameter noise improves AR under data constraint but cannot close the\ngap. At scale, a 1.7B DLM trained with a ~1.5T-token compute budget on 10B\nunique Python tokens overtakes an AR coder trained with strictly matched\nsettings. In addition, a 1B-parameter DLM achieves > 56% accuracy on HellaSwag\nand > 33% on MMLU using only 1B tokens, without any special tricks, just by\nrepeating standard pre-training data. We also show that rising validation\ncross-entropy does not imply degraded downstream performance in this regime.", "upvotes": 118, "discussionId": "690c1cdc60494e4fa76756b1", "projectPage": "https://github.com/JinjieNi/dlms-are-super-data-learners", "githubRepo": "https://github.com/JinjieNi/MegaDLMs", "ai_summary": "Diffusion language models outperform autoregressive models in low-data settings due to any-order modeling, iterative bidirectional denoising, and Monte Carlo augmentation, and maintain advantages even at scale.", "ai_keywords": ["diffusion language models", "autoregressive models", "any-order modeling", "iterative bidirectional denoising", "Monte Carlo augmentation", "HellaSwag", "MMLU"], "githubStars": 283, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "summary_zh": "<ul>\n    <li>\u5728\u4e25\u683c\u7684\u9884\u8bad\u7ec3\u6761\u4ef6\u4e0b\uff0c\u6269\u6563\u8bed\u8a00\u6a21\u578b\uff08DLM\uff09\u5728\u6570\u636e\u6709\u9650\u65f6\u8868\u73b0\u4f18\u4e8e\u81ea\u56de\u5f52\uff08AR\uff09\u6a21\u578b\u3002</li>\n    <li>\u968f\u7740\u6570\u636e\u91cf\u589e\u52a0\u6216\u6570\u636e\u8d28\u91cf\u63d0\u9ad8\uff0cDLM\u7684\u4f18\u52bf\u4f1a\u63a8\u8fdf\u51fa\u73b0\uff0c\u4f46\u5728\u66f4\u5927\u6a21\u578b\u4e2d\u4f1a\u66f4\u65e9\u51fa\u73b0\u3002</li>\n    <li>DLM\u7684\u6210\u529f\u5f52\u56e0\u4e8e\u4e09\u4e2a\u56e0\u7d20\uff1a\u65e0\u5e8f\u5efa\u6a21\u3001\u8fed\u4ee3\u53cc\u5411\u53bb\u566a\u7684\u8d85\u7ea7\u5bc6\u96c6\u8ba1\u7b97\u3001\u4ee5\u53ca\u5185\u7f6e\u7684\u8499\u7279\u5361\u7f57\u589e\u5f3a\u3002</li>\n    <li>\u5728\u5927\u89c4\u6a21\u5b9e\u9a8c\u4e2d\uff0c1.7B\u53c2\u6570\u7684DLM\u57281.5T-token\u7684\u8ba1\u7b97\u9884\u7b97\u4e0b\u8d85\u8d8a\u4e86\u81ea\u56de\u5f52\u7f16\u7801\u5668\u3002</li>\n    <li>\u5373\u4f7f\u53ea\u4f7f\u75281B tokens\uff0c1B\u53c2\u6570\u7684DLM\u4e5f\u5728HellaSwag\u548cMMLU\u4e0a\u53d6\u5f97\u4e86\u8d85\u8fc756%\u548c33%\u7684\u51c6\u786e\u7387\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Diffusion language models (DLMs) perform better than autoregressive (AR) models when trained for more epochs with limited unique data.</li>\n    <li>The advantage of DLMs increases with better quality data and larger models, and it remains consistent across different model architectures.</li>\n    <li>Three key factors contribute to DLMs' success: the ability to model data in any order, efficient computing through iterative bidirectional processing, and built-in noise augmentation.</li>\n    <li>A DLM with 1.7 billion parameters trained on a large dataset outperforms an AR model under similar conditions.</li>\n    <li>A smaller 1 billion parameter DLM achieves high accuracy on specific benchmarks using regular pre-training data without special techniques.</li>\n</ul>"}, "publishedAt": "2025-11-05T03:17:42.000Z", "title": "Diffusion Language Models are Super Data Learners", "summary": "Under strictly controlled pre-training settings, we observe a Crossover: when\nunique data is limited, diffusion language models (DLMs) consistently surpass\nautoregressive (AR) models by training for more epochs. The crossover shifts\nlater with more or higher-quality data, earlier with larger models, and\npersists across dense and sparse architectures. We attribute the gains to three\ncompounding factors: (1) any-order modeling, (2) super-dense compute from\niterative bidirectional denoising, and (3) built-in Monte Carlo augmentation;\ninput or parameter noise improves AR under data constraint but cannot close the\ngap. At scale, a 1.7B DLM trained with a ~1.5T-token compute budget on 10B\nunique Python tokens overtakes an AR coder trained with strictly matched\nsettings. In addition, a 1B-parameter DLM achieves > 56% accuracy on HellaSwag\nand > 33% on MMLU using only 1B tokens, without any special tricks, just by\nrepeating standard pre-training data. We also show that rising validation\ncross-entropy does not imply degraded downstream performance in this regime.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/62a7362fd1e7a011fd4e31a7/QrHOFNxOkfy93f6tPGJdN.jpeg"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2511.03276.png", "numComments": 15, "submittedBy": {"_id": "62a7362fd1e7a011fd4e31a7", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/62a7362fd1e7a011fd4e31a7/ZY_mwH-sI0o05SHpLqwc7.png", "fullname": "Jinjie Ni", "name": "jinjieni", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 18}, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-uploads.huggingface.co/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "isAuthorParticipating": true}]
};
